function readJsonStorage(key, fallback) {
  try {
    const parsed = JSON.parse(localStorage.getItem(key) || "null");
    return parsed === null || typeof parsed === "undefined" ? fallback : parsed;
  } catch {
    return fallback;
  }
}

function writeJsonStorage(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
    return true;
  } catch {
    return false;
  }
}

function loadUserStorageCache() {
  return loadUserStorageCacheForUser("guest");
}

function getUserStorageCacheKey(userId = "guest") {
  const safeUserId = String(userId || "guest").replace(/[^a-zA-Z0-9_-]/g, "") || "guest";
  return `${userCacheStorageKey}:${safeUserId}`;
}

function loadUserStorageCacheForUser(userId = "guest") {
  const scoped = readJsonStorage(getUserStorageCacheKey(userId), {});
  if (scoped?.version === userStorageVersion && typeof scoped === "object") {
    return scoped;
  }
  const legacy = readJsonStorage(userCacheStorageKey, {});
  return legacy?.version === userStorageVersion && typeof legacy === "object" && (legacy.userId || "guest") === userId
    ? legacy
    : {};
}

function writeUserStorageCache(snapshot = getUserStorageSnapshot()) {
  const userId = snapshot?.userId || state.supabaseUser?.id || "guest";
  writeJsonStorage(getUserStorageCacheKey(userId), snapshot);
  writeJsonStorage(userCacheStorageKey, snapshot);
}

function getUserStorageSnapshotWeight(snapshot = {}) {
  const source = snapshot && typeof snapshot === "object" ? snapshot : {};
  const purchases = Array.isArray(source.unlockedCosmeticsCache?.purchases)
    ? source.unlockedCosmeticsCache.purchases
    : Array.isArray(source.shopDisplayCache?.purchases)
      ? source.shopDisplayCache.purchases
      : [];
  const achievements = source.achievementProgressCache && typeof source.achievementProgressCache === "object"
    ? source.achievementProgressCache
    : {};
  const unlockedCount = achievements.unlocked && typeof achievements.unlocked === "object"
    ? Object.keys(achievements.unlocked).length
    : 0;
  const progressCount = achievements.progress && typeof achievements.progress === "object"
    ? Object.keys(achievements.progress).length
    : 0;
  const milestoneCount = Array.isArray(achievements.claimedMilestones) ? achievements.claimedMilestones.length : 0;
  return (
    Math.max(0, Number(source.currencyDisplayCache?.coins) || 0)
    + purchases.length * 1000
    + unlockedCount * 1000
    + progressCount * 100
    + milestoneCount * 250
  );
}

function chooseBestUserStorageSnapshot(localSnapshot = {}, remoteSnapshot = {}) {
  const localValid = localSnapshot?.version === userStorageVersion;
  const remoteValid = remoteSnapshot?.version === userStorageVersion;
  if (localValid && remoteValid) {
    const localUpdatedAt = Number(localSnapshot.updatedAt || 0);
    const remoteUpdatedAt = Number(remoteSnapshot.updatedAt || 0);
    if (Math.abs(localUpdatedAt - remoteUpdatedAt) > userStorageWriteDelayMs) {
      return localUpdatedAt > remoteUpdatedAt ? localSnapshot : remoteSnapshot;
    }
    const localWeight = getUserStorageSnapshotWeight(localSnapshot);
    const remoteWeight = getUserStorageSnapshotWeight(remoteSnapshot);
    if (localWeight > remoteWeight) {
      return localSnapshot;
    }
    if (remoteWeight > localWeight) {
      return remoteSnapshot;
    }
    return remoteUpdatedAt >= localUpdatedAt
      ? remoteSnapshot
      : localSnapshot;
  }
  return remoteValid ? remoteSnapshot : localValid ? localSnapshot : null;
}

function normalizeCachedThemes(themes) {
  const uniqueThemes = [...new Set((Array.isArray(themes) ? themes : [])
    .map((theme) => String(theme || "").trim())
    .filter((theme) => triviaThemes.includes(theme)))];
  return uniqueThemes.length ? uniqueThemes : [];
}

function getCacheableAvatar(avatar) {
  const value = String(avatar || "");
  return value.length <= 180000 ? value : "";
}

function getPublicCatalogCachePayload() {
  return {
    version: publicCatalogVersion,
    updatedAt: Date.now(),
    catalog: {
      achievements: achievementCatalog.map((achievement) => achievement.id),
      cosmetics: profileShopItems.map((item) => ({
        key: getProfileShopKey(item.type, item.id),
        type: item.type,
        id: item.id,
        name: item.name,
        cost: item.cost,
        unlockType: item.unlockType || "",
        rarity: item.rarity || ""
      })),
      powerUps: powerDeck.map((power) => power.id),
      themes: [...triviaThemes]
    }
  };
}

function writePublicCatalogCache() {
  const current = readJsonStorage(publicCatalogCacheStorageKey, {});
  if (current?.version === publicCatalogVersion) {
    return;
  }
  writeJsonStorage(publicCatalogCacheStorageKey, getPublicCatalogCachePayload());
}

function getUserStorageSnapshot() {
  const avatar = getCacheableAvatar(state.profile?.avatar);
  const purchases = loadProfileShopPurchases();
  return {
    version: userStorageVersion,
    updatedAt: Date.now(),
    userId: state.supabaseUser?.id || "guest",
    profile: {
      username: state.profile?.name || savedGuestName,
      avatarPreview: avatar,
      compressedAvatar: avatar,
      cardCustomization: normalizeProfileCustomization(state.profile?.cardCustomization || loadProfileCustomization()),
      equippedAchievementId: state.profile?.equippedTitleId || "",
      specialBadges: getRoomSyncSpecialBadges(state.profile?.specialBadges || [])
    },
    settings: {
      sfx: Math.round((soundState.sfxVolume || 0) * 100),
      music: Math.round((soundState.musicVolume || 0) * 100),
      timerSeconds: state.timerSeconds,
      maxRounds: state.maxRounds,
      performanceMode: state.performanceMode,
      lastSelectedThemes: getEnabledTriviaThemes()
    },
    currencyDisplayCache: {
      coins: getCurrencyBalance()
    },
    unlockedCosmeticsCache: {
      purchases,
      equipped: normalizeProfileCustomization(state.profile?.cardCustomization || loadProfileCustomization())
    },
    recentQuestionCache: {
      total: loadRecentSetupCache().length
    },
    tutorialHelpSeenFlags: readJsonStorage(helpSeenFlagsStorageKey, {}),
    shopDisplayCache: {
      purchases,
      catalogVersion: publicCatalogVersion
    },
    achievementProgressCache: {
      unlocked: loadUnlockedAchievements(),
      progress: loadAchievementProgress(),
      claimedMilestones: loadClaimedAchievementMilestones()
    }
  };
}

function shouldBlockUserStorageSnapshotWrites() {
  if (state.userStorageHydrating || state.userStorageApplying) {
    return true;
  }
  if (state.supabaseAuthResolving) {
    return true;
  }
  if (!state.supabaseAuthResolved && hasAnyStoredSupabaseSession()) {
    return true;
  }
  return false;
}

function flushUserStorageSnapshot() {
  if (state.userStorageWriteTimerId) {
    window.clearTimeout(state.userStorageWriteTimerId);
    state.userStorageWriteTimerId = null;
  }
  if (shouldBlockUserStorageSnapshotWrites()) {
    return;
  }
  const snapshot = getDisplayUserStorageSnapshot(getUserStorageSnapshot());
  writeUserStorageCache(snapshot);
  if (state.supabaseUser) {
    void saveRemoteUserStorageSnapshot(snapshot);
  }
}

function cacheUserStorageSnapshotNow() {
  if (shouldBlockUserStorageSnapshotWrites()) {
    return null;
  }
  const snapshot = getDisplayUserStorageSnapshot(getUserStorageSnapshot());
  writeUserStorageCache(snapshot);
  return snapshot;
}

function scheduleUserStorageSnapshot() {
  if (shouldBlockUserStorageSnapshotWrites()) {
    return;
  }
  if (state.userStorageWriteTimerId) {
    window.clearTimeout(state.userStorageWriteTimerId);
  }
  state.userStorageWriteTimerId = window.setTimeout(flushUserStorageSnapshot, userStorageWriteDelayMs);
}

function setJsonLocalStorage(key, value) {
  if (Array.isArray(value) ? value.length : value && Object.keys(value).length) {
    localStorage.setItem(key, JSON.stringify(value));
  } else {
    localStorage.removeItem(key);
  }
}

function applyUserStorageSnapshot(snapshot = {}, options = {}) {
  const source = snapshot && typeof snapshot === "object" ? snapshot : {};
  const shouldApplyInventory = options.displayOnly === true
    ? false
    : options.applyInventory === true || !state.supabaseUser;
  state.userStorageApplying = true;
  try {
    const profile = source.profile && typeof source.profile === "object" ? source.profile : {};
    const settings = source.settings && typeof source.settings === "object" ? source.settings : {};
    const achievements = source.achievementProgressCache && typeof source.achievementProgressCache === "object"
      ? source.achievementProgressCache
      : {};
    const purchases = Array.isArray(source.unlockedCosmeticsCache?.purchases)
      ? source.unlockedCosmeticsCache.purchases
      : Array.isArray(source.shopDisplayCache?.purchases)
        ? source.shopDisplayCache.purchases
        : [];
    const customization = normalizeProfileCustomization(profile.cardCustomization || source.unlockedCosmeticsCache?.equipped || defaultProfileCustomization);
    const themes = normalizeCachedThemes(settings.lastSelectedThemes);
    const username = normalizeGuestNameCasing(
      String(profile.username || options.fallbackName || savedGuestName).replace(/[\r\n\t]/g, " ").slice(0, 16)
    ) || savedGuestName;
    const avatar = getCacheableAvatar(profile.compressedAvatar || profile.avatarPreview || "");
    const equippedAchievementId = achievementTitleMap[profile.equippedAchievementId] ? profile.equippedAchievementId : "";
    const sfx = clampNumber(settings.sfx, 0, 100, 50);
    const music = clampNumber(settings.music, 0, 100, 50);
    const maxRounds = clampNumber(settings.maxRounds, 1, 10, 5);
    const timerSeconds = clampNumber(settings.timerSeconds, 10, 60, 30);
    const performanceMode = normalizePerformanceMode(settings.performanceMode || getStoredPerformanceMode());

    localStorage.setItem("cardsAgainstAiProfileName", username);
    if (avatar) {
      localStorage.setItem("cardsAgainstAiProfileAvatar", avatar);
    } else {
      localStorage.removeItem("cardsAgainstAiProfileAvatar");
    }
    if (state.supabaseUser) {
      localStorage.setItem(getUserProfileStorageKey(state.supabaseUser, "name"), username);
      if (avatar) {
        localStorage.setItem(getUserProfileStorageKey(state.supabaseUser, "avatar"), avatar);
      } else {
        localStorage.removeItem(getUserProfileStorageKey(state.supabaseUser, "avatar"));
      }
    }
    localStorage.setItem(profileCustomizationStorageKey, JSON.stringify(customization));
    if (equippedAchievementId) {
      localStorage.setItem(equippedAchievementStorageKey, equippedAchievementId);
    } else {
      localStorage.removeItem(equippedAchievementStorageKey);
    }
    if (shouldApplyInventory) {
      setJsonLocalStorage(profileShopPurchasesStorageKey, purchases);
      setJsonLocalStorage(achievementStorageKey, achievements.unlocked || {});
      setJsonLocalStorage(achievementProgressStorageKey, achievements.progress || {});
      setJsonLocalStorage(achievementMilestonesStorageKey, achievements.claimedMilestones || []);
      localStorage.removeItem(unseenAchievementStorageKey);
      localStorage.setItem(currencyStorageKey, String(Math.max(0, Math.floor(Number(source.currencyDisplayCache?.coins) || 0))));
    }
    localStorage.setItem("cardsAgainstAiSfxVolume", String(sfx));
    localStorage.setItem("cardsAgainstAiMusicVolume", String(music));
    localStorage.setItem("cardsAgainstAiMaxRounds", String(maxRounds));
    localStorage.setItem("cardsAgainstAiTimerSeconds", String(timerSeconds));
    localStorage.setItem(performanceModeStorageKey, performanceMode);
    writeJsonStorage(helpSeenFlagsStorageKey, source.tutorialHelpSeenFlags || {});

    state.profile.name = username;
    state.profile.avatar = avatar;
    state.profile.equippedTitleId = equippedAchievementId;
    state.profile.cardCustomization = customization;
    state.profile.specialBadges = normalizeSpecialBadges(profile.specialBadges || []).filter((badge) => badge.id !== "admin");
    state.enabledThemes = themes.length ? themes : [...triviaThemes];
    state.roomSettings.enabledThemes = [...state.enabledThemes];
    state.maxRounds = maxRounds;
    state.timerSeconds = timerSeconds;
    state.performanceMode = performanceMode;
    if (!state.timerId) {
      state.timerRemaining = timerSeconds;
    }
    soundState.sfxVolume = sfx / 100;
    soundState.musicVolume = music / 100;
    updateMusicVolume();
    applyPerformanceMode(performanceMode);
    syncProfileToPlayer();
    renderProfile();
    renderRoomPlayers();
    renderRoomChat();
    renderLeaderboard();
    renderThemeSummary();
    syncSettingsControls();
    updateAchievementNotificationDot();
    updateQuestionSubmissionNotificationDot();
  } finally {
    state.userStorageApplying = false;
  }
}

function getUserInventoryStorageId(user = state.supabaseUser) {
  return String(user?.id || "").replace(/[^a-zA-Z0-9_-]/g, "").slice(0, 140);
}

function getUserInventoryQueueKey(userId = getUserInventoryStorageId()) {
  const safeUserId = String(userId || "guest").replace(/[^a-zA-Z0-9_-]/g, "") || "guest";
  return `${userInventoryQueueStorageKey}:${safeUserId}`;
}

function getUserInventoryMutationQueueKey(userId = getUserInventoryStorageId()) {
  const safeUserId = String(userId || "guest").replace(/[^a-zA-Z0-9_-]/g, "") || "guest";
  return `${userInventoryMutationQueueStorageKey}:${safeUserId}`;
}

function getUserInventoryCacheKey(userId = getUserInventoryStorageId()) {
  const safeUserId = String(userId || "guest").replace(/[^a-zA-Z0-9_-]/g, "") || "guest";
  return `${userInventoryCacheStorageKey}:${safeUserId}`;
}

function normalizeInventoryOpId(value) {
  return String(value || "").trim().replace(/[^a-zA-Z0-9_:.@/-]/g, "").slice(0, 220);
}

function normalizeInventoryKey(value) {
  return String(value || "").trim().replace(/[^a-zA-Z0-9_:.@/-]/g, "").slice(0, 180);
}

function createUserInventoryOpId(type, key = "") {
  const cleanType = normalizeInventoryKey(type || "op") || "op";
  const cleanKey = normalizeInventoryKey(key || Math.random().toString(36).slice(2)) || "item";
  return `${cleanType}:${cleanKey}:${Date.now()}:${Math.random().toString(36).slice(2, 8)}`;
}

function hashInventoryPayload(value) {
  const source = typeof value === "string" ? value : JSON.stringify(value || {});
  let hash = 2166136261;
  for (let index = 0; index < source.length; index += 1) {
    hash ^= source.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36);
}

function loadUserInventoryQueue(userId = getUserInventoryStorageId()) {
  const queue = readJsonStorage(getUserInventoryQueueKey(userId), []);
  return Array.isArray(queue) ? queue.filter((op) => op && typeof op === "object" && normalizeInventoryOpId(op.id)) : [];
}

function saveUserInventoryQueue(queue, userId = getUserInventoryStorageId()) {
  const cleanQueue = (Array.isArray(queue) ? queue : [])
    .filter((op) => op && typeof op === "object" && normalizeInventoryOpId(op.id))
    .slice(-250);
  if (cleanQueue.length) {
    writeJsonStorage(getUserInventoryQueueKey(userId), cleanQueue);
  } else {
    localStorage.removeItem(getUserInventoryQueueKey(userId));
  }
}

function normalizePendingInventoryMutation(entry) {
  const source = entry && typeof entry === "object" ? entry : {};
  const kind = ["purchase", "milestone"].includes(source.kind) ? source.kind : "";
  const opId = normalizeInventoryOpId(source.opId);
  const userId = getUserInventoryStorageId({ id: source.userId });
  if (!kind || !opId || !userId) {
    return null;
  }
  if (kind === "purchase") {
    const type = normalizeInventoryKey(source.type);
    const id = normalizeInventoryKey(source.id);
    return type && id ? {
      kind,
      userId,
      type,
      id,
      opId,
      createdAt: Number(source.createdAt) || Date.now()
    } : null;
  }
  const milestoneId = normalizeInventoryKey(source.milestoneId);
  return milestoneId ? {
    kind,
    userId,
    milestoneId,
    opId,
    createdAt: Number(source.createdAt) || Date.now()
  } : null;
}

function loadUserInventoryMutationQueue(userId = getUserInventoryStorageId()) {
  const queue = readJsonStorage(getUserInventoryMutationQueueKey(userId), []);
  return (Array.isArray(queue) ? queue : [])
    .map(normalizePendingInventoryMutation)
    .filter(Boolean);
}

function saveUserInventoryMutationQueue(queue, userId = getUserInventoryStorageId()) {
  const cleanQueue = (Array.isArray(queue) ? queue : [])
    .map(normalizePendingInventoryMutation)
    .filter(Boolean)
    .slice(-100);
  if (cleanQueue.length) {
    writeJsonStorage(getUserInventoryMutationQueueKey(userId), cleanQueue);
  } else {
    localStorage.removeItem(getUserInventoryMutationQueueKey(userId));
  }
}

function rememberPendingInventoryMutation(mutation) {
  const normalized = normalizePendingInventoryMutation(mutation);
  if (!normalized) {
    return null;
  }
  const queue = loadUserInventoryMutationQueue(normalized.userId);
  if (!queue.some((entry) => entry.opId === normalized.opId)) {
    saveUserInventoryMutationQueue([...queue, normalized], normalized.userId);
  }
  return normalized;
}

function forgetPendingInventoryMutation(userId, opId) {
  const safeUserId = getUserInventoryStorageId({ id: userId });
  const cleanOpId = normalizeInventoryOpId(opId);
  if (!safeUserId || !cleanOpId) {
    return;
  }
  saveUserInventoryMutationQueue(
    loadUserInventoryMutationQueue(safeUserId).filter((entry) => entry.opId !== cleanOpId),
    safeUserId
  );
}

function writeUserInventoryCache(inventory) {
  if (!inventory?.userId) {
    return;
  }
  writeJsonStorage(getUserInventoryCacheKey(inventory.userId), {
    ...inventory,
    cachedAt: Date.now()
  });
}

function loadUserInventoryCache(userId = getUserInventoryStorageId()) {
  const cache = readJsonStorage(getUserInventoryCacheKey(userId), null);
  return cache && typeof cache === "object" ? cache : null;
}

function hasPendingUserInventoryWork(userId = getUserInventoryStorageId()) {
  return Boolean(userId && (loadUserInventoryQueue(userId).length || loadUserInventoryMutationQueue(userId).length));
}

function doesActiveUserStorageCacheBelongToUser(user = state.supabaseUser) {
  const userId = getUserInventoryStorageId(user);
  if (!userId) {
    return false;
  }
  const activeCache = readJsonStorage(userCacheStorageKey, {});
  return activeCache?.version === userStorageVersion && String(activeCache.userId || "") === userId;
}

function cacheCurrentUserInventoryState(user = state.supabaseUser) {
  if (state.userInventoryApplying || !user?.id) {
    return null;
  }
  const snapshot = getLocalUserInventorySnapshot(user);
  if (snapshot) {
    writeUserInventoryCache(snapshot);
  }
  return snapshot;
}

function enqueueUserInventoryOps(ops) {
  if (state.userInventoryApplying || !state.supabaseUser?.id) {
    return;
  }
  const userId = getUserInventoryStorageId();
  const existingIds = new Set(loadUserInventoryQueue(userId).map((op) => normalizeInventoryOpId(op.id)).filter(Boolean));
  const cleanOps = (Array.isArray(ops) ? ops : [ops])
    .filter((op) => op && typeof op === "object")
    .map((op) => ({ ...op, id: normalizeInventoryOpId(op.id || createUserInventoryOpId(op.type, op.key || op.achievementId || op.milestoneId)) }))
    .filter((op) => op.id && op.type && !existingIds.has(op.id));
  if (!cleanOps.length) {
    return;
  }
  saveUserInventoryQueue([...loadUserInventoryQueue(userId), ...cleanOps], userId);
  void flushUserInventoryQueue();
}

function enqueueUserInventoryOpsForUser(user, ops) {
  const userId = getUserInventoryStorageId(user);
  if (!userId) {
    return;
  }
  const existingIds = new Set(loadUserInventoryQueue(userId).map((op) => normalizeInventoryOpId(op.id)).filter(Boolean));
  const cleanOps = (Array.isArray(ops) ? ops : [ops])
    .filter((op) => op && typeof op === "object")
    .map((op) => ({ ...op, id: normalizeInventoryOpId(op.id || createUserInventoryOpId(op.type, op.key || op.achievementId || op.milestoneId)) }))
    .filter((op) => op.id && op.type && !existingIds.has(op.id));
  if (cleanOps.length) {
    saveUserInventoryQueue([...loadUserInventoryQueue(userId), ...cleanOps], userId);
  }
}

function queueUserProfileInventorySync(reason = "profile") {
  if (!state.supabaseUser?.id || state.userInventoryApplying) {
    return;
  }
  enqueueUserInventoryOps({
    id: createUserInventoryOpId("profile", reason),
    type: "profile",
    profile: {
      equippedAchievementId: state.profile.equippedTitleId || "",
      cardCustomization: normalizeProfileCustomization(state.profile.cardCustomization || loadProfileCustomization())
    }
  });
}

async function fetchServerUserInventory(user = state.supabaseUser, options = {}) {
  const userId = getUserInventoryStorageId(user);
  if (!userId) {
    return null;
  }
  const response = await fetch(`/api/user/inventory?userId=${encodeURIComponent(userId)}`, {
    cache: "no-store",
    headers: await getInventoryAuthHeaders(options)
  });
  const result = await response.json().catch(() => ({}));
  if (!response.ok) {
    throw new Error(result.error || "Could not load server inventory.");
  }
  return result.inventory || null;
}

async function postUserInventoryOps(userId, ops, options = {}) {
  const response = await fetch("/api/user/inventory/ops", {
    method: "POST",
    keepalive: Boolean(options.keepalive),
    headers: {
      "Content-Type": "application/json",
      ...(await getInventoryAuthHeaders(options))
    },
    body: JSON.stringify({ userId, ops })
  });
  const result = await response.json().catch(() => ({}));
  if (!response.ok) {
    throw new Error(result.error || "Could not save inventory.");
  }
  return result;
}

function trackUserInventoryWrite(promise) {
  const tracked = Promise.resolve(promise);
  if (!(state.userInventoryWritePromises instanceof Set)) {
    state.userInventoryWritePromises = new Set();
  }
  state.userInventoryWritePromises.add(tracked);
  tracked.finally(() => {
    state.userInventoryWritePromises.delete(tracked);
  });
  return tracked;
}

async function waitForTrackedUserInventoryWrites() {
  const pending = [...(state.userInventoryWritePromises instanceof Set ? state.userInventoryWritePromises : [])];
  if (!pending.length) {
    return;
  }
  await Promise.allSettled(pending);
}

async function postUserInventoryPurchase(userId, type, id, opId = "", options = {}) {
  const mutation = {
    kind: "purchase",
    userId,
    type,
    id,
    opId: normalizeInventoryOpId(opId || createUserInventoryOpId("purchase-cosmetic", `${type}:${id}`)),
    createdAt: Date.now()
  };
  if (options.remember !== false) {
    rememberPendingInventoryMutation(mutation);
  }
  return trackUserInventoryWrite((async () => {
    if (options.flushWritesBefore !== false) {
      await flushPendingUserInventoryWrites({
        user: { id: userId },
        session: options.session
      });
    }
    const response = await fetch("/api/user/inventory/purchase", {
      method: "POST",
      keepalive: Boolean(options.keepalive),
      headers: {
        "Content-Type": "application/json",
        ...(await getInventoryAuthHeaders(options))
      },
      body: JSON.stringify({ userId, type, id, opId: mutation.opId })
    });
    const result = await response.json().catch(() => ({}));
    if (!response.ok) {
      if (result.inventory && !loadUserInventoryQueue(userId).length) {
        applyServerUserInventory(result.inventory, { authoritative: true });
      }
      if ([400, 409].includes(response.status)) {
        forgetPendingInventoryMutation(userId, mutation.opId);
      }
      throw new Error(result.error || result.purchase?.reason || "Could not save purchase.");
    }
    if (result.inventory) {
      applyServerUserInventory(result.inventory, { authoritative: true });
    }
    forgetPendingInventoryMutation(userId, mutation.opId);
    return result;
  })());
}

async function postUserInventoryMilestone(userId, milestoneId, opId = "", options = {}) {
  const mutation = {
    kind: "milestone",
    userId,
    milestoneId,
    opId: normalizeInventoryOpId(opId || createUserInventoryOpId("milestone", milestoneId)),
    createdAt: Date.now()
  };
  if (options.remember !== false) {
    rememberPendingInventoryMutation(mutation);
  }
  return trackUserInventoryWrite((async () => {
    const response = await fetch("/api/user/inventory/milestone", {
      method: "POST",
      keepalive: Boolean(options.keepalive),
      headers: {
        "Content-Type": "application/json",
        ...(await getInventoryAuthHeaders(options))
      },
      body: JSON.stringify({ userId, milestoneId, opId: mutation.opId })
    });
    const result = await response.json().catch(() => ({}));
    if (result.inventory) {
      applyServerUserInventory(result.inventory, { authoritative: true });
    }
    if (!response.ok) {
      if ([400, 409].includes(response.status)) {
        forgetPendingInventoryMutation(userId, mutation.opId);
      }
      throw new Error(result.error || result.milestone?.reason || "Could not save milestone.");
    }
    forgetPendingInventoryMutation(userId, mutation.opId);
    return result;
  })());
}

async function getInventoryAuthHeaders(options = {}) {
  try {
    const session = options.session || state.supabaseSession || (state.supabaseClient
      ? (await state.supabaseClient.auth.getSession())?.data?.session
      : null);
    const token = String(session?.access_token || "").trim();
    return token ? { Authorization: `Bearer ${token}` } : {};
  } catch {
    return {};
  }
}

function isLikelyFreshJwt(token) {
  const parts = String(token || "").split(".");
  if (parts.length !== 3 || parts.some((part) => !part)) {
    return false;
  }
  try {
    const payloadPart = parts[1].replace(/-/g, "+").replace(/_/g, "/");
    const paddedPayload = payloadPart.padEnd(Math.ceil(payloadPart.length / 4) * 4, "=");
    const payload = JSON.parse(window.atob(paddedPayload));
    return !payload.exp || Number(payload.exp) > Math.floor(Date.now() / 1000) + 30;
  } catch {
    return true;
  }
}

async function getQuestionSubmissionAuthHeaders(options = {}) {
  const headers = await getInventoryAuthHeaders(options);
  const token = String(headers.Authorization || "").replace(/^Bearer\s+/i, "").trim();
  return token && isLikelyFreshJwt(token) ? headers : {};
}

function getInventoryAuthHeadersSync(options = {}) {
  const session = options.session || state.supabaseSession;
  const token = String(session?.access_token || "").trim();
  return token ? { Authorization: `Bearer ${token}` } : {};
}

function getCoveredCoinOpsForInventoryQueue(userId = getUserInventoryStorageId()) {
  return loadUserInventoryQueue(userId)
    .filter((op) => op?.type === "coin" && !op.mode && normalizeInventoryOpId(op.id))
    .map((op) => ({
      id: normalizeInventoryOpId(op.id),
      delta: Math.floor(Number(op.delta) || 0)
    }))
    .filter((op) => op.id && op.delta);
}

function getKeepaliveInventoryOps(userId, priorityOps = []) {
  const seenIds = new Set();
  return [...(Array.isArray(priorityOps) ? priorityOps : []), ...loadUserInventoryQueue(userId)]
    .filter((op) => op && typeof op === "object")
    .map((op) => ({ ...op, id: normalizeInventoryOpId(op.id) }))
    .filter((op) => {
      if (!op.id || !op.type || seenIds.has(op.id)) {
        return false;
      }
      seenIds.add(op.id);
      return true;
    });
}

function sendUserInventoryQueueKeepalive(user, options = {}) {
  const userId = getUserInventoryStorageId(user || options.user || state.supabaseUser);
  if (!userId || typeof fetch !== "function") {
    return false;
  }
  const ops = getKeepaliveInventoryOps(userId, options.priorityOps).slice(0, 100);
  if (!ops.length) {
    return false;
  }
  let batch = [];
  let body = "";
  for (const op of ops) {
    const nextBatch = [...batch, op];
    const nextBody = JSON.stringify({ userId, ops: nextBatch });
    if (nextBody.length > 60000 && batch.length) {
      break;
    }
    batch = nextBatch;
    body = nextBody;
  }
  if (!batch.length || !body) {
    return false;
  }
  try {
    void fetch("/api/user/inventory/ops", {
      method: "POST",
      keepalive: true,
      headers: {
        "Content-Type": "application/json",
        ...getInventoryAuthHeadersSync(options)
      },
      body
    }).catch(() => {});
    return true;
  } catch {
    return false;
  }
}

async function flushUserInventoryQueue(options = {}) {
  const userId = options.userId || getUserInventoryStorageId(options.user || state.supabaseUser);
  if (!userId) {
    return null;
  }
  if (state.userInventoryFlushPromise) {
    return state.userInventoryFlushPromise;
  }
  const queue = loadUserInventoryQueue(userId);
  if (!queue.length) {
    return null;
  }
  state.userInventoryFlushing = true;
  state.userInventoryFlushPromise = (async () => {
    const batch = queue.slice(0, 100);
    const result = await postUserInventoryOps(userId, batch, options);
    const completedIds = new Set([
      ...(Array.isArray(result.applied) ? result.applied : []),
      ...(Array.isArray(result.skipped) ? result.skipped.map((entry) => entry.id) : [])
    ].map(normalizeInventoryOpId).filter(Boolean));
    if (completedIds.size) {
      saveUserInventoryQueue(loadUserInventoryQueue(userId).filter((op) => !completedIds.has(normalizeInventoryOpId(op.id))), userId);
    }
    if (result.inventory) {
      applyServerUserInventory(result.inventory, { authoritative: true });
    }
    if (loadUserInventoryQueue(userId).length) {
      window.setTimeout(() => flushUserInventoryQueue(options), 750);
    }
    return result;
  })();
  try {
    return await state.userInventoryFlushPromise;
  } catch (error) {
    console.warn("Inventory queue sync failed:", error.message || error);
    return null;
  } finally {
    state.userInventoryFlushing = false;
    state.userInventoryFlushPromise = null;
  }
}

async function flushPendingUserInventoryWrites(options = {}) {
  await flushUserInventoryQueue(options);
}

async function flushPendingUserInventoryMutations(options = {}) {
  const userId = options.userId || getUserInventoryStorageId(options.user || state.supabaseUser);
  if (!userId) {
    return;
  }
  const queue = loadUserInventoryMutationQueue(userId);
  if (!queue.length) {
    return;
  }
  for (const mutation of queue) {
    try {
      if (mutation.kind === "purchase") {
        await postUserInventoryPurchase(mutation.userId, mutation.type, mutation.id, mutation.opId, {
          ...options,
          remember: false
        });
      } else if (mutation.kind === "milestone") {
        await postUserInventoryMilestone(mutation.userId, mutation.milestoneId, mutation.opId, {
          ...options,
          remember: false
        });
      }
    } catch (error) {
      console.warn("Pending inventory mutation sync failed:", error.message || error);
      if (options.keepalive) {
        return;
      }
    }
  }
}

function flushPendingUserInventoryBeforePageExit() {
  const user = state.supabaseUser;
  if (!user?.id) {
    return;
  }
  const session = state.supabaseSession;
  const stateSync = enqueueCurrentUserInventoryStateForUser(user, { includeOps: true });
  sendUserInventoryQueueKeepalive(user, { session, priorityOps: stateSync?.ops || [] });
  void flushPendingUserInventoryWrites({ user, session, keepalive: true });
  void flushPendingUserInventoryMutations({ user, session, keepalive: true });
}

function applyServerUserInventory(inventory = {}, options = {}) {
  const userId = getUserInventoryStorageId(options.user || state.supabaseUser);
  const inventoryUserId = getUserInventoryStorageId({ id: inventory.userId || userId });
  if (!userId || inventoryUserId !== userId) {
    return;
  }
  const serverInventory = {
    ...inventory,
    userId: inventoryUserId
  };
  const shouldMergeLocal = options.authoritative !== true && options.mergeLocal !== false;
  const canTrustCurrentBrowserInventory = options.includeLocalSnapshot === true
    || (options.includeLocalSnapshot !== false && doesActiveUserStorageCacheBelongToUser({ id: userId }));
  const includeLocalSnapshot = options.includeLocalSnapshot === true
    || (options.includeLocalSnapshot !== false && hasPendingUserInventoryWork(userId) && canTrustCurrentBrowserInventory);
  const inventoryToApply = shouldMergeLocal
    ? mergeUserInventoriesForHydration({ id: userId }, [
      serverInventory,
      loadUserInventoryCache(userId),
      includeLocalSnapshot ? getLocalUserInventorySnapshot({ id: userId }) : null
    ]) || serverInventory
    : serverInventory;
  state.userInventoryApplying = true;
  try {
    const coins = Math.max(0, Math.floor(Number(inventoryToApply.coins) || 0));
    const cosmetics = [...new Set((Array.isArray(inventoryToApply.cosmetics) ? inventoryToApply.cosmetics : [])
      .map(normalizeInventoryKey)
      .filter(Boolean))];
    const achievements = inventoryToApply.achievements && typeof inventoryToApply.achievements === "object" ? inventoryToApply.achievements : {};
    const progress = inventoryToApply.achievementProgress && typeof inventoryToApply.achievementProgress === "object" ? inventoryToApply.achievementProgress : {};
    const milestones = [...new Set((Array.isArray(inventoryToApply.claimedMilestones) ? inventoryToApply.claimedMilestones : [])
      .map(normalizeInventoryKey)
      .filter(Boolean))];
    const profile = inventoryToApply.profile && typeof inventoryToApply.profile === "object" ? inventoryToApply.profile : {};
    const profileCustomization = profile.cardCustomization
      ? normalizeProfileCustomization(profile.cardCustomization)
      : null;
    const equippedAchievementId = achievementTitleMap[profile.equippedAchievementId] ? profile.equippedAchievementId : "";
    localStorage.setItem(currencyStorageKey, String(coins));
    setJsonLocalStorage(profileShopPurchasesStorageKey, cosmetics);
    setJsonLocalStorage(achievementStorageKey, achievements);
    setJsonLocalStorage(achievementProgressStorageKey, progress);
    setJsonLocalStorage(achievementMilestonesStorageKey, milestones);
    if (profileCustomization) {
      state.profile.cardCustomization = profileCustomization;
      localStorage.setItem(profileCustomizationStorageKey, JSON.stringify(profileCustomization));
    }
    if (equippedAchievementId) {
      state.profile.equippedTitleId = equippedAchievementId;
      localStorage.setItem(equippedAchievementStorageKey, equippedAchievementId);
    } else if (profile.equippedAchievementId === "") {
      state.profile.equippedTitleId = "";
      localStorage.removeItem(equippedAchievementStorageKey);
    }
    syncProfileCustomizationToPlayers();
    writeUserInventoryCache(inventoryToApply);
    renderProfile();
    renderProfileShop();
    renderAchievementLibraryPreservingScroll();
    renderRoomPlayers();
    renderLeaderboard();
    updateAchievementNotificationDot();
    if (isModalOpen(elements.profileCustomModal)) {
      renderProfileCustomizationModal();
    }
  } finally {
    state.userInventoryApplying = false;
  }
}

function getInventoryFromUserStorageSnapshot(snapshot = {}, userId = getUserInventoryStorageId()) {
  const source = snapshot && typeof snapshot === "object" ? snapshot : {};
  const achievements = source.achievementProgressCache && typeof source.achievementProgressCache === "object"
    ? source.achievementProgressCache
    : {};
  const purchases = Array.isArray(source.unlockedCosmeticsCache?.purchases)
    ? source.unlockedCosmeticsCache.purchases
    : Array.isArray(source.shopDisplayCache?.purchases)
      ? source.shopDisplayCache.purchases
      : [];
  const profile = source.profile && typeof source.profile === "object" ? source.profile : {};
  return {
    userId,
    coins: Math.max(0, Math.floor(Number(source.currencyDisplayCache?.coins) || 0)),
    cosmetics: [...new Set(purchases.map(normalizeInventoryKey).filter(Boolean))],
    achievements: achievements.unlocked && typeof achievements.unlocked === "object" ? achievements.unlocked : {},
    achievementProgress: achievements.progress && typeof achievements.progress === "object" ? achievements.progress : {},
    claimedMilestones: [...new Set((Array.isArray(achievements.claimedMilestones) ? achievements.claimedMilestones : [])
      .map(normalizeInventoryKey)
      .filter(Boolean))],
    profile: {
      equippedAchievementId: achievementTitleMap[profile.equippedAchievementId] ? profile.equippedAchievementId : "",
      cardCustomization: normalizeProfileCustomization(profile.cardCustomization || source.unlockedCosmeticsCache?.equipped || defaultProfileCustomization)
    },
    updatedAt: source.updatedAt || Date.now()
  };
}

function getInventoryMigrationOpsFromSnapshot(snapshot = {}, userId = getUserInventoryStorageId()) {
  return getInventoryStateOpsFromInventory(getInventoryFromUserStorageSnapshot(snapshot, userId), {
    userId,
    prefix: "migration"
  });
}

function enqueueInventoryRecoveryOpsForUser(user, sources = [], options = {}) {
  const userId = getUserInventoryStorageId(user);
  if (!userId) {
    return [];
  }
  const coveredCoinOps = getCoveredCoinOpsForInventoryQueue(userId);
  const seenIds = new Set(loadUserInventoryQueue(userId).map((op) => normalizeInventoryOpId(op.id)).filter(Boolean));
  const ops = [];
  sources.forEach((source, index) => {
    if (!source || isServerInventoryEmpty(source)) {
      return;
    }
    getInventoryStateOpsFromInventory(source, {
      userId,
      prefix: options.prefix || `recovery-${index + 1}`,
      coveredCoinOps
    }).forEach((op) => {
      const id = normalizeInventoryOpId(op.id);
      if (!id || seenIds.has(id)) {
        return;
      }
      seenIds.add(id);
      ops.push(op);
    });
  });
  if (ops.length) {
    enqueueUserInventoryOpsForUser(user, ops);
  }
  return ops;
}

function getLocalUserInventorySnapshot(user = state.supabaseUser) {
  const userId = getUserInventoryStorageId(user);
  if (!userId) {
    return null;
  }
  return {
    userId,
    profile: {
      equippedAchievementId: state.profile?.equippedTitleId || "",
      cardCustomization: normalizeProfileCustomization(state.profile?.cardCustomization || loadProfileCustomization())
    },
    coins: loadCurrencyBalance(),
    coinTransactions: [],
    cosmetics: [...new Set(loadProfileShopPurchases().map(normalizeInventoryKey).filter(Boolean))],
    achievements: loadUnlockedAchievements(),
    achievementProgress: loadAchievementProgress(),
    claimedMilestones: [...new Set(loadClaimedAchievementMilestones().map(normalizeInventoryKey).filter(Boolean))],
    updatedAt: Date.now()
  };
}

function getInventoryStateOpsFromInventory(inventory = {}, options = {}) {
  const userId = normalizeInventoryKey(inventory.userId || options.userId || getUserInventoryStorageId());
  if (!userId) {
    return [];
  }
  const prefix = normalizeInventoryKey(options.prefix || "state") || "state";
  const achievements = inventory.achievements && typeof inventory.achievements === "object" ? inventory.achievements : {};
  const progress = inventory.achievementProgress && typeof inventory.achievementProgress === "object" ? inventory.achievementProgress : {};
  const coins = Math.max(0, Math.floor(Number(inventory.coins) || 0));
  const coveredCoinOps = (Array.isArray(options.coveredCoinOps) ? options.coveredCoinOps : [])
    .map((op) => ({
      id: normalizeInventoryOpId(op?.id),
      delta: Math.floor(Number(op?.delta) || 0)
    }))
    .filter((op) => op.id && op.delta)
    .slice(0, 200);
  const ops = [];
  if (coins > 0 || coveredCoinOps.length) {
    ops.push({
      id: `${prefix}:${userId}:coins:${coins}:${hashInventoryPayload(coveredCoinOps)}`,
      type: "coin",
      mode: "reconcile",
      value: coins,
      reason: "state-sync",
      coveredCoinOps
    });
  }
  [...new Set((Array.isArray(inventory.cosmetics) ? inventory.cosmetics : [])
    .map(normalizeInventoryKey)
    .filter(Boolean))].forEach((key) => {
    ops.push({ id: `${prefix}:${userId}:cosmetic:${key}`, type: "cosmetic", key });
  });
  Object.entries(achievements).forEach(([achievementId, record]) => {
    const key = normalizeInventoryKey(achievementId);
    if (key) {
      ops.push({ id: `${prefix}:${userId}:achievement:${key}`, type: "achievement", achievementId: key, record });
    }
  });
  Object.entries(progress).forEach(([key, value]) => {
    const cleanKey = normalizeInventoryKey(key);
    const cleanValue = Math.max(0, Math.floor(Number(value) || 0));
    if (cleanKey && cleanValue > 0) {
      ops.push({
        id: `${prefix}:${userId}:progress:${cleanKey}:${cleanValue}`,
        type: "achievement-progress",
        key: cleanKey,
        value: cleanValue,
        mode: "max"
      });
    }
  });
  [...new Set((Array.isArray(inventory.claimedMilestones) ? inventory.claimedMilestones : [])
    .map(normalizeInventoryKey)
    .filter(Boolean))].forEach((milestoneId) => {
    ops.push({ id: `${prefix}:${userId}:milestone:${milestoneId}`, type: "milestone", milestoneId });
  });
  const profile = inventory.profile && typeof inventory.profile === "object" ? inventory.profile : {};
  const profilePayload = {
    equippedAchievementId: achievementTitleMap[profile.equippedAchievementId] ? profile.equippedAchievementId : "",
    cardCustomization: normalizeProfileCustomization(profile.cardCustomization || defaultProfileCustomization)
  };
  ops.push({
    id: `${prefix}:${userId}:profile:${hashInventoryPayload(profilePayload)}`,
    type: "profile",
    profile: profilePayload
  });
  return ops;
}

function mergeAchievementProgressSources(sources = []) {
  const merged = {};
  sources.forEach((source) => {
    const progress = source?.achievementProgress && typeof source.achievementProgress === "object" ? source.achievementProgress : {};
    Object.entries(progress).forEach(([key, value]) => {
      const cleanKey = normalizeInventoryKey(key);
      const cleanValue = Math.max(0, Math.floor(Number(value) || 0));
      if (cleanKey && cleanValue > Math.max(0, Math.floor(Number(merged[cleanKey]) || 0))) {
        merged[cleanKey] = cleanValue;
      }
    });
  });
  return merged;
}

function getInventoryMergeWeight(inventory = {}) {
  const source = inventory && typeof inventory === "object" ? inventory : {};
  const cosmetics = Array.isArray(source.cosmetics) ? source.cosmetics.length : 0;
  const achievements = source.achievements && typeof source.achievements === "object"
    ? Object.keys(source.achievements).length
    : 0;
  const progress = source.achievementProgress && typeof source.achievementProgress === "object"
    ? Object.values(source.achievementProgress).reduce((total, value) => total + Math.max(0, Math.floor(Number(value) || 0)), 0)
    : 0;
  const milestones = Array.isArray(source.claimedMilestones) ? source.claimedMilestones.length : 0;
  const coins = Math.max(0, Math.floor(Number(source.coins) || 0));
  return coins + cosmetics * 1000 + achievements * 1000 + progress + milestones * 250;
}

function getInventoryProfileWeight(inventory = {}) {
  const profile = inventory?.profile && typeof inventory.profile === "object" ? inventory.profile : {};
  let weight = 0;
  if (achievementTitleMap[profile.equippedAchievementId]) {
    weight += 300;
  }
  if (profile.cardCustomization) {
    const customization = normalizeProfileCustomization(profile.cardCustomization);
    if (JSON.stringify(customization) !== JSON.stringify(normalizeProfileCustomization(defaultProfileCustomization))) {
      weight += 50;
    }
  }
  return weight;
}

function mergeInventoryProfileFields(profileSources = []) {
  const sortedSources = [...profileSources]
    .filter((source) => source && typeof source.profile === "object")
    .sort((a, b) => {
      const profileDelta = getInventoryProfileWeight(b) - getInventoryProfileWeight(a);
      if (profileDelta) {
        return profileDelta;
      }
      const timeDelta = (Number(b.updatedAt) || 0) - (Number(a.updatedAt) || 0);
      return timeDelta || getInventoryMergeWeight(b) - getInventoryMergeWeight(a);
    });
  const fallbackProfile = sortedSources[0]?.profile || {};
  const titleSource = sortedSources.find((source) => achievementTitleMap[source.profile?.equippedAchievementId]);
  const styleSource = sortedSources.find((source) => {
    const customization = source.profile?.cardCustomization;
    if (!customization) {
      return false;
    }
    const normalized = normalizeProfileCustomization(customization);
    return JSON.stringify(normalized) !== JSON.stringify(normalizeProfileCustomization(defaultProfileCustomization));
  });
  const equippedAchievementId = achievementTitleMap[titleSource?.profile?.equippedAchievementId]
    ? titleSource.profile.equippedAchievementId
    : achievementTitleMap[fallbackProfile.equippedAchievementId]
      ? fallbackProfile.equippedAchievementId
      : "";
  const rawCustomization = styleSource?.profile?.cardCustomization || fallbackProfile.cardCustomization || defaultProfileCustomization;
  const cardCustomization = normalizeProfileCustomization(rawCustomization);
  return {
    equippedAchievementId,
    cardCustomization
  };
}

function mergeUserInventoriesForHydration(user, inventories = []) {
  const userId = getUserInventoryStorageId(user);
  const sources = (Array.isArray(inventories) ? inventories : [])
    .filter((inventory) => inventory && typeof inventory === "object")
    .map((inventory) => ({
      ...inventory,
      userId: normalizeInventoryKey(inventory.userId || userId)
    }))
    .filter((inventory) => inventory.userId === userId);
  if (!sources.length) {
    return null;
  }
  const mergedInventory = {
    userId,
    coins: Math.max(...sources.map((source) => Math.max(0, Math.floor(Number(source.coins) || 0)))),
    coinTransactions: [],
    cosmetics: [...new Set(sources.flatMap((source) => Array.isArray(source.cosmetics) ? source.cosmetics : [])
      .map(normalizeInventoryKey)
      .filter(Boolean))],
    achievements: sources.reduce((merged, source) => ({
      ...merged,
      ...(source.achievements && typeof source.achievements === "object" ? source.achievements : {})
    }), {}),
    achievementProgress: mergeAchievementProgressSources(sources),
    claimedMilestones: [...new Set(sources.flatMap((source) => Array.isArray(source.claimedMilestones) ? source.claimedMilestones : [])
      .map(normalizeInventoryKey)
      .filter(Boolean))],
    profile: {},
    updatedAt: Math.max(...sources.map((source) => Number(source.updatedAt) || 0), Date.now())
  };
  mergedInventory.profile = mergeInventoryProfileFields(sources);
  return mergedInventory;
}

function enqueueCurrentUserInventoryStateForUser(user = state.supabaseUser, options = {}) {
  const snapshot = getLocalUserInventorySnapshot(user);
  if (!snapshot) {
    return null;
  }
  const userId = getUserInventoryStorageId(user);
  const coveredCoinOps = getCoveredCoinOpsForInventoryQueue(userId);
  const ops = getInventoryStateOpsFromInventory(snapshot, {
    prefix: "state",
    coveredCoinOps
  });
  writeUserInventoryCache(snapshot);
  enqueueUserInventoryOpsForUser(user, ops);
  return options.includeOps ? { snapshot, ops } : snapshot;
}

function isServerInventoryEmpty(inventory = {}) {
  const profileCustomization = inventory.profile?.cardCustomization
    ? normalizeProfileCustomization(inventory.profile.cardCustomization)
    : null;
  const hasSavedProfile = Boolean(inventory.profile?.equippedAchievementId)
    || (profileCustomization && JSON.stringify(profileCustomization) !== JSON.stringify(normalizeProfileCustomization(defaultProfileCustomization)));
  return !Math.max(0, Math.floor(Number(inventory.coins) || 0))
    && !(Array.isArray(inventory.cosmetics) && inventory.cosmetics.length)
    && !(inventory.achievements && Object.keys(inventory.achievements).length)
    && !(inventory.achievementProgress && Object.keys(inventory.achievementProgress).length)
    && !(Array.isArray(inventory.claimedMilestones) && inventory.claimedMilestones.length)
    && !hasSavedProfile;
}

function resetSignedOutAccountState() {
  const guestName = createGuestName();
  localStorage.setItem("cardsAgainstAiGuestName", guestName);
  [
    profileCustomizationDebugStorageKey,
    profileSpecialBadgeDebugStorageKey,
    creatorApprovedCountStorageKey,
    disabledAchievementStorageKey,
    questionSubmissionSeenStorageKey,
    questionSubmissionRefundedStorageKey
  ].forEach((key) => localStorage.removeItem(key));
  state.userQuestionSubmissions = [];
  updateQuestionSubmissionNotificationDot();
  const guestSnapshot = {
    version: userStorageVersion,
    updatedAt: Date.now(),
    userId: "guest",
    profile: {
      username: guestName,
      avatarPreview: "",
      compressedAvatar: "",
      cardCustomization: defaultProfileCustomization,
      equippedAchievementId: "",
      specialBadges: []
    },
    settings: {
      sfx: 50,
      music: 50,
      timerSeconds: 30,
      maxRounds: 5,
      performanceMode: "full",
      lastSelectedThemes: [...triviaThemes]
    },
    currencyDisplayCache: { coins: 0 },
    unlockedCosmeticsCache: { purchases: [], equipped: defaultProfileCustomization },
    shopDisplayCache: { purchases: [], catalogVersion: publicCatalogVersion },
    achievementProgressCache: { unlocked: {}, progress: {}, claimedMilestones: [] },
    tutorialHelpSeenFlags: {}
  };
  applyUserStorageSnapshot(guestSnapshot, { fallbackName: guestName });
  writeUserStorageCache(guestSnapshot);
}

async function loadRemoteUserStorageSnapshot(user) {
  if (!state.supabaseClient || !user?.id) {
    return null;
  }
  const { data, error } = await state.supabaseClient
    .from("user_storage")
    .select("data, updated_at")
    .eq("user_id", user.id)
    .maybeSingle();
  if (error) {
    console.warn("Supabase user storage load failed:", error.message || error);
    return null;
  }
  return data?.data && typeof data.data === "object" ? data.data : null;
}

async function saveRemoteUserStorageSnapshot(snapshot = getUserStorageSnapshot()) {
  return saveRemoteUserStorageSnapshotForUser(snapshot, state.supabaseUser, state.supabaseClient);
}

function getDisplayUserStorageSnapshot(snapshot = getUserStorageSnapshot()) {
  const source = snapshot && typeof snapshot === "object" ? snapshot : getUserStorageSnapshot();
  const sourcePurchases = Array.isArray(source.unlockedCosmeticsCache?.purchases)
    ? source.unlockedCosmeticsCache.purchases
    : Array.isArray(source.shopDisplayCache?.purchases)
      ? source.shopDisplayCache.purchases
      : null;
  const purchases = [...new Set([...(sourcePurchases || []), ...loadProfileShopPurchases()].map(normalizeInventoryKey).filter(Boolean))];
  const achievements = source.achievementProgressCache && typeof source.achievementProgressCache === "object"
    ? source.achievementProgressCache
    : {};
  const unlocked = achievements.unlocked && typeof achievements.unlocked === "object"
    ? { ...loadUnlockedAchievements(), ...achievements.unlocked }
    : loadUnlockedAchievements();
  const localProgress = loadAchievementProgress();
  const sourceProgress = achievements.progress && typeof achievements.progress === "object" ? achievements.progress : {};
  const progress = { ...localProgress };
  Object.entries(sourceProgress).forEach(([key, value]) => {
    progress[key] = Math.max(
      Math.max(0, Math.floor(Number(progress[key]) || 0)),
      Math.max(0, Math.floor(Number(value) || 0))
    );
  });
  const claimedMilestones = [...new Set([
    ...(Array.isArray(achievements.claimedMilestones) ? achievements.claimedMilestones : []),
    ...loadClaimedAchievementMilestones()
  ].map(normalizeInventoryKey).filter(Boolean))];
  const sourceCoins = Math.max(0, Math.floor(Number(source.currencyDisplayCache?.coins) || 0));
  const localCoins = Math.max(0, Math.floor(Number(localStorage.getItem(currencyStorageKey)) || 0));
  return {
    ...source,
    currencyDisplayCache: {
      coins: Math.max(sourceCoins, localCoins)
    },
    unlockedCosmeticsCache: {
      purchases,
      equipped: source.unlockedCosmeticsCache?.equipped || source.profile?.cardCustomization || defaultProfileCustomization
    },
    shopDisplayCache: {
      purchases,
      catalogVersion: publicCatalogVersion
    },
    achievementProgressCache: {
      unlocked,
      progress,
      claimedMilestones
    }
  };
}

async function saveRemoteUserStorageSnapshotForUser(snapshot = getUserStorageSnapshot(), user = state.supabaseUser, client = state.supabaseClient) {
  if (!client || !user?.id) {
    return null;
  }
  const snapshotUserId = String(snapshot?.userId || "");
  if (snapshotUserId && snapshotUserId !== user.id) {
    console.warn("Skipped user storage save for mismatched account snapshot.");
    return null;
  }
  const displaySnapshot = getDisplayUserStorageSnapshot(snapshot);
  const payload = {
    user_id: user.id,
    data: { ...displaySnapshot, userId: user.id },
    updated_at: new Date(displaySnapshot.updatedAt || Date.now()).toISOString()
  };
  const { error } = await client
    .from("user_storage")
    .upsert(payload, { onConflict: "user_id" });
  if (error) {
    console.warn("Supabase user storage save failed:", error.message || error);
    return null;
  }
  return payload;
}

function applyCachedSignedInProfilePreview(user) {
  return applyCachedSignedInProfilePreviewForUserId(user?.id, {
    fallbackName: state.profile.name
  });
}

function applyCachedSignedInProfilePreviewForUserId(userId, options = {}) {
  const safeUserId = String(userId || "").trim();
  if (!safeUserId) {
    return false;
  }
  const localSnapshot = loadUserStorageCacheForUser(safeUserId);
  if (localSnapshot?.version !== userStorageVersion) {
    return false;
  }
  state.profileLoadedFromCache = true;
  applyUserStorageSnapshot(localSnapshot, {
    fallbackName: options.fallbackName || state.profile.name,
    displayOnly: true
  });
  syncProfileLoadingState();
  renderSupabaseAuthControls();
  return true;
}

async function hydrateSignedInUserStorage(user) {
  if (!user?.id) {
    return;
  }
  let restoredSnapshot = false;
  setProfileLoading(true);
  let chosenSnapshot = null;
  let localSnapshot = null;
  let cachedInventory = null;
  try {
    state.userStorageHydrating = true;
    syncProfileLoadingState();
    renderSupabaseAuthControls();
    try {
      localSnapshot = loadUserStorageCacheForUser(user.id);
      const remoteSnapshot = await loadRemoteUserStorageSnapshot(user);
      chosenSnapshot = chooseBestUserStorageSnapshot(localSnapshot, remoteSnapshot);
      if (chosenSnapshot) {
        state.profileLoadedFromCache = false;
        applyUserStorageSnapshot(chosenSnapshot, { fallbackName: state.profile.name, applyInventory: false });
        writeUserStorageCache(getDisplayUserStorageSnapshot(chosenSnapshot));
        restoredSnapshot = true;
      } else {
        console.warn("No saved user storage snapshot found; keeping current signed-in profile without overwriting user progress.");
      }
    } finally {
      state.userStorageHydrating = false;
    }
    try {
      cachedInventory = loadUserInventoryCache(user.id);
      const canTrustCurrentBrowserInventory = doesActiveUserStorageCacheBelongToUser(user);
      const currentBrowserInventory = canTrustCurrentBrowserInventory
        ? getLocalUserInventorySnapshot(user)
        : null;
      const recoverySources = [
        cachedInventory,
        getInventoryFromUserStorageSnapshot(localSnapshot, user.id),
        getInventoryFromUserStorageSnapshot(chosenSnapshot, user.id)
      ];
      if (currentBrowserInventory) {
        recoverySources.unshift(currentBrowserInventory);
      }
      enqueueInventoryRecoveryOpsForUser(user, recoverySources);
      await flushPendingUserInventoryWrites({ user });
      await flushPendingUserInventoryMutations({ user });
      let inventory = await fetchServerUserInventory(user);
      cachedInventory = loadUserInventoryCache(user.id);
      let migrationOps = isServerInventoryEmpty(inventory) ? getInventoryMigrationOpsFromSnapshot(chosenSnapshot || {}, user.id) : [];
      if (!migrationOps.length && isServerInventoryEmpty(inventory) && cachedInventory && !isServerInventoryEmpty(cachedInventory)) {
        migrationOps = getInventoryStateOpsFromInventory(cachedInventory, { userId: user.id, prefix: "cache" });
      }
      if (migrationOps.length) {
        const migrated = await postUserInventoryOps(user.id, migrationOps);
        inventory = migrated.inventory || inventory;
      }
      if (inventory) {
        const mergedInventory = mergeUserInventoriesForHydration(user, [
          inventory,
          cachedInventory,
          getInventoryFromUserStorageSnapshot(localSnapshot, user.id),
          getInventoryFromUserStorageSnapshot(chosenSnapshot, user.id),
          currentBrowserInventory
        ]);
        const inventoryToApply = mergedInventory || (
          isServerInventoryEmpty(inventory) && cachedInventory && !isServerInventoryEmpty(cachedInventory)
            ? cachedInventory
            : inventory
        );
        applyServerUserInventory(inventoryToApply, { includeLocalSnapshot: canTrustCurrentBrowserInventory });
        const recoveryOps = getInventoryStateOpsFromInventory(inventoryToApply, {
          userId: user.id,
          prefix: "hydration",
          coveredCoinOps: getCoveredCoinOpsForInventoryQueue(userId)
        });
        if (recoveryOps.length) {
          enqueueUserInventoryOpsForUser(user, recoveryOps);
          void flushPendingUserInventoryWrites({ user });
        }
      } else {
        if (cachedInventory) {
          applyServerUserInventory(cachedInventory, { includeLocalSnapshot: canTrustCurrentBrowserInventory });
        }
      }
    } catch (error) {
      console.warn("Server inventory hydration failed:", error.message || error);
      const cachedInventory = loadUserInventoryCache(user.id);
      if (cachedInventory) {
        applyServerUserInventory(cachedInventory);
      }
    }
    if (restoredSnapshot) {
      flushUserStorageSnapshot();
    }
    void loadUserQuestionSubmissions();
  } finally {
    state.profileLoadedFromCache = false;
    setProfileLoading(false);
  }
}
