async function startGame(mode) {
  initAudio();
  startMusic();
  playSound("click");
  clearRoomAutoResolve();
  stopRoomDirectoryPolling();
  if (mode === "room") {
    ensureRoomCurrentOwner();
    const appliedSyncedSettings = applyRoomGameMatchSettings(state.roomGame || state.joiningRoom?.game, { code: state.roomSettings.code }, { render: false, resetTimer: true });
    if (!appliedSyncedSettings) {
      syncRoomMatchStateFromSettings(state.roomSettings, { render: false, resetTimer: true });
    }
  }
  resetMatch(mode);
  const matchToken = state.matchWorkToken;
  setHidden(elements.modeScreen, true);
  setHidden(elements.roomScreen, true);
  setHidden(elements.joinScreen, true);
  setHidden(elements.roomLobbyScreen, true);
  setHidden(elements.gameStage, false);
  if (mode === "room") {
    await ensureSupabaseAuthReady({ realtime: true });
    startRoomRealtime(state.roomSettings.code);
    startRoomDirectoryPolling();
  }
  resetRoundUiForLoading();
  try {
    const enabledThemes = getEnabledTriviaThemes();
    const firstRoundSetupOptions = { round: 1, totalRounds: state.maxRounds };
    const syncedSetup = mode === "room" && !isCurrentHost()
      ? getSyncedRoomSetupForRound(1) || await waitForSyncedRoomSetupForRound(1)
      : null;
    const firstSetup = syncedSetup
      || takeReservedSetup(enabledThemes, "", firstRoundSetupOptions)
      || takeWarmSetup(enabledThemes, firstRoundSetupOptions)
      || await getWarmSetupPromise(enabledThemes, firstRoundSetupOptions)
      || await requestRoundSetup(firstRoundSetupOptions);
    if (!isCurrentMatchWork(matchToken)) {
      return;
    }
    if (state.warmSetup === firstSetup) {
      clearWarmSetup();
    }
    applyRoundSetup(firstSetup);
    if (mode === "room" && !isCurrentHost()) {
      applyRoomGamePowerState();
    }
  } catch (error) {
    if (isAbortError(error) || !isCurrentMatchWork(matchToken)) {
      return;
    }
    console.warn(error);
    stopLoadingMessages();
    playSound("error");
    elements.errorText.textContent = `${error.message} Start the server with npm start and make sure your model settings are valid.`;
    setHidden(elements.loadingPanel, true);
    setHidden(elements.errorPanel, false);
  }
}

function generateRoomCode() {
  for (let attempt = 0; attempt < 30; attempt += 1) {
    const code = `CAI-${Math.floor(1000 + Math.random() * 9000)}`;
    if (!state.hostedRooms.some((room) => room.code === code) && !isRoomLocallyClosed(code)) {
      return code;
    }
  }
  return `CAI-${Math.floor(1000 + Math.random() * 9000)}`;
}

function normalizeJoinRoomCode(value = "") {
  const raw = String(value || "").trim().toUpperCase().replace(/\s+/g, "");
  const shortMatch = raw.match(/^(\d{4})$/);
  if (shortMatch) {
    return `CAI-${shortMatch[1]}`;
  }
  const caiMatch = raw.match(/^CAI-?(\d{4})$/);
  if (caiMatch) {
    return `CAI-${caiMatch[1]}`;
  }
  return raw.slice(0, 12);
}

function getRoomShortCode(code = state.roomSettings.code) {
  const match = String(code || "").trim().toUpperCase().match(/^CAI-(\d{4})$/);
  return match ? match[1] : "";
}

function getRoomInviteUrl(code = state.roomSettings.code) {
  const shortCode = getRoomShortCode(code);
  if (!shortCode) {
    return "";
  }
  return `${window.location.origin}/${shortCode}`;
}

function getInitialRoomInviteCodeFromPath() {
  const path = decodeURIComponent(String(window.location.pathname || "/")).replace(/\/+$/, "");
  const match = path.match(/^\/(?:CAI-?)?(\d{4})$/i);
  if (match) {
    return `CAI-${match[1]}`;
  }
  const hash = decodeURIComponent(String(window.location.hash || "")).replace(/^#+/, "").replace(/\/+$/, "");
  const hashMatch = hash.match(/^\/?(?:CAI-?)?(\d{4})$/i);
  return hashMatch ? `CAI-${hashMatch[1]}` : "";
}

function setRoomInviteUrlPath(code = state.roomSettings.code, options = {}) {
  const shortCode = getRoomShortCode(code);
  if (!shortCode || !window.history?.replaceState) {
    return;
  }
  const nextPath = `/${shortCode}`;
  const currentPath = decodeURIComponent(String(window.location.pathname || "/")).replace(/\/+$/, "") || "/";
  if (currentPath === nextPath && !window.location.hash) {
    return;
  }
  const method = options.push ? "pushState" : "replaceState";
  window.history[method]({}, document.title, `${window.location.origin}${nextPath}`);
}

function clearRoomInviteUrlPath() {
  if (!getInitialRoomInviteCodeFromPath() || !window.history?.replaceState) {
    return;
  }
  window.history.replaceState({}, document.title, `${window.location.origin}/`);
}

async function copyTextToClipboard(text = "") {
  if (!text) {
    return false;
  }
  if (navigator.clipboard?.writeText) {
    await navigator.clipboard.writeText(text);
    return true;
  }
  const input = document.createElement("textarea");
  input.value = text;
  input.setAttribute("readonly", "");
  input.style.position = "fixed";
  input.style.opacity = "0";
  document.body.appendChild(input);
  input.select();
  const ok = document.execCommand("copy");
  input.remove();
  return ok;
}

async function copyCurrentRoomInviteLink(button = null) {
  const inviteUrl = getRoomInviteUrl();
  if (!inviteUrl) {
    return;
  }
  try {
    await copyTextToClipboard(inviteUrl);
    const target = button || elements.copyRoomInviteButton || elements.copyLobbyInviteButton;
    if (target) {
      const previous = target.textContent;
      target.textContent = "Copied";
      window.setTimeout(() => {
        if (target.isConnected) {
          target.textContent = previous || "Copy Invite Link";
        }
      }, 1200);
    }
    addSystemChat(`Invite link copied: ${inviteUrl}`, { private: true, sync: false });
  } catch (error) {
    console.warn("Could not copy invite link:", error.message || error);
    addSystemChat("Could not copy the invite link. Copy the room code instead.", { private: true, sync: false });
  }
}

function syncRoomInviteButtons() {
  const inviteUrl = getRoomInviteUrl();
  [elements.copyRoomInviteButton, elements.copyLobbyInviteButton].forEach((button) => {
    if (!button) {
      return;
    }
    button.disabled = !inviteUrl;
    button.dataset.description = inviteUrl ? `Copy ${inviteUrl}` : "Create a room first.";
  });
}

function getDefaultRoomSettings(code = "CAI-0000") {
  const cachedThemes = normalizeCachedThemes(state.enabledThemes);
  return {
    rounds: 10,
    timerSeconds: 30,
    maxPlayers: 5,
    harsh: false,
    chaos: false,
    timeMoney: false,
    amplified: false,
    wildFire: false,
    partyMayhem: false,
    classicMode: false,
    randomModifiers: false,
    autoAdvance: true,
    enabledThemes: cachedThemes.length ? cachedThemes : [...triviaThemes],
    private: false,
    password: "",
    code
  };
}

function syncRoomControls() {
  state.roomSettings.maxPlayers = getRoomMaxPlayers();
  state.roomSettings.enabledThemes = getEnabledTriviaThemes();
  elements.roomRoundsSlider.value = state.roomSettings.rounds;
  elements.roomRoundsValue.textContent = `${state.roomSettings.rounds}`;
  elements.roomTimerSlider.value = state.roomSettings.timerSeconds;
  elements.roomTimerValue.textContent = `${state.roomSettings.timerSeconds}s`;
  elements.roomPlayerLimitSlider.value = state.roomSettings.maxPlayers;
  elements.roomPlayerLimitValue.textContent = `${state.roomSettings.maxPlayers}`;
  elements.harshModeToggle.checked = state.roomSettings.harsh;
  elements.chaosModeToggle.checked = state.roomSettings.chaos;
  elements.timeMoneyModeToggle.checked = state.roomSettings.timeMoney;
  elements.amplifiedModeToggle.checked = state.roomSettings.amplified;
  elements.wildFireModeToggle.checked = state.roomSettings.wildFire;
  elements.partyMayhemModeToggle.checked = state.roomSettings.partyMayhem;
  elements.randomModeToggle.checked = Boolean(state.roomSettings.randomModifiers);
  elements.classicModeToggle.checked = state.roomSettings.classicMode;
  elements.autoAdvanceToggle.checked = state.roomSettings.autoAdvance !== false;
  elements.privateRoomToggle.checked = state.roomSettings.private;
  syncClassicRoomToggleState();
  elements.roomPasswordInput.value = state.roomSettings.password || "";
  setCollapsed(elements.roomPasswordRow, !state.roomSettings.private);
  renderThemeSummary();
  renderModifierIconLabel(elements.roomVariantLabel);
  renderModifierIconLabel(elements.lobbyRoomVariantLabel);
  elements.roomCodePreview.textContent = state.roomSettings.code;
  elements.startRoomButton.textContent = state.currentRoomStatus === "lobby" ? "Continue" : "Create Room";
  setHidden(elements.roomHostProfile, Boolean(state.joiningRoom));
  syncRoomInviteButtons();
  renderRoomPlayers();
}

function openRoomScreen() {
  stopJoinDirectoryPolling();
  void ensureSupabaseAuthReady({ realtime: true });
  state.roomSessionId += 1;
  state.mode = null;
  state.players = [];
  state.joiningRoom = null;
  state.isSpectator = false;
  state.roomExitLeaveSent = false;
  state.roomMissingSince = 0;
  state.roomClosedNotice = "";
  state.roomGame = null;
  state.roomMatchId = "";
  state.roomRoundResult = null;
  resetRoomPowerSyncClocks();
  state.roomPlayedResetSyncedRound = null;
  state.roomEventRevision = 0;
  clearLocalRoomSubmission();
  state.roomSubmissions = {};
  state.currentOwner = "player";
  state.currentRoomStatus = "draft";
  state.roomParticipants = [];
  state.roomSettings = getDefaultRoomSettings(generateRoomCode());
  state.publishedDraftRoomCode = state.roomSettings.code;
  state.roomChat = [];
  resetChatCooldown();
  rememberHostedRoomSession(state.roomSettings.code);
  setRoomInviteUrlPath(state.roomSettings.code);
  startRoomRealtime(state.roomSettings.code);
  syncRoomControls();
  publishDraftRoom();
  startRoomDirectoryPolling();
  setHidden(elements.modeScreen, true);
  setHidden(elements.joinScreen, true);
  setHidden(elements.gameStage, true);
  setHidden(elements.roomLobbyScreen, true);
  setHidden(elements.roomScreen, false);
  playSound("click");
}

function closeRoomScreen() {
  const returnToLobby = state.currentRoomStatus === "lobby";
  if (state.currentRoomStatus === "draft" && state.publishedDraftRoomCode === state.roomSettings.code) {
    leavePublishedRoom({ keepalive: true });
    clearLocalRoomState();
    stopRoomDirectoryPolling();
    clearRoomInviteUrlPath();
  }
  setHidden(elements.roomScreen, true);
  setHidden(elements.roomLobbyScreen, !returnToLobby);
  setHidden(elements.modeScreen, returnToLobby);
  if (returnToLobby) {
    renderRoomLobby();
  }
  playSound("click");
}

async function rotateDraftRoomCodeAfterPublishConflict(previousCode = state.roomSettings.code, attempt = 0) {
  if (state.currentRoomStatus !== "draft" || state.joiningRoom || !isCurrentHost() || attempt >= 3) {
    return false;
  }
  const oldCode = String(previousCode || state.roomSettings.code || "").trim().toUpperCase();
  const nextCode = generateRoomCode();
  if (!nextCode || nextCode === oldCode) {
    return false;
  }
  clearHostedRoomSession(oldCode);
  stopRoomRealtime();
  state.roomSettings = {
    ...state.roomSettings,
    code: nextCode
  };
  state.publishedDraftRoomCode = nextCode;
  rememberHostedRoomSession(nextCode);
  setRoomInviteUrlPath(nextCode);
  startRoomRealtime(nextCode);
  syncRoomControls();
  return publishDraftRoom(attempt + 1);
}

function publishDraftRoom(attempt = 0) {
  if (!state.roomSettings.code || state.roomSettings.code === "CAI-0000") {
    return;
  }
  const room = buildRoomDirectoryPayload("lobby");
  publishRoomDirectory(room).then(async (serverRoom) => {
    if (serverRoom) {
      mergeHostedRoom(serverRoom);
      if (state.currentRoomStatus === "draft" && state.roomSettings.code === serverRoom.code) {
        state.roomParticipants = normalizeRoomParticipantsList(Array.isArray(serverRoom.participants) ? serverRoom.participants : state.roomParticipants);
        renderRoomPlayers();
      }
      return;
    }
    const lookup = await fetchRoomByCode(room.code);
    if (lookup.status === "found" || lookup.status === "closed") {
      await rotateDraftRoomCodeAfterPublishConflict(room.code, attempt);
    }
  });
}

function leavePublishedRoom(options = {}) {
  const code = state.roomSettings.code;
  if (!code || code === "CAI-0000") {
    return Promise.resolve(null);
  }
  const reason = options.reason || "manual";
  const isHostLeaving = isCurrentHost() && !state.joiningRoom;
  const leavingParticipant = state.roomParticipants.find((entry) => entry.id === state.clientId)
    || getCurrentParticipant({ host: isCurrentHost(), spectator: state.isSpectator });
  const leaveDetails = {
    participantId: state.clientId,
    participantName: leavingParticipant?.name || state.profile.name || "A player",
    participant: leavingParticipant || null,
    reason
  };
  if (isHostLeaving) {
    markRoomLocallyClosed(code);
    removeHostedRoom(code);
    broadcastRealtimeRoomChange("room-closed", code, {
      reason: reason === "page-exit" ? "host-left" : reason
    });
    if (!options.keepalive || reason !== "page-exit") {
      clearHostedRoomSession(code);
    }
    return closeHostedRoomByCode(code, {
      keepalive: Boolean(options.keepalive),
      reason: reason === "page-exit" ? "host-left" : reason
    }).then(async (response) => {
      if (!response || typeof response.json !== "function") {
        return { closed: true, code, reason };
      }
      const result = await response.json().catch(() => ({}));
      return result?.closed ? result : { closed: true, code, reason };
    });
  } else if (options.keepalive) {
    broadcastRealtimeRoomChange("participant-left", code, leaveDetails);
  }
  const payload = JSON.stringify({
    participantId: state.clientId,
    reason
  });
  const url = `/api/rooms/${encodeURIComponent(code)}/leave`;
  if (options.keepalive && navigator.sendBeacon) {
    navigator.sendBeacon(url, new Blob([payload], { type: "application/json" }));
    return Promise.resolve(null);
  }
  return fetchWithTimeout(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: payload,
    keepalive: Boolean(options.keepalive)
  }, roomLeaveFetchTimeoutMs).then(async (response) => {
    const result = await response.json().catch(() => ({}));
    if (result?.closed) {
      broadcastRealtimeRoomChange("room-closed", code, { reason: result.reason || reason });
    } else if (result?.room) {
      broadcastRealtimeRoomChange("participant-left", result.room, {
        ...leaveDetails,
        participantName: result.participant?.name || leaveDetails.participantName,
        participant: result.participant || leaveDetails.participant
      });
    }
    return result;
  }).catch(() => null);
}

function markCurrentRoomParticipantDisconnected(options = {}) {
  const code = String(options.code || state.roomSettings.code || "").trim().toUpperCase();
  if (!code || code === "CAI-0000") {
    return Promise.resolve(null);
  }
  const isHost = Object.hasOwn(options, "host")
    ? Boolean(options.host)
    : isCurrentHost() && !state.joiningRoom;
  const isSpectator = Object.hasOwn(options, "spectator")
    ? Boolean(options.spectator)
    : Boolean(state.isSpectator);
  const participant = getCurrentParticipant({
    host: isHost,
    spectator: isSpectator,
    active: false,
    status: isHost ? "host-disconnected" : isSpectator ? "spectator-disconnected" : "disconnected"
  });
  const payload = JSON.stringify({
    participant,
    compact: true,
    hostParticipantId: isHost ? state.clientId : ""
  });
  broadcastRealtimeRoomChange("participant-disconnected", code, {
    participantId: participant.id,
    participantName: participant.name,
    host: participant.host,
    spectator: participant.spectator,
    status: participant.status,
    participant
  });
  const url = `/api/rooms/${encodeURIComponent(code)}/presence`;
  if (options.keepalive && navigator.sendBeacon) {
    navigator.sendBeacon(url, new Blob([payload], { type: "application/json" }));
    return Promise.resolve(null);
  }
  return fetchWithTimeout(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: payload,
    keepalive: Boolean(options.keepalive)
  }, roomLeaveFetchTimeoutMs).catch(() => null);
}

function clearLocalRoomState(options = {}) {
  if (options.clearHostedSession) {
    clearHostedRoomSession(state.roomSettings.code);
  }
  state.roomSessionId += 1;
  state.mode = null;
  state.currentRoomStatus = "draft";
  state.joiningRoom = null;
  state.isSpectator = false;
  state.roomGame = null;
  state.roomMatchId = "";
  state.roomRoundResult = null;
  resetRoomPowerSyncClocks();
  state.roomPlayedResetSyncedRound = null;
  state.players = [];
  state.roomParticipants = [];
  clearLocalRoomSubmission();
  state.roomSubmissions = {};
  clearSpectatorAnswerDraftState();
  state.spectatorRoundResultPlaybackKey = "";
  state.roomRoundResultPlaybackKey = "";
  state.roomMissingSince = 0;
  state.roomExitLeaveSent = false;
  state.publishedDraftRoomCode = "";
  state.roomEventRevision = 0;
  resetChatCooldown();
  stopRoomHeartbeat();
  stopRoomEventPolling();
  stopRoomRealtime();
  renderSpectatorCountIndicator();
  if (options.resetCode !== false) {
    state.roomSettings.code = "CAI-0000";
  }
}

function shouldSendRoomExitLeave() {
  return !state.roomExitLeaveSent
    && state.roomSettings.code
    && state.roomSettings.code !== "CAI-0000"
    && (isRoomMode() || state.currentRoomStatus === "lobby" || state.currentRoomStatus === "draft");
}

function handleWindowBeforeUnload() {
  flushUserStorageSnapshot();
  flushPendingUserInventoryBeforePageExit();
  if (!shouldSendRoomExitLeave()) {
    return;
  }
  state.roomExitLeaveSent = true;
  markCurrentRoomParticipantDisconnected({ keepalive: true });
}

function handleWindowPageHide() {
  flushUserStorageSnapshot();
  flushPendingUserInventoryBeforePageExit();
  if (!shouldSendRoomExitLeave()) {
    return;
  }
  state.roomExitLeaveSent = true;
  markCurrentRoomParticipantDisconnected({ keepalive: true });
}

function handleCurrentRoomClosed(reason = "Room closed.") {
  if (!(isRoomMode() || state.currentRoomStatus === "lobby" || state.currentRoomStatus === "draft")) {
    return;
  }
  if (state.roomClosedNotice) {
    return;
  }
  const closedCode = state.roomSettings.code;
  markRoomLocallyClosed(closedCode);
  removeHostedRoom(closedCode);
  state.matchEnded = true;
  cancelActiveMatchWork({ stopRoomSync: true });
  state.roomClosedNotice = reason;
  clearLocalRoomState({ clearHostedSession: true });
  clearRoomInviteUrlPath();
  addSystemChat(reason, { private: true, sync: false });
  setHidden(elements.gameStage, true);
  setHidden(elements.roomChat, true);
  setHidden(elements.roomLobbyScreen, true);
  setHidden(elements.roomScreen, true);
  setHidden(elements.joinScreen, true);
  elements.gameStage.classList.remove("room-active");
  setHidden(elements.modeScreen, false);
  showAppConfirm({
    eyebrow: "Room closed",
    title: "Room closed",
    copy: reason,
    confirmLabel: "OK",
    cancelLabel: "Close",
    danger: false
  });
}

function setJoinInviteStatus(message = "", tone = "") {
  if (!elements.joinInviteStatus) {
    return;
  }
  elements.joinInviteStatus.textContent = message;
  elements.joinInviteStatus.dataset.tone = tone || "";
  setHidden(elements.joinInviteStatus, !message);
}

function setJoinInviteMode(active, options = {}) {
  const code = normalizeJoinRoomCode(options.code || state.roomInvite.code || "");
  state.roomInvite = {
    active: Boolean(active),
    code: active ? code : "",
    checked: Boolean(options.checked)
  };
  if (elements.joinScreen) {
    if (active) {
      elements.joinScreen.dataset.invite = "true";
    } else {
      delete elements.joinScreen.dataset.invite;
    }
  }
  if (elements.joinEyebrow) {
    elements.joinEyebrow.textContent = active ? "Room invite" : "Hosted rooms";
  }
  if (elements.joinTitle) {
    elements.joinTitle.textContent = active ? "JOIN ROOM" : "JOIN GAME";
  }
  if (elements.joinRoomCodeInput) {
    elements.joinRoomCodeInput.value = active && code ? getRoomShortCode(code) || code : elements.joinRoomCodeInput.value;
    elements.joinRoomCodeInput.readOnly = Boolean(active && code);
  }
  if (elements.joinCodeForm) {
    const submitButton = elements.joinCodeForm.querySelector("button[type='submit']");
    if (submitButton) {
      submitButton.textContent = active ? "Join Room" : "Join Code";
    }
  }
  if (!active) {
    setJoinInviteStatus("");
    if (elements.joinRoomCodeInput) {
      elements.joinRoomCodeInput.readOnly = false;
    }
  }
}

function focusInvitePasswordField() {
  window.setTimeout(() => {
    elements.joinRoomPasswordInput?.focus();
    elements.joinRoomPasswordInput?.select?.();
  }, 0);
}

function openJoinScreen(options = {}) {
  void ensureSupabaseAuthReady({ realtime: true });
  if (options.inviteCode) {
    setJoinInviteMode(true, { code: options.inviteCode, checked: options.checked });
  } else {
    setJoinInviteMode(false);
  }
  if (!state.roomInvite.active) {
    renderHostedRooms();
    startJoinDirectoryPolling();
  } else {
    stopJoinDirectoryPolling();
  }
  setHidden(elements.modeScreen, true);
  setHidden(elements.roomScreen, true);
  setHidden(elements.roomLobbyScreen, true);
  setHidden(elements.gameStage, true);
  setHidden(elements.joinScreen, false);
  if (!state.roomInvite.active) {
    refreshHostedRoomsAndRender({ force: true });
  }
  if (options.playSound !== false) {
    playSound("click");
  }
}

async function refreshJoinRooms() {
  if (!elements.refreshJoinRoomsButton) {
    return;
  }
  const previousLabel = elements.refreshJoinRoomsButton.textContent;
  elements.refreshJoinRoomsButton.disabled = true;
  elements.refreshJoinRoomsButton.textContent = "Refreshing...";
  try {
    await refreshHostedRoomsAndRender({ force: true });
  } finally {
    elements.refreshJoinRoomsButton.textContent = previousLabel || "Refresh";
    elements.refreshJoinRoomsButton.disabled = false;
  }
  playSound("click");
}

function closeJoinScreen() {
  stopJoinDirectoryPolling();
  if (state.roomInvite.active) {
    clearRoomInviteUrlPath();
  }
  setJoinInviteMode(false);
  setHidden(elements.joinScreen, true);
  setHidden(elements.modeScreen, false);
  playSound("click");
}

function startJoinDirectoryPolling() {
  stopJoinDirectoryPolling();
  if (state.supabaseEnabled && state.realtimeLobbyReady) {
    return;
  }
  const intervalMs = state.supabaseEnabled ? 6000 : 1800;
  state.joinDirectoryPollId = window.setInterval(async () => {
    if (elements.joinScreen.classList.contains("hidden")) {
      stopJoinDirectoryPolling();
      return;
    }
    await refreshHostedRoomsAndRender();
  }, intervalMs);
}

function stopJoinDirectoryPolling() {
  if (state.joinDirectoryPollId) {
    window.clearInterval(state.joinDirectoryPollId);
    state.joinDirectoryPollId = null;
  }
}

function scheduleRoomSettingsPublish(kind = state.currentRoomStatus, delay = 300) {
  if (!state.roomSettings.code || state.roomSettings.code === "CAI-0000") {
    return;
  }
  state.roomSettingsPublishKind = kind;
  if (state.roomSettingsPublishTimerId) {
    window.clearTimeout(state.roomSettingsPublishTimerId);
  }
  state.roomSettingsPublishTimerId = window.setTimeout(() => {
    const publishKind = state.roomSettingsPublishKind;
    state.roomSettingsPublishTimerId = null;
    state.roomSettingsPublishKind = "";
    if (publishKind === "lobby" && state.currentRoomStatus === "lobby") {
      publishRoomSettings("lobby");
    } else if (publishKind === "draft" && state.currentRoomStatus === "draft") {
      publishRoomSettings("draft");
    }
  }, delay);
}

function publishCurrentRoomSettingsSoon(options = {}) {
  const editSeq = markRoomSettingsLocallyChanged();
  const code = state.roomSettings.code;
  const updatedAt = state.roomSettingsLocalUpdatedAtByCode[code] || Date.now();
  const serverStatus = state.currentRoomStatus === "draft" ? "lobby" : state.currentRoomStatus;
  const immediate = options.immediate === true;
  if (immediate && state.roomSettingsPublishTimerId) {
    window.clearTimeout(state.roomSettingsPublishTimerId);
    state.roomSettingsPublishTimerId = null;
    state.roomSettingsPublishKind = "";
  }
  const hostedRoom = state.hostedRooms.find((room) => room.code === code);
  if (hostedRoom) {
    hostedRoom.settings = { ...(hostedRoom.settings || {}), ...state.roomSettings, code };
    hostedRoom.status = serverStatus || hostedRoom.status;
    hostedRoom.updatedAt = updatedAt;
  }
  broadcastRealtimeRoomChange("room-settings", code, {
    status: serverStatus,
    revision: Number(state.roomSettingsRevisionByCode[code]) || state.roomEventRevision || 0,
    updatedAt,
    settingsEditSeq: editSeq,
    settings: { ...state.roomSettings, code }
  });
  if (state.currentRoomStatus === "lobby") {
    if (immediate) {
      publishRoomSettings("lobby");
    } else {
      scheduleRoomSettingsPublish("lobby");
    }
    renderRoomLobby();
  } else if (state.currentRoomStatus === "draft") {
    if (immediate) {
      publishRoomSettings("draft");
    } else {
      scheduleRoomSettingsPublish("draft");
    }
  }
  scheduleUserStorageSnapshot();
}

function updateRoomRounds(value) {
  state.roomSettings.rounds = clampNumber(value, 1, 10, 10);
  elements.roomRoundsValue.textContent = `${state.roomSettings.rounds}`;
  publishCurrentRoomSettingsSoon();
}

function updateRoomTimer(value) {
  state.roomSettings.timerSeconds = clampNumber(value, 10, 60, 30);
  elements.roomTimerValue.textContent = `${state.roomSettings.timerSeconds}s`;
  publishCurrentRoomSettingsSoon();
}

function updateRoomPlayerLimit(value) {
  state.roomSettings.maxPlayers = clampNumber(value, 2, 10, 5);
  elements.roomPlayerLimitSlider.value = state.roomSettings.maxPlayers;
  elements.roomPlayerLimitValue.textContent = `${state.roomSettings.maxPlayers}`;
  renderRoomPlayers();
  publishCurrentRoomSettingsSoon();
}

function syncClassicRoomToggleState() {
  [
    elements.harshModeToggle,
    elements.chaosModeToggle,
    elements.timeMoneyModeToggle,
    elements.amplifiedModeToggle,
    elements.wildFireModeToggle,
    elements.partyMayhemModeToggle
  ].forEach((toggle) => {
    if (toggle) {
      toggle.disabled = false;
    }
  });
  if (elements.randomModeToggle) {
    elements.randomModeToggle.disabled = false;
  }
}

function getRoomModifierToggleElements() {
  return [
    elements.randomModeToggle,
    elements.harshModeToggle,
    elements.chaosModeToggle,
    elements.timeMoneyModeToggle,
    elements.amplifiedModeToggle,
    elements.wildFireModeToggle,
    elements.partyMayhemModeToggle
  ].filter(Boolean);
}

function clearRoomModifierToggles() {
  getRoomModifierToggleElements().forEach((toggle) => {
    toggle.checked = false;
  });
}

function getRoomVariantSourceElement(options = {}) {
  if (options && options.target && typeof options.target === "object") {
    return options.target;
  }
  return options?.sourceElement || null;
}

function applyRoomVariantControlsToSettings(options = {}) {
  const sourceElement = getRoomVariantSourceElement(options);
  const modifierToggles = getRoomModifierToggleElements();
  if (
    sourceElement
    && sourceElement !== elements.classicModeToggle
    && modifierToggles.includes(sourceElement)
    && sourceElement.checked
    && elements.classicModeToggle.checked
  ) {
    elements.classicModeToggle.checked = false;
  }
  if (elements.classicModeToggle.checked) {
    clearRoomModifierToggles();
  }
  state.roomSettings.harsh = elements.harshModeToggle.checked;
  state.roomSettings.chaos = elements.chaosModeToggle.checked;
  state.roomSettings.timeMoney = elements.timeMoneyModeToggle.checked;
  state.roomSettings.amplified = elements.amplifiedModeToggle.checked;
  state.roomSettings.wildFire = elements.wildFireModeToggle.checked;
  state.roomSettings.partyMayhem = elements.partyMayhemModeToggle.checked;
  state.roomSettings.classicMode = elements.classicModeToggle.checked;
  state.roomSettings.randomModifiers = elements.randomModeToggle.checked;
  state.roomSettings.autoAdvance = elements.autoAdvanceToggle.checked;
  state.roomSettings.private = elements.privateRoomToggle.checked;
  state.roomSettings.password = cleanChatInput(elements.roomPasswordInput.value);
  setCollapsed(elements.roomPasswordRow, !state.roomSettings.private);
  scheduleRoomPanelHeightSync();
  syncClassicRoomToggleState();
  renderModifierIconLabel(elements.roomVariantLabel);
  renderModifierIconLabel(elements.lobbyRoomVariantLabel);
}

function updateRoomVariants(options = {}) {
  applyRoomVariantControlsToSettings(options);
  if (options.publish === false) {
    return;
  }
  publishCurrentRoomSettingsSoon({ immediate: options.immediate === true });
}

function applyRandomRoomModifiersForMatch() {
  if (!state.roomSettings.randomModifiers || state.roomSettings.classicMode) {
    return;
  }
  const rolled = rollMatchModifiers("local");
  state.roomSettings.harsh = state.roomSettings.harsh || rolled.harsh;
  state.roomSettings.chaos = state.roomSettings.chaos || rolled.chaos;
  state.roomSettings.timeMoney = state.roomSettings.timeMoney || rolled.timeMoney;
  state.roomSettings.amplified = state.roomSettings.amplified || rolled.amplified;
  state.roomSettings.wildFire = state.roomSettings.wildFire || rolled.wildFire;
  state.roomSettings.partyMayhem = state.roomSettings.partyMayhem || rolled.partyMayhem;
  state.roomSettings.randomModifiers = false;
  syncRoomControls();
}

async function handleClassicModeToggle() {
  if (!elements.classicModeToggle.checked) {
    updateRoomVariants();
    return;
  }
  const previousSettings = { ...state.roomSettings };
  const confirmed = await showAppConfirm({
    eyebrow: "Classic mode",
    title: "Disable modifiers and power-ups?",
    copy: "Classic mode is multiplayer only. It turns off every other modifier, prevents table events, and disables all power-ups for this room.",
    confirmLabel: "Enable Classic",
    cancelLabel: "Cancel",
    danger: false
  });
  if (!confirmed) {
    state.roomSettings = previousSettings;
    syncRoomControls();
    return;
  }
  elements.classicModeToggle.checked = true;
  clearRoomModifierToggles();
  updateRoomVariants({ immediate: true, sourceElement: elements.classicModeToggle });
}

function buildRoomDirectoryPayload(status = "lobby") {
  const participants = getRoomParticipantsFromPlayers(status);
  const existing = state.hostedRooms.find((room) => room.code === state.roomSettings.code);
  const inProgressGame = status === "in-progress"
    ? state.roomGame || (state.roomMatchId ? {
      matchId: state.roomMatchId,
      status: "starting",
      round: Number(state.round) || 1,
      setup: null,
      matchSettings: getRoomMatchSettingsPayload(state.roomSettings),
      powerState: null,
      updatedAt: Date.now()
    } : null)
    : null;
  const hostSource = (!state.joiningRoom && isCurrentHost())
    ? {
      id: state.clientId,
      profileUserId: getRoomParticipantProfileUserId(),
      name: state.profile.name || "Host",
      avatar: getRoomSyncAvatar(state.profile.avatar),
      equippedTitleId: state.profile.equippedTitleId || "",
      specialBadges: getRoomSyncSpecialBadges(),
      cardCustomization: getRoomSyncCardCustomization(state.profile.cardCustomization)
    }
    : (existing?.host || state.joiningRoom?.host || participants.find((participant) => participant.host) || {});
  return {
    code: state.roomSettings.code,
    status,
    settings: { ...state.roomSettings },
    host: {
      id: hostSource.id || state.clientId,
      profileUserId: hostSource.profileUserId || getRoomParticipantProfileUserId(),
      name: hostSource.name || "Host",
      avatar: getRoomSyncAvatar(hostSource.avatar),
      equippedTitleId: hostSource.equippedTitleId || "",
      specialBadges: getRoomSyncSpecialBadges(hostSource.specialBadges || []),
      cardCustomization: getRoomSyncCardCustomization(hostSource.cardCustomization)
    },
    participants,
    activePlayers: participants.filter((participant) => participant.active && !participant.spectator).length,
    spectators: participants.filter((participant) => participant.active && participant.spectator).length,
    banned: [...getRoomBanList()],
    game: inProgressGame
  };
}

async function publishRoomDirectory(room) {
  try {
    const response = await fetch("/api/rooms", {
      method: "PUT",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ room })
    });
    if (!response.ok) {
      state.roomDirectoryOnline = false;
      const errorPayload = await response.json().catch(() => ({}));
      console.warn("Room directory update failed:", response.status, errorPayload.error || errorPayload);
      return null;
    }
    const data = await response.json();
    state.roomDirectoryOnline = true;
    if (data.room) {
      broadcastRealtimeRoomChange("room-updated", data.room);
    }
    return data.room || room;
  } catch {
    state.roomDirectoryOnline = false;
    console.warn("Room directory update failed.");
    return null;
  }
}

async function publishRoomSettings(status = state.currentRoomStatus) {
  const code = state.roomSettings.code;
  if (!code || code === "CAI-0000") {
    return null;
  }
  const publishSeq = getRoomSettingsEditSeq(code);
  const settingsSnapshot = { ...state.roomSettings };
  const serverStatus = status === "draft" ? "lobby" : status;
  const host = (!state.joiningRoom && isCurrentHost())
    ? {
      id: state.clientId,
      name: state.profile.name || "Host",
      avatar: getRoomSyncAvatar(state.profile.avatar),
      equippedTitleId: state.profile.equippedTitleId || "",
      specialBadges: getRoomSyncSpecialBadges(),
      cardCustomization: getRoomSyncCardCustomization(state.profile.cardCustomization)
    }
    : null;
  const hostedRoom = state.hostedRooms.find((room) => room.code === code);
  if (hostedRoom) {
    hostedRoom.settings = { ...settingsSnapshot };
    hostedRoom.status = serverStatus;
    if (host) {
      hostedRoom.host = { ...(hostedRoom.host || {}), ...host };
    }
    hostedRoom.updatedAt = Date.now();
  }
  try {
    const response = await fetchWithTimeout(`/api/rooms/${encodeURIComponent(code)}/settings`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        status: serverStatus,
        settings: settingsSnapshot,
        settingsEditSeq: publishSeq,
        hostParticipantId: state.clientId,
        host
      })
    }, roomPresenceFetchTimeoutMs);
    if (!response.ok) {
      state.roomDirectoryOnline = false;
      if (response.status === 404 && !state.joiningRoom && isCurrentHost()) {
        return publishRoomDirectory(buildRoomDirectoryPayload(serverStatus));
      }
      return null;
    }
    const data = await response.json();
    state.roomDirectoryOnline = true;
    updateRoomEventRevision(data.revision);
    const latestSeq = getRoomSettingsEditSeq(code);
    if (state.roomSettings.code === code && latestSeq === publishSeq) {
      applyRealtimeRoomSettings({ ...data, code, localSettingsEcho: true, settingsEditSeq: publishSeq });
      broadcastRealtimeRoomChange("room-settings", code, { ...data, settingsEditSeq: publishSeq });
    }
    return data;
  } catch {
    state.roomDirectoryOnline = false;
    return null;
  }
}

function upsertHostedRoom(status = "lobby") {
  const existing = state.hostedRooms.find((room) => room.code === state.roomSettings.code);
  const room = buildRoomDirectoryPayload(status);
  if (!state.joiningRoom && isCurrentHost() && status !== "complete") {
    rememberHostedRoomSession(room.code);
  }
  if (existing) {
    Object.assign(existing, room);
  } else {
    state.hostedRooms.unshift(room);
  }
  publishRoomDirectory(room).then((serverRoom) => {
    if (serverRoom && serverRoom.code === room.code) {
      mergeHostedRoom(serverRoom);
      if (state.roomSettings.code === serverRoom.code) {
        applyRoomDirectoryRoom(serverRoom);
      }
    }
  });
  return room;
}

function mergeHostedRoom(room) {
  if (isRoomLocallyClosed(room?.code)) {
    return;
  }
  const normalizedRoom = {
    ...room,
    participants: normalizeRoomParticipantsList(room?.participants)
  };
  const existing = state.hostedRooms.find((entry) => entry.code === normalizedRoom.code);
  if (existing) {
    const settings = mergeRoomSettingsFresh(existing.settings || {}, normalizedRoom.settings || {}, normalizedRoom);
    Object.assign(existing, normalizedRoom, { settings });
  } else {
    const settings = mergeRoomSettingsFresh({}, normalizedRoom.settings || {}, normalizedRoom);
    state.hostedRooms.unshift({ ...normalizedRoom, settings });
  }
}

function fetchWithTimeout(url, options = {}, timeoutMs = roomDirectoryFetchTimeoutMs) {
  if (!window.AbortController || options.keepalive) {
    return fetch(url, options);
  }
  const controller = new AbortController();
  const timeoutId = window.setTimeout(() => controller.abort(), timeoutMs);
  return fetch(url, {
    ...options,
    signal: controller.signal
  }).finally(() => {
    window.clearTimeout(timeoutId);
  });
}

async function refreshHostedRooms(options = {}) {
  if (state.hostedRoomsRefreshPromise && !options.force) {
    return state.hostedRoomsRefreshPromise;
  }
  state.hostedRoomsRefreshPromise = (async () => {
    try {
      pruneLocallyClosedRooms();
      const response = await fetchWithTimeout("/api/rooms", { cache: "no-store" }, roomDirectoryFetchTimeoutMs);
      if (!response.ok) {
        state.roomDirectoryOnline = false;
        return false;
      }
      const data = await response.json();
      state.roomDirectoryOnline = true;
      state.hostedRooms = (Array.isArray(data.rooms) ? data.rooms : [])
        .filter((room) => !isRoomLocallyClosed(room?.code))
        .map((room) => {
          const existing = state.hostedRooms.find((entry) => entry.code === room.code) || {};
          return {
            ...room,
            settings: mergeRoomSettingsFresh(existing.settings || {}, room.settings || {}, room)
          };
        });
      return true;
    } catch {
      state.roomDirectoryOnline = false;
      // Keep the local fallback list when the server is unavailable.
      return false;
    } finally {
      state.hostedRoomsRefreshPromise = null;
    }
  })();
  return state.hostedRoomsRefreshPromise;
}

async function refreshHostedRoomsAndRender(options = {}) {
  const ok = await refreshHostedRooms(options);
  if (!elements.joinScreen.classList.contains("hidden")) {
    renderHostedRooms();
  }
  return ok;
}

async function fetchRoomByCode(code = state.roomSettings.code) {
  if (!code || code === "CAI-0000") {
    return { status: "missing", room: null };
  }
  if (isRoomLocallyClosed(code)) {
    return { status: "closed", room: null };
  }
  try {
    const response = await fetchWithTimeout(`/api/rooms/${encodeURIComponent(code)}`, { cache: "no-store" }, roomLookupFetchTimeoutMs);
    if (response.status === 410) {
      const data = await response.json().catch(() => ({}));
      state.roomDirectoryOnline = true;
      return { status: "closed", room: null, close: data.close || null };
    }
    if (response.status === 404) {
      state.roomDirectoryOnline = true;
      return { status: "missing", room: null };
    }
    if (!response.ok) {
      state.roomDirectoryOnline = false;
      return { status: "unknown", room: null };
    }
    const data = await response.json();
    state.roomDirectoryOnline = true;
    return { status: "found", room: data.room || null };
  } catch {
    state.roomDirectoryOnline = false;
    return { status: "unknown", room: null };
  }
}

async function updateRoomPresence(room, options = {}) {
  try {
    const participant = getCurrentParticipant({
      host: Object.hasOwn(options, "host") ? Boolean(options.host) : isCurrentHost() && !state.joiningRoom,
      spectator: Boolean(options.spectator),
      active: options.active !== false,
      status: options.status || (options.spectator ? "spectating" : "joined"),
      answer: options.answer || "",
      submittedRound: options.submittedRound || 0,
      submissionMatchId: options.submissionMatchId || (Number(options.submittedRound) > 0 ? getCurrentRoomMatchId() : ""),
      remainingTime: options.remainingTime || 0
    });
    if (!Object.hasOwn(options, "answer")) {
      delete participant.answer;
    }
    if (!Object.hasOwn(options, "submittedRound")) {
      delete participant.submittedRound;
      delete participant.submissionMatchId;
    }
    if (!Object.hasOwn(options, "remainingTime")) {
      delete participant.remainingTime;
    }
    const response = await fetchWithTimeout(`/api/rooms/${encodeURIComponent(room.code)}/presence`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        participant,
        compact: options.compactResponse !== false,
        ...(Object.hasOwn(options, "roomPassword") ? { password: options.roomPassword } : {})
      })
    }, roomPresenceFetchTimeoutMs);
    if (!response.ok) {
      return null;
    }
    const data = await response.json();
    if (data.participant) {
      applyRoomParticipantDelta(data.participant, data);
      if (!options.skipRealtimeBroadcast) {
        const eventType = String(data.eventType || "participant_updated").replaceAll("_", "-");
        broadcastRealtimeRoomChange(eventType || "participant-updated", state.roomSettings.code, {
          status: data.status || "",
          revision: data.revision || 0,
          updatedAt: data.updatedAt || Date.now(),
          participant: data.participant
        });
      }
    } else if (data.room) {
      mergeHostedRoom(data.room);
      applyRoomDirectoryRoom(data.room);
      if (!options.skipRealtimeBroadcast) {
        broadcastRealtimeRoomChange("participant-updated", data.room);
      }
    }
    return data.room || {
      ...room,
      status: data.status || room.status,
      revision: Number(data.revision) || Number(room.revision) || 0,
      updatedAt: Number(data.updatedAt) || Date.now(),
      participants: state.roomParticipants
    };
  } catch {
    return null;
  }
}

async function publishRoomParticipantDelta(participant, options = {}) {
  const code = String(options.code || state.roomSettings.code || "").trim().toUpperCase();
  if (!code || code === "CAI-0000" || !participant?.id) {
    return null;
  }
  try {
    const response = await fetchWithTimeout(`/api/rooms/${encodeURIComponent(code)}/presence`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        participant,
        compact: true,
        hostParticipantId: state.clientId,
        ...(Object.hasOwn(options, "roomPassword") ? { password: options.roomPassword } : {})
      })
    }, roomPresenceFetchTimeoutMs);
    if (!response.ok) {
      state.roomDirectoryOnline = false;
      return null;
    }
    const data = await response.json().catch(() => ({}));
    state.roomDirectoryOnline = true;
    if (data.participant) {
      applyRoomParticipantDelta(data.participant, {
        code,
        status: data.status || "",
        revision: data.revision || 0,
        updatedAt: data.updatedAt || Date.now()
      });
      if (!options.skipRealtimeBroadcast) {
        const eventType = String(data.eventType || "participant_updated").replaceAll("_", "-");
        broadcastRealtimeRoomChange(eventType || "participant-updated", code, {
          status: data.status || "",
          revision: data.revision || 0,
          updatedAt: data.updatedAt || Date.now(),
          participant: data.participant
        });
      }
    }
    return data;
  } catch {
    state.roomDirectoryOnline = false;
    return null;
  }
}

function normalizeRoomParticipantDelta(participant = {}) {
  const source = participant && typeof participant === "object" ? participant : {};
  const id = String(source.id || "").slice(0, 80);
  if (!id) {
    return null;
  }
  return {
    id,
    profileUserId: String(source.profileUserId || source.userId || `participant:${id}`).slice(0, 140),
    connectionId: String(source.connectionId || "").slice(0, 120),
    name: String(source.name || "Guest").slice(0, 32),
    avatar: getRoomSyncAvatar(source.avatar),
    equippedTitleId: String(source.equippedTitleId || "").slice(0, 80),
    specialBadges: getRoomSyncSpecialBadges(source.specialBadges || []),
    cardCustomization: getRoomSyncCardCustomization(source.cardCustomization),
    host: Boolean(source.host),
    spectator: Boolean(source.spectator),
    bot: Boolean(source.bot),
    active: source.active !== false,
    muted: Boolean(source.muted),
    status: String(source.status || (source.host ? "host" : source.spectator ? "spectating" : "joined")).slice(0, 32),
    answer: cleanInput(source.answer || ""),
    submittedRound: Number(source.submittedRound) || 0,
    submissionMatchId: String(source.submissionMatchId || "").trim(),
    remainingTime: Math.max(0, Number(source.remainingTime) || 0),
    disconnectedAt: Math.max(0, Number(source.disconnectedAt) || 0),
    lastConnectedAt: Math.max(0, Number(source.lastConnectedAt) || 0)
  };
}

function normalizeRoomParticipantsList(participants = []) {
  const byId = new Map();
  (Array.isArray(participants) ? participants : []).forEach((participant) => {
    const normalized = normalizeRoomParticipantDelta(participant);
    if (!normalized) {
      return;
    }
    const previous = byId.get(normalized.id) || {};
    byId.set(normalized.id, {
      ...previous,
      ...normalized,
      host: Boolean(previous.host || normalized.host),
      bot: Boolean(previous.bot || normalized.bot),
      active: normalized.active !== false,
      spectator: Boolean(normalized.spectator),
      status: previous.host || normalized.host
        ? "host"
        : normalized.status || previous.status || (normalized.bot ? "bot" : normalized.spectator ? "spectating" : "joined")
    });
  });

  const merged = [...byId.values()];
  const activeHosts = merged.filter((participant) => participant.active !== false && participant.host && !participant.spectator);
  let staleHostIds = new Set();
  if (activeHosts.length > 1) {
    const preferredHost = activeHosts.find((participant) => participant.id === state.clientId) || activeHosts.at(-1);
    staleHostIds = new Set(activeHosts.filter((participant) => participant.id !== preferredHost.id).map((participant) => participant.id));
  }

  const maxEntries = Math.max(getRoomMaxPlayers() + 10, 12);
  return merged.filter((participant) => !staleHostIds.has(participant.id)).slice(-maxEntries);
}

function applyRoomParticipantDelta(participant, payload = {}) {
  const normalized = normalizeRoomParticipantDelta(participant);
  if (!normalized) {
    return false;
  }
  const code = String(payload.code || state.roomSettings.code || "").trim().toUpperCase();
  if (code && code !== state.roomSettings.code) {
    return false;
  }
  const existingIndex = state.roomParticipants.findIndex((entry) => entry.id === normalized.id);
  if (existingIndex >= 0) {
    state.roomParticipants[existingIndex] = {
      ...state.roomParticipants[existingIndex],
      ...normalized
    };
  } else {
    state.roomParticipants.push(normalized);
  }
  state.roomParticipants = normalizeRoomParticipantsList(state.roomParticipants);
  applyLocalRoomSubmission();
  if (state.joiningRoom) {
    state.joiningRoom = {
      ...state.joiningRoom,
      participants: [...state.roomParticipants],
      updatedAt: Number(payload.updatedAt) || Date.now(),
      revision: Number(payload.revision) || state.joiningRoom.revision || 0
    };
  }
  const hostedRoom = state.hostedRooms.find((entry) => entry.code === state.roomSettings.code);
  if (hostedRoom) {
    hostedRoom.participants = [...state.roomParticipants];
    hostedRoom.activePlayers = state.roomParticipants.filter((entry) => entry.active && !entry.spectator).length;
    hostedRoom.spectators = state.roomParticipants.filter((entry) => entry.active && entry.spectator).length;
    hostedRoom.updatedAt = Number(payload.updatedAt) || hostedRoom.updatedAt || Date.now();
    hostedRoom.revision = Number(payload.revision) || hostedRoom.revision || 0;
  }
  if (state.currentRoomStatus === "lobby" || !isRoomMode()) {
    setPlayersForMode("room");
  } else {
    const participantIndex = state.roomParticipants.findIndex((entry) => entry.id === normalized.id);
    const owner = getRoomOwnerForParticipant(normalized, participantIndex);
    const player = state.players.find((entry) => entry.participantId === normalized.id)
      || state.players.find((entry) => entry.owner === owner);
    if (player) {
      player.label = normalized.name;
      player.avatar = normalized.avatar;
      player.equippedTitleId = normalized.equippedTitleId;
      player.specialBadges = normalizeSpecialBadges(normalized.specialBadges);
      player.cardCustomization = normalized.cardCustomization;
      player.connectionStatus = normalized.status;
      player.muted = normalized.muted;
      player.active = normalized.active;
      player.spectator = normalized.spectator;
    }
  }
  syncRoomSubmissionsFromParticipants();
  renderRoomPlayers();
  renderRoomChat();
  renderSubmissionStatus();
  renderSpectatorAnswerCards();
  renderSpectatorCountIndicator();
  if (normalized.spectator && normalized.active !== false) {
    broadcastSpectatorAnswerDraft(elements.answerInput?.value || "");
  }
  if (!elements.roomLobbyScreen.classList.contains("hidden")) {
    renderRoomLobby();
  }
  updateRoomEventRevision(payload.revision);
  if (state.currentRoomStatus === "draft" && !state.joiningRoom && isCurrentHost()) {
    scheduleRoomSettingsPublish("draft", 120);
  }
  return true;
}

function applyRoomParticipantConnectionDelta(payload = {}) {
  const participant = payload.participant || {};
  const normalized = normalizeRoomParticipantDelta(participant);
  if (!normalized) {
    return false;
  }
  const eventType = String(payload.eventType || "").replaceAll("_", "-");
  const applied = applyRoomParticipantDelta(normalized, payload);
  if (!applied) {
    return false;
  }
  const name = String(payload.participantName || normalized.name || "A player").trim();
  if (normalized.id !== state.clientId) {
    if (eventType === "participant-disconnected") {
      addSystemChat(
        normalized.host
          ? "Waiting for host to reconnect. The room will close if the host does not return within 1 minute."
          : `${name} disconnected. Waiting for them to reconnect.`,
        { sync: false }
      );
    } else if (eventType === "participant-reconnected") {
      addSystemChat(normalized.host ? "Host rejoined." : `${name} reconnected.`, { sync: false });
    }
  }
  renderRoomPlayers();
  renderRoomChat();
  renderScore();
  renderSubmissionStatus();
  renderSpectatorCountIndicator();
  return true;
}

function applyRoomDirectoryRoom(room) {
  if (!room || room.code !== state.roomSettings.code) {
    return;
  }
  updateRoomEventRevision(room.revision);
  state.roomSettings = mergeRoomSettingsFresh(state.roomSettings, room.settings || {}, room);
  syncRoomMatchStateFromSettings(state.roomSettings);
  state.roomParticipants = normalizeRoomParticipantsList(room.participants);
  syncRoomPlayersFromParticipants({ preserveMatchStats: state.currentRoomStatus === "in-progress" });
  applyLocalRoomSubmission();
  if (Array.isArray(room.chat)) {
    mergeRoomChatMessages(room.chat);
  }
  if (room.status === "lobby") {
    setCurrentRoomMatchId("");
  }
  const incomingGame = room.game && typeof room.game === "object" ? room.game : null;
  const shouldAcceptIncomingGame = !incomingGame
    || !getCurrentRoomMatchId()
    || !incomingGame.matchId
    || incomingGame.matchId === getCurrentRoomMatchId()
    || canAdoptIncomingRoomGame(incomingGame, room);
  state.roomGame = shouldAcceptIncomingGame ? incomingGame : state.roomGame;
  if (state.roomGame?.matchId) {
    setCurrentRoomMatchId(state.roomGame.matchId);
  }
  applyRoomGameMatchSettings(state.roomGame, room);
  if (state.roomGame?.roundResult) {
    applyRealtimeRoomRoundResult({
      code: room.code,
      revision: room.revision,
      updatedAt: room.updatedAt,
      round: state.roomGame.round,
      roundResult: state.roomGame.roundResult,
      game: state.roomGame
    });
  }
  applyRoomGamePowerState(state.roomGame);
  state.joiningRoom = state.joiningRoom ? room : state.joiningRoom;
  syncRoomSubmissionsFromParticipants();
  renderSpectatorAnswerCards();
  renderSpectatorCountIndicator();
}

function syncRoomSubmissionsFromParticipants() {
  if (!isRoomMode() || !state.roomParticipants.length || !state.round) {
    applyLocalRoomSubmission();
    return;
  }
  state.roomParticipants.forEach((participant, index) => {
    if (
      !participant.active
      || participant.spectator
      || Number(participant.submittedRound) !== Number(state.round)
      || !participantSubmissionMatchesCurrentMatch(participant)
    ) {
      return;
    }
    const player = state.players.find((entry) => entry.participantId === participant.id)
      || state.players.find((entry) => entry.owner === getRoomOwnerForParticipant(participant, index));
    const owner = player?.owner || getRoomOwnerForParticipant(participant, index);
    state.roomSubmissions[owner] = true;
    if (participant.answer) {
      lockRoundAnswer(owner, participant.answer);
      if (owner === "player") {
        state.localAnswers.playerOne = participant.answer;
      }
      if (owner === "opponent") {
        state.localAnswers.playerTwo = participant.answer;
      }
    }
    if (Number.isFinite(Number(participant.remainingTime))) {
      state.answerRemainingTimes[owner] = Math.max(0, Number(participant.remainingTime));
    }
    if (player && player.active && !player.muted) {
      player.connectionStatus = "submitted";
    }
  });
  applyLocalRoomSubmission();
}

function getSyncedRoomSetupForRound(round = state.round) {
  const game = state.roomGame || state.joiningRoom?.game || null;
  if (!game || game.status === "ended" || Number(game.round) !== Number(round) || !game.setup) {
    return null;
  }
  if (!canAdoptIncomingRoomGame(game, state.joiningRoom, round)) {
    return null;
  }
  if (game.matchId) {
    setCurrentRoomMatchId(game.matchId);
  }
  try {
    return normalizeSetupPayload(game.setup);
  } catch {
    return null;
  }
}

function publishRoomRoundSetup(setup) {
  if (!isRoomMode() || !isCurrentHost() || state.joiningRoom || !setup) {
    return;
  }
  const syncedSetup = normalizeSetupPayload(setup);
  const matchId = setCurrentRoomMatchId(getCurrentRoomMatchId() || createRoomMatchId());
  state.roomGame = {
    matchId,
    status: "playing",
    round: state.round,
    setup: syncedSetup,
    matchSettings: getRoomMatchSettingsPayload(state.roomSettings),
    powerState: getRoomPowerStatePayload(),
    updatedAt: Date.now()
  };
  broadcastRealtimeRoomChange("round-started", state.roomSettings.code, {
    status: "in-progress",
    matchId,
    revision: state.roomEventRevision || 0,
    updatedAt: state.roomGame.updatedAt,
    game: state.roomGame
  });
  fetch(`/api/rooms/${encodeURIComponent(state.roomSettings.code)}/game`, {
    method: "PUT",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ game: state.roomGame })
  }).then(async (response) => {
    if (!response.ok) {
      state.roomDirectoryOnline = false;
      return;
    }
    const data = await response.json();
    state.roomDirectoryOnline = true;
    if (data.room) {
      mergeHostedRoom(data.room);
      applyRoomDirectoryRoom(data.room);
      broadcastRealtimeRoomChange("round-started", data.room);
    }
  }).catch(() => {
    state.roomDirectoryOnline = false;
  });
}

function publishRoomRoundAdvancing(round = state.round) {
  if (!isRoomMode() || !isCurrentHost() || state.joiningRoom || !state.roomSettings.code || state.roomSettings.code === "CAI-0000") {
    return;
  }
  broadcastRealtimeRoomChange("round-advancing", state.roomSettings.code, {
    status: "in-progress",
    round: Number(round) || state.round,
    matchId: getCurrentRoomMatchId(),
    matchSettings: getRoomMatchSettingsPayload(state.roomSettings),
    updatedAt: Date.now()
  });
}

function publishRoomGameEnded() {
  if (!isRoomMode() || !isCurrentHost() || state.joiningRoom || !state.roomSettings.code || state.roomSettings.code === "CAI-0000") {
    return Promise.resolve(null);
  }
  const game = {
    ...(state.roomGame || {}),
    matchId: setCurrentRoomMatchId(getCurrentRoomMatchId() || createRoomMatchId()),
    status: "ended",
    round: state.round,
    setup: state.roomGame?.setup || null,
    powerState: getRoomPowerStatePayload(),
    updatedAt: Date.now()
  };
  state.roomGame = game;
  return fetch(`/api/rooms/${encodeURIComponent(state.roomSettings.code)}/game`, {
    method: "PUT",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ game })
  }).then(async (response) => {
    if (!response.ok) {
      state.roomDirectoryOnline = false;
      broadcastRealtimeRoomChange("game-ended", state.roomSettings.code, {
        status: "complete",
        matchId: game.matchId,
        game,
        updatedAt: game.updatedAt
      });
      return null;
    }
    const data = await response.json();
    state.roomDirectoryOnline = true;
    if (data.room) {
      mergeHostedRoom(data.room);
      broadcastRealtimeRoomChange("game-ended", data.room.code || state.roomSettings.code, {
        status: "complete",
        matchId: game.matchId,
        revision: data.room.revision || 0,
        updatedAt: data.room.updatedAt || game.updatedAt,
        game: data.room.game || game
      });
    }
    return data.room || null;
  }).catch(() => {
    state.roomDirectoryOnline = false;
    broadcastRealtimeRoomChange("game-ended", state.roomSettings.code, {
      status: "complete",
      matchId: game.matchId,
      game,
      updatedAt: game.updatedAt
    });
    return null;
  });
}

function publishRoomHeartbeat(status = "host") {
  if (!state.roomSettings.code || state.roomSettings.code === "CAI-0000") {
    return Promise.resolve(null);
  }
  return fetch(`/api/rooms/${encodeURIComponent(state.roomSettings.code)}/heartbeat`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      participantId: state.clientId,
      status
    })
  }).then(async (response) => {
    if (!response.ok) {
      return null;
    }
    const data = await response.json();
    if (data.room) {
      mergeHostedRoom(data.room);
      applyRoomDirectoryRoom(data.room);
    }
    return data.room || null;
  }).catch(() => null);
}

async function waitForSyncedRoomSetupForRound(round = state.round, timeoutMs = 12000) {
  const matchToken = state.matchWorkToken;
  const startedAt = Date.now();
  let lastEventRefreshAt = 0;
  let lastDirectRoomRefreshAt = 0;
  while (isCurrentMatchWork(matchToken) && Date.now() - startedAt < timeoutMs) {
    const setup = getSyncedRoomSetupForRound(round);
    if (setup) {
      return setup;
    }
    const eventRefreshIntervalMs = state.realtimeRoomReady ? 2500 : 800;
    if (Date.now() - lastEventRefreshAt > eventRefreshIntervalMs) {
      lastEventRefreshAt = Date.now();
      await refreshRoomEventsSinceLastRevision();
      if (!isCurrentMatchWork(matchToken)) {
        throw createAbortError();
      }
      const eventSetup = getSyncedRoomSetupForRound(round);
      if (eventSetup) {
        return eventSetup;
      }
    }
    const directRoomRefreshIntervalMs = state.realtimeRoomReady ? 1600 : 800;
    const shouldDirectRefresh = Date.now() - lastDirectRoomRefreshAt > directRoomRefreshIntervalMs;
    if (shouldDirectRefresh || !(state.supabaseEnabled && state.realtimeRoomChannel)) {
      lastDirectRoomRefreshAt = Date.now();
      const lookup = await fetchRoomByCode(state.roomSettings.code);
      if (!isCurrentMatchWork(matchToken)) {
        throw createAbortError();
      }
      if (lookup.status === "found" && lookup.room) {
        mergeHostedRoom(lookup.room);
        applyRoomDirectoryRoom(lookup.room);
        const roomSetup = getSyncedRoomSetupForRound(round);
        if (roomSetup) {
          return roomSetup;
        }
      } else if (lookup.status === "closed") {
        handleCurrentRoomClosed("The room was closed by the host or an admin.");
        break;
      }
    }
    await sleep(650);
  }
  if (!isCurrentMatchWork(matchToken)) {
    throw createAbortError();
  }
  throw new Error("Timed out waiting for the host to sync this round.");
}

function shouldStartJoinedRoomMatch(room) {
  const canStartFromWaitingState = state.currentRoomStatus === "lobby"
    || state.currentRoomStatus === "complete"
    || elements.gameStage.classList.contains("hidden")
    || !elements.endPanel.classList.contains("hidden");
  return Boolean(
    room
      && state.joiningRoom
      && !isCurrentHost()
      && canStartFromWaitingState
      && room.status === "in-progress"
      && room.game?.setup
  );
}

function startJoinedRoomMatchFromDirectory(room) {
  applyRoomDirectoryRoom(room);
  state.currentRoomStatus = "in-progress";
  state.mode = "room";
  setPlayersForMode("room");
  startGame("room");
}

function startJoinedRoomMatchFromRealtime(payload = {}, game = null) {
  const code = String(payload.code || payload.room?.code || state.roomSettings.code || "").trim().toUpperCase();
  if (!code || code !== state.roomSettings.code || isCurrentHost() || !state.joiningRoom) {
    return false;
  }
  const sourceRoom = payload.room && typeof payload.room === "object" ? payload.room : state.joiningRoom;
  const nextGame = game || sourceRoom?.game || null;
  const incomingMatchId = getRoomMatchIdFromPayload({ ...payload, game: nextGame });
  if (incomingMatchId && getCurrentRoomMatchId() && incomingMatchId !== getCurrentRoomMatchId() && !canAdoptIncomingRoomGame(nextGame, sourceRoom)) {
    return false;
  }
  if (incomingMatchId) {
    setCurrentRoomMatchId(incomingMatchId);
  }
  state.roomGame = nextGame?.status === "ended" ? null : nextGame;
  applyRoomGameMatchSettings(state.roomGame, payload, { render: false, resetTimer: true });
  state.joiningRoom = {
    ...(state.joiningRoom || {}),
    ...(sourceRoom || {}),
    code,
    status: "in-progress",
    game: state.roomGame,
    revision: Number(payload.revision) || Number(sourceRoom?.revision) || state.joiningRoom?.revision || 0,
    updatedAt: Number(payload.updatedAt) || Number(sourceRoom?.updatedAt) || Date.now()
  };
  state.currentRoomStatus = "in-progress";
  state.mode = "room";
  setPlayersForMode("room");
  startGame("room");
  return true;
}

function applyRealtimeRoundAdvancing(payload = {}) {
  const code = String(payload.code || payload.room?.code || state.roomSettings.code || "").trim().toUpperCase();
  const canStartFromLobby = state.currentRoomStatus === "lobby"
    || state.currentRoomStatus === "complete"
    || elements.gameStage.classList.contains("hidden")
    || !elements.endPanel.classList.contains("hidden");
  if (!code || code !== state.roomSettings.code || !hasActiveRoomContext() || (state.matchEnded && !canStartFromLobby)) {
    return false;
  }
  if (isCurrentHost() && !state.joiningRoom) {
    return false;
  }
  const nextRound = Number(payload.round || payload.nextRound) || 0;
  if (!nextRound || nextRound < Number(state.round)) {
    return false;
  }
  const incomingMatchId = getRoomMatchIdFromPayload(payload);
  if (incomingMatchId && getCurrentRoomMatchId() && incomingMatchId !== getCurrentRoomMatchId() && !isJoinedRoomWaitingForSyncedSetup(nextRound || state.round)) {
    return false;
  }
  if (payload.matchSettings || payload.settings) {
    applyRoomGameMatchSettings({ matchSettings: payload.matchSettings || payload.settings }, payload, { render: false, resetTimer: canStartFromLobby });
  }
  if (incomingMatchId) {
    setCurrentRoomMatchId(incomingMatchId);
  }
  if (canStartFromLobby) {
    if (state.joiningRoom) {
      state.joiningRoom = {
        ...state.joiningRoom,
        status: "in-progress",
        game: null,
        revision: Number(payload.revision) || state.joiningRoom.revision || 0,
        updatedAt: Number(payload.updatedAt) || Date.now()
      };
    }
    state.roomGame = null;
    state.roomRoundResult = null;
    clearRoundSubmissionState();
    updateRoomEventRevision(payload.revision);
    return startJoinedRoomMatchFromRealtime(payload, null);
  }
  if (nextRound === Number(state.round) && elements.verdictPanel.classList.contains("hidden")) {
    updateRoomEventRevision(payload.revision);
    return true;
  }
  cancelActiveMatchWork();
  state.currentRoomStatus = "in-progress";
  state.round = nextRound;
  state.questionId = "";
  state.blackCard = "";
  state.questionType = "image";
  state.questionStyle = "standard";
  state.gradingStrictness = "normal";
  state.questionDifficulty = "medium";
  state.triviaTheme = "";
  state.questionImage = null;
  state.canonicalAnswer = "";
  state.acceptedAnswers = [];
  state.judge = null;
  state.multipleChoiceOptions = [];
  resetRoundUiForLoading({ resetBlackCardTheme: true });
  updateRoomEventRevision(payload.revision);
  return true;
}

function applyRealtimeRoundStarted(payload = {}) {
  const code = String(payload.code || payload.room?.code || state.roomSettings.code || "").trim().toUpperCase();
  const canStartFromLobby = state.currentRoomStatus === "lobby"
    || state.currentRoomStatus === "complete"
    || elements.gameStage.classList.contains("hidden")
    || !elements.endPanel.classList.contains("hidden");
  if (!code || code !== state.roomSettings.code || !hasActiveRoomContext() || (state.matchEnded && !canStartFromLobby)) {
    return false;
  }
  if (isCurrentHost() && !state.joiningRoom) {
    return false;
  }
  const game = payload.game && typeof payload.game === "object"
    ? payload.game
    : payload.room?.game && typeof payload.room.game === "object"
      ? payload.room.game
      : null;
  if (!game?.setup) {
    return false;
  }
  if (!canAdoptIncomingRoomGame(game, payload.room || state.joiningRoom)) {
    return false;
  }
  const nextRound = Number(game.round) || 0;
  if (!nextRound || nextRound < Number(state.round)) {
    return false;
  }
  if (game.matchId) {
    setCurrentRoomMatchId(game.matchId);
  }
  applyRoomGameMatchSettings(game, payload, { render: false, resetTimer: true });
  let setup;
  try {
    setup = normalizeSetupPayload(game.setup);
  } catch {
    return false;
  }
  if (state.currentRoomStatus === "lobby" || elements.gameStage.classList.contains("hidden")) {
    state.roomGame = game;
    if (state.joiningRoom) {
      state.joiningRoom = {
        ...state.joiningRoom,
        status: "in-progress",
        game,
        revision: Number(payload.revision) || state.joiningRoom.revision || 0,
        updatedAt: Number(payload.updatedAt) || Date.now()
      };
    }
    updateRoomEventRevision(payload.revision);
    return startJoinedRoomMatchFromRealtime(payload, game);
  }
  const sameRound = nextRound === Number(state.round);
  const alreadyShowingSetup = sameRound
    && state.questionId
    && setup.id
    && state.questionId === setup.id
    && elements.verdictPanel.classList.contains("hidden");
  if (alreadyShowingSetup) {
    state.roomGame = game;
    syncCurrentRoundSetupMetadata(setup);
    applyRoomGamePowerState(state.roomGame);
    updateRoomEventRevision(payload.revision);
    return true;
  }
  cancelActiveMatchWork();
  state.currentRoomStatus = "in-progress";
  state.round = nextRound;
  state.roomGame = game;
  if (state.joiningRoom) {
    state.joiningRoom = {
      ...state.joiningRoom,
      status: "in-progress",
      game,
      revision: Number(payload.revision) || state.joiningRoom.revision || 0,
      updatedAt: Number(payload.updatedAt) || Date.now()
    };
  }
  resetRoundUiForLoading({ resetBlackCardTheme: true });
  applyRoundSetup(setup);
  applyRoomGamePowerState(game);
  updateRoomEventRevision(payload.revision);
  return true;
}

function applyRealtimeRoomGameEnded(payload = {}) {
  const code = String(payload.code || payload.room?.code || state.roomSettings.code || "").trim().toUpperCase();
  if (!code || code !== state.roomSettings.code || !hasActiveRoomContext()) {
    return false;
  }
  if (!roomPayloadMatchesCurrentMatch(payload)) {
    return false;
  }
  state.roomGame = payload.game && typeof payload.game === "object"
    ? payload.game
    : {
      ...(state.roomGame || {}),
      status: "ended",
      round: state.round,
      updatedAt: Number(payload.updatedAt) || Date.now()
    };
  setCurrentRoomMatchId(state.roomGame.matchId || getCurrentRoomMatchId());
  state.currentRoomStatus = "complete";
  if (state.joiningRoom) {
    state.joiningRoom = {
      ...state.joiningRoom,
      status: "complete",
      game: state.roomGame,
      revision: Number(payload.revision) || state.joiningRoom.revision || 0,
      updatedAt: Number(payload.updatedAt) || Date.now()
    };
  }
  const hostedRoom = state.hostedRooms.find((entry) => entry.code === code);
  if (hostedRoom) {
    hostedRoom.status = "complete";
    hostedRoom.game = state.roomGame;
    hostedRoom.revision = Number(payload.revision) || hostedRoom.revision || 0;
    hostedRoom.updatedAt = Number(payload.updatedAt) || hostedRoom.updatedAt || Date.now();
  }
  updateRoomEventRevision(payload.revision);
  if (!state.matchEnded) {
    addSystemChat("The host ended the game.", { private: true, sync: false });
    endMatch(true, { syncRoom: false });
  }
  return true;
}

function applyRealtimeRoomReturnedToLobby(room = {}) {
  const code = String(room.code || state.roomSettings.code || "").trim().toUpperCase();
  if (!code || code !== state.roomSettings.code || !hasActiveRoomContext()) {
    return false;
  }
  if (!isRoomMode() && state.currentRoomStatus !== "complete" && state.currentRoomStatus !== "in-progress") {
    return false;
  }
  const shouldShowLobby = elements.roomLobbyScreen.classList.contains("hidden")
    && (!elements.gameStage.classList.contains("hidden") || state.currentRoomStatus === "complete" || state.matchEnded);
  if (!shouldShowLobby) {
    return false;
  }
  state.roomGame = null;
  state.roomMatchId = "";
  state.roomRoundResult = null;
  if (state.joiningRoom) {
    state.joiningRoom = {
      ...state.joiningRoom,
      ...(room || {}),
      status: "lobby",
      game: null
    };
  }
  returnToRoomLobbyAfterMatch({ sync: false, playSound: false, participants: room.participants });
  addSystemChat("The host returned everyone to the room.", { private: true, sync: false });
  return true;
}

function hasActiveRoomContext() {
  return state.roomSettings.code !== "CAI-0000"
    && (isRoomMode() || state.currentRoomStatus === "lobby" || state.currentRoomStatus === "draft");
}

function isRoomTabBackgrounded() {
  return document.visibilityState === "hidden";
}

function syncActiveRoomFromDirectory(room, options = {}) {
  state.roomMissingSince = 0;
  applyRoomDirectoryRoom(room);
  if (room?.status === "lobby" && applyRealtimeRoomReturnedToLobby(room)) {
    return true;
  }
  if (room?.status === "complete" && !state.matchEnded) {
    applyRealtimeRoomGameEnded({
      code: room.code,
      revision: room.revision || 0,
      updatedAt: room.updatedAt || Date.now(),
      game: room.game || null
    });
    return true;
  }
  if (shouldStartJoinedRoomMatch(room)) {
    startJoinedRoomMatchFromDirectory(room);
    return true;
  }
  if (isRoomLobbyActive()) {
    renderRoomLobby();
  }
  if (!options.skipHeartbeat && isCurrentHost() && !state.joiningRoom) {
    state.roomExitLeaveSent = false;
    publishRoomHeartbeat(state.currentRoomStatus === "in-progress" ? "playing" : "host");
  }
  return false;
}

async function refreshCurrentRoomDirectory(expectedSessionId = state.roomSessionId) {
  if (expectedSessionId !== state.roomSessionId || !hasActiveRoomContext()) {
    return;
  }
  if (state.currentRoomRefreshPromise) {
    return state.currentRoomRefreshPromise;
  }
  state.currentRoomRefreshPromise = (async () => {
    const directRoom = await fetchRoomByCode(state.roomSettings.code);
    if (expectedSessionId !== state.roomSessionId || !hasActiveRoomContext()) {
      return;
    }
    if (directRoom.status === "found" && directRoom.room) {
      state.roomMissingSince = 0;
      mergeHostedRoom(directRoom.room);
      const closeEvent = Array.isArray(directRoom.room.events)
        && directRoom.room.events.some((event) => event.type === "room_closed");
      if (directRoom.room.closed || closeEvent) {
        handleCurrentRoomClosed("The room was closed by the host or an admin.");
        return;
      }
      syncActiveRoomFromDirectory(directRoom.room, { skipHeartbeat: true });
      return;
    }
    if (directRoom.status === "closed") {
      handleCurrentRoomClosed("The room was closed by the host or an admin.");
      return;
    }
    if ((isRoomMode() || state.currentRoomStatus === "lobby") && state.roomSettings.code !== "CAI-0000") {
      if (isRoomTabBackgrounded()) {
        state.roomMissingSince = 0;
        return;
      }
      const now = Date.now();
      if (!state.roomMissingSince) {
        state.roomMissingSince = now;
        return;
      }
      if (now - state.roomMissingSince < roomMissingGraceMs) {
        return;
      }
      if (directRoom.status === "missing") {
        state.roomMissingSince = 0;
      }
    }
  })();
  try {
    return await state.currentRoomRefreshPromise;
  } finally {
    state.currentRoomRefreshPromise = null;
  }
}

function handleRoomVisibilityChange() {
  if (document.visibilityState !== "visible" || !hasActiveRoomContext()) {
    return;
  }
  state.roomMissingSince = 0;
  requestRoomRealtimeCatchup("visible", { force: true, snapshot: false });
  if (!isRoomRealtimeHealthy()) {
    startRoomDirectoryPolling();
  }
}

function startRoomHeartbeat() {
  stopRoomHeartbeat();
  if (!isCurrentHost() || state.joiningRoom || !hasActiveRoomContext()) {
    return;
  }
  state.roomHeartbeatTimerId = window.setInterval(() => {
    if (!isCurrentHost() || state.joiningRoom || !hasActiveRoomContext()) {
      stopRoomHeartbeat();
      return;
    }
    publishRoomHeartbeat(state.currentRoomStatus === "in-progress" ? "playing" : "host");
  }, 60000);
}

function startRoomEventPolling() {
  stopRoomEventPolling();
  if (state.realtimeRoomReady || !hasActiveRoomContext()) {
    return;
  }
  const sessionId = state.roomSessionId;
  const intervalMs = getRoomEventPollIntervalMs();
  state.roomEventPollId = window.setInterval(() => {
    if (sessionId !== state.roomSessionId || !hasActiveRoomContext() || state.realtimeRoomReady) {
      stopRoomEventPolling();
      return;
    }
    refreshRoomEventsSinceLastRevision();
  }, intervalMs);
}

function stopRoomEventPolling() {
  if (state.roomEventPollId) {
    window.clearInterval(state.roomEventPollId);
    state.roomEventPollId = null;
  }
}

function stopRoomHeartbeat() {
  if (state.roomHeartbeatTimerId) {
    window.clearInterval(state.roomHeartbeatTimerId);
    state.roomHeartbeatTimerId = null;
  }
}

function isRoomRealtimeHealthy() {
  return Boolean(state.supabaseEnabled && state.realtimeRoomChannel && state.realtimeRoomReady);
}

function handleRoomRealtimeStatus(status = "") {
  state.roomRealtimeStatus = String(status || "unknown");
  state.realtimeRoomReady = status === "SUBSCRIBED";
  if (state.realtimeRoomReady) {
    state.roomRealtimeUnhealthySince = 0;
    stopRoomFallbackPolling({ keepHeartbeat: true });
    startRoomHeartbeat();
    requestRoomRealtimeCatchup("subscribed", { force: true, snapshot: false });
    return;
  }
  if (!state.roomRealtimeUnhealthySince) {
    state.roomRealtimeUnhealthySince = Date.now();
  }
  scheduleRoomFallbackPolling(`realtime-${state.roomRealtimeStatus.toLowerCase()}`);
}

function getRoomFallbackDelayMs() {
  if (!state.supabaseEnabled || !state.realtimeRoomChannel) {
    return 3500;
  }
  return isRoomTabBackgrounded() ? 15000 : 9000;
}

function requestRoomRealtimeCatchup(reason = "sync", options = {}) {
  if (!hasActiveRoomContext()) {
    return Promise.resolve(false);
  }
  const now = Date.now();
  if (!options.force && now - (state.roomLastCatchupAt || 0) < 1200) {
    return Promise.resolve(false);
  }
  state.roomLastCatchupAt = now;
  return refreshRoomEventsSinceLastRevision({ force: true }).then((hadEvents) => {
    if (hadEvents || options.snapshot === false) {
      return hadEvents;
    }
    return refreshCurrentRoomDirectory(state.roomSessionId).then(() => false);
  });
}

function scheduleRoomFallbackPolling(reason = "realtime-unhealthy") {
  if (!hasActiveRoomContext() || isRoomRealtimeHealthy()) {
    stopRoomFallbackPolling({ keepHeartbeat: true });
    return;
  }
  startRoomHeartbeat();
  if (state.roomFallbackActive || state.roomFallbackStartTimerId) {
    return;
  }
  const delayMs = getRoomFallbackDelayMs();
  state.roomFallbackStartTimerId = window.setTimeout(() => {
    state.roomFallbackStartTimerId = null;
    if (!hasActiveRoomContext() || isRoomRealtimeHealthy()) {
      stopRoomFallbackPolling({ keepHeartbeat: true });
      return;
    }
    startRoomFallbackPolling(reason);
  }, delayMs);
}

function startRoomFallbackPolling(reason = "realtime-unhealthy") {
  if (!hasActiveRoomContext() || isRoomRealtimeHealthy()) {
    stopRoomFallbackPolling({ keepHeartbeat: true });
    return;
  }
  state.roomFallbackActive = true;
  startRoomEventPolling();
  refreshRoomEventsSinceLastRevision({ force: true });
  if (!state.roomDirectoryPollId) {
    const sessionId = state.roomSessionId;
    const intervalMs = getRoomSnapshotPollIntervalMs();
    state.roomDirectoryPollId = window.setInterval(() => refreshCurrentRoomDirectory(sessionId), intervalMs);
  }
}

function stopRoomFallbackPolling(options = {}) {
  if (state.roomFallbackStartTimerId) {
    window.clearTimeout(state.roomFallbackStartTimerId);
    state.roomFallbackStartTimerId = null;
  }
  if (state.roomDirectoryPollId) {
    window.clearInterval(state.roomDirectoryPollId);
    state.roomDirectoryPollId = null;
  }
  stopRoomEventPolling();
  state.roomFallbackActive = false;
  if (!options.keepHeartbeat) {
    stopRoomHeartbeat();
  }
}

function isRoomInWaitingSyncState() {
  return state.currentRoomStatus === "lobby"
    || state.currentRoomStatus === "complete"
    || !elements.endPanel.classList.contains("hidden");
}

function getRoomEventPollIntervalMs() {
  if (isRoomTabBackgrounded()) {
    return 20000;
  }
  return isRoomInWaitingSyncState() ? 6000 : 3000;
}

function getRoomSnapshotPollIntervalMs() {
  if (isRoomTabBackgrounded()) {
    return 45000;
  }
  if (isRoomInWaitingSyncState()) {
    return 20000;
  }
  return state.supabaseEnabled ? 20000 : 15000;
}

function startRoomDirectoryPolling() {
  stopRoomFallbackPolling({ keepHeartbeat: true });
  startRoomHeartbeat();
  if (isRoomRealtimeHealthy()) {
    requestRoomRealtimeCatchup("start", { force: true, snapshot: false });
    return;
  }
  scheduleRoomFallbackPolling("start");
}

function stopRoomDirectoryPolling() {
  stopRoomFallbackPolling();
}

function getKickableRoomBotTarget(owner = "", participantId = "") {
  if (!isRoomMode() || !isCurrentHost()) {
    return null;
  }

  const participant = participantId
    ? state.roomParticipants.find((entry) => entry.id === participantId)
    : null;
  const player = owner ? getPlayer(owner) : null;
  const participantFromPlayer = player?.participantId
    ? state.roomParticipants.find((entry) => entry.id === player.participantId)
    : null;
  const targetParticipant = participant || participantFromPlayer;
  const targetPlayer = player?.bot
    ? player
    : state.players.find((entry) => targetParticipant && entry.participantId === targetParticipant.id) || null;
  const isBot = Boolean(targetParticipant?.bot || targetPlayer?.bot || targetPlayer?.type === "bot");
  const isActive = targetParticipant
    ? targetParticipant.active !== false && !targetParticipant.spectator
    : Boolean(targetPlayer?.active);
  const resolvedParticipantId = targetParticipant?.id || targetPlayer?.participantId || "";

  if (!isBot || !isActive || !resolvedParticipantId) {
    return null;
  }

  return {
    owner: targetPlayer?.owner || owner,
    participantId: resolvedParticipantId,
    name: targetParticipant?.name || targetPlayer?.label || "Bot"
  };
}

function canKickRoomBot(owner = "", participantId = "") {
  return Boolean(getKickableRoomBotTarget(owner, participantId));
}

function kickRoomBot(owner = "", participantId = "") {
  const target = getKickableRoomBotTarget(owner, participantId);
  if (!target) {
    return false;
  }

  const opponentParticipantId = getPlayer("opponent")?.participantId;
  removeRoomParticipantLocally(target.participantId, { status: "kicked" });
  if (target.owner === "opponent" || opponentParticipantId === target.participantId) {
    state.localAnswers.playerTwo = "";
  }

  addSystemChat(`${target.name} was kicked from the room.`);
  const opponent = getPlayer("opponent");
  if (opponent?.active && state.roomSubmissions.opponent === undefined) {
    state.roomSubmissions.opponent = false;
  }
  renderScore();
  renderRoomPlayers();
  renderSubmissionStatus();
  maybeResolveRoomSubmissions();
  publishRoomModeration("kick", target.participantId, { reason: "bot-kicked" }).then((data) => {
    if (!data) {
      upsertHostedRoom(state.currentRoomStatus === "in-progress" ? "in-progress" : "lobby");
      broadcastRealtimeRoomChange("participant-moderated", state.roomSettings.code, {
        action: "kick",
        participantId: target.participantId,
        participantName: target.name,
        updatedAt: Date.now()
      });
    }
  });
  playSound("click");
  return true;
}

function handleKickableBotClick(event) {
  if (event.target.closest("button, a, input, select, textarea, [data-action], .leaderboard-power-pill, .result-power-pill")) {
    return false;
  }
  const row = event.target.closest("[data-participant-id], [data-owner]");
  if (!row) {
    return false;
  }
  const owner = row.dataset.owner || "";
  const participantId = row.dataset.participantId || "";
  if (!kickRoomBot(owner, participantId)) {
    return false;
  }
  event.preventDefault();
  event.stopPropagation();
  return true;
}

function getHostedRoomsRenderSignature(visibleRooms = []) {
  if (!visibleRooms.length) {
    return `empty:${state.roomDirectoryOnline ? "online" : "offline"}`;
  }
  return JSON.stringify(visibleRooms.map((room) => ({
    code: room.code,
    status: room.status,
    activePlayers: getHostedRoomActivePlayerCount(room),
    maxPlayers: getRoomMaxPlayers(room.settings),
    spectators: Number(room.spectators) || 0,
    private: Boolean(room.settings?.private),
    mode: getRoomModeLabel(room.settings),
    host: {
      id: room.host?.id || "",
      name: room.host?.name || "",
      avatar: room.host?.avatar || "",
      equippedTitleId: room.host?.equippedTitleId || "",
      specialBadges: room.host?.specialBadges || [],
      cardCustomization: room.host?.cardCustomization || null
    }
  })));
}

function captureJoinScreenLayoutSnapshot() {
  if (!elements.joinScreen || elements.joinScreen.classList.contains("hidden")) {
    return [];
  }
  return [elements.joinScreen.querySelector(".room-header"), elements.joinCodeForm]
    .filter(Boolean)
    .map((element) => ({
      element,
      rect: element.getBoundingClientRect()
    }));
}

function animateJoinScreenLayoutShift(snapshot = []) {
  if (!snapshot.length || shouldReduceMotion()) {
    return;
  }
  window.requestAnimationFrame(() => {
    snapshot.forEach(({ element, rect }) => {
      if (!element.isConnected || typeof element.animate !== "function") {
        return;
      }
      const nextRect = element.getBoundingClientRect();
      const deltaX = rect.left - nextRect.left;
      const deltaY = rect.top - nextRect.top;
      if (Math.abs(deltaX) < 0.5 && Math.abs(deltaY) < 0.5) {
        return;
      }
      element.animate(
        [
          { translate: `${deltaX}px ${deltaY}px` },
          { translate: "0 0" }
        ],
        {
          duration: 420,
          easing: "cubic-bezier(0.16, 1, 0.3, 1)"
        }
      );
    });
  });
}

function renderHostedRooms(options = {}) {
  const visibleRooms = state.hostedRooms.filter((room) => room.status !== "complete");
  const renderSignature = getHostedRoomsRenderSignature(visibleRooms);
  if (!options.force && state.hostedRoomsRenderSignature === renderSignature && elements.joinRoomList.children.length) {
    return;
  }
  const layoutSnapshot = elements.joinRoomList.children.length ? captureJoinScreenLayoutSnapshot() : [];
  state.hostedRoomsRenderSignature = renderSignature;
  elements.joinRoomList.replaceChildren();
  if (!visibleRooms.length) {
    const empty = document.createElement("section");
    empty.className = "join-room-card";
    const copy = document.createElement("div");
    const title = document.createElement("strong");
    title.textContent = state.roomDirectoryOnline ? "No hosted rooms yet." : "Room server is not connected.";
    const meta = document.createElement("div");
    meta.className = "join-room-meta";
    const chip = document.createElement("span");
    chip.textContent = state.roomDirectoryOnline ? "Create one first" : "Open the app from npm start on the same address";
    meta.appendChild(chip);
    copy.append(title, meta);
    empty.appendChild(copy);
    elements.joinRoomList.appendChild(empty);
    animateJoinScreenLayoutShift(layoutSnapshot);
    return;
  }

  visibleRooms.forEach((room) => {
    const card = document.createElement("section");
    card.className = "join-room-card";
    applyProfileCustomizationSurface(card, room.host?.cardCustomization || defaultProfileCustomization);
    const details = document.createElement("div");
    const host = document.createElement("div");
    host.className = "join-room-host";
    const avatar = document.createElement("span");
    avatar.className = "room-player-avatar";
    renderAvatar(avatar, { label: room.host.name, avatar: room.host.avatar });
    const hostName = document.createElement("strong");
    renderPlayerNameWithTitle(hostName, {
      owner: room.host.id === state.clientId ? state.currentOwner : "room-host",
      label: room.host.name,
      host: true,
      equippedTitleId: room.host.equippedTitleId || "",
      specialBadges: room.host.specialBadges || [],
      cardCustomization: room.host.cardCustomization || null
    }, room.host.name);
    host.append(avatar, hostName);
    const meta = document.createElement("div");
    meta.className = "join-room-meta";
    const activePlayers = getHostedRoomActivePlayerCount(room);
    [room.settings.private ? "Private" : "Public", `${activePlayers}/${getRoomMaxPlayers(room.settings)} players`, `${room.spectators} spectators`, room.status].forEach((label) => {
      const chip = document.createElement("span");
      chip.textContent = label;
      meta.appendChild(chip);
    });
    const modifierChip = document.createElement("span");
    modifierChip.className = "join-room-modifier-chip";
    renderModifierIconLabel(modifierChip, room.settings, {
      className: "modifier-icon-list join-room-modifiers",
      includeSettings: false,
      emptyText: "No Modifiers"
    });
    meta.appendChild(modifierChip);
    details.append(host, meta);
    const actions = document.createElement("div");
    actions.className = "join-room-actions";
    const joinButton = document.createElement("button");
    joinButton.type = "button";
    joinButton.dataset.roomAction = "join";
    joinButton.dataset.joinRoom = room.code;
    const currentProfileParticipant = getRoomParticipantWithCurrentProfile(room);
    const currentProfileIsHost = isCurrentProfileHostOfRoom(room);
    const currentProfileCanReconnectAsPlayer = canReconnectCurrentProfileAsRoomPlayer(room);
    const currentProfileIsActive = Boolean(
      currentProfileParticipant
      && currentProfileParticipant.active !== false
      && !currentProfileIsHost
    );
    joinButton.textContent = currentProfileIsHost || currentProfileParticipant?.active === false ? "Rejoin" : "Join Game";
    const roomIsFull = activePlayers >= getRoomMaxPlayers(room.settings);
    joinButton.disabled = currentProfileIsActive
      || (!currentProfileIsHost && !currentProfileCanReconnectAsPlayer && room.status !== "lobby")
      || (!currentProfileParticipant && roomIsFull);
    const joinHint = room.status === "lobby"
      ? currentProfileIsActive
        ? "This profile is already active in this room."
        : roomIsFull
        ? "This room is full, but you can still watch as a spectator."
        : currentProfileIsHost
          ? "Rejoin your hosted room."
          : room.settings.private ? "Enter the room password to join before the match starts." : "Join this lobby as an active player before the match starts."
      : currentProfileIsHost
        ? "Rejoin your active room as host."
        : currentProfileCanReconnectAsPlayer
          ? "Reconnect to your player slot in this active match."
          : "This game already started. You can spectate instead.";
    setFloatingButtonHint(joinButton, joinHint);
    const spectateButton = document.createElement("button");
    spectateButton.type = "button";
    spectateButton.className = "secondary-button";
    spectateButton.dataset.roomAction = "spectate";
    spectateButton.dataset.joinRoom = room.code;
    spectateButton.textContent = "Spectate";
    setFloatingButtonHint(spectateButton, room.settings.private ? "Enter the password to watch this private room." : "Watch the game without taking a player slot.");
    actions.append(joinButton, spectateButton);
    card.append(details, actions);
    elements.joinRoomList.appendChild(card);
  });
  animateJoinScreenLayoutShift(layoutSnapshot);
}

function getHostedRoomActivePlayerCount(room) {
  if (Array.isArray(room?.participants) && room.participants.length) {
    return room.participants.filter((participant) => participant.active !== false && !participant.spectator).length;
  }
  return Number(room?.activePlayers || 0);
}

function getRoomParticipantWithCurrentProfile(room = null) {
  const profileUserId = getRoomParticipantProfileUserId();
  return normalizeRoomParticipantsList(room?.participants || [])
    .find((participant) => (
      participant.id === state.clientId
      || (profileUserId && participant.profileUserId === profileUserId)
    )) || null;
}

function isCurrentProfileHostOfRoom(room = null) {
  const participant = getRoomParticipantWithCurrentProfile(room);
  const hostProfileUserId = String(room?.host?.profileUserId || "").trim();
  const profileUserId = getRoomParticipantProfileUserId();
  return Boolean(
    participant?.host
    || participant?.id === room?.host?.id
    || room?.host?.id === state.clientId
    || (hostProfileUserId && hostProfileUserId === profileUserId)
  );
}

function canReconnectCurrentProfileAsRoomPlayer(room = null) {
  const participant = getRoomParticipantWithCurrentProfile(room);
  return Boolean(
    participant
    && participant.active === false
    && !participant.host
    && !participant.spectator
    && room?.status === "in-progress"
    && room?.game
  );
}

async function rejoinHostedRoomAsHost(room) {
  state.roomSettings = { ...room.settings };
  syncRoomMatchStateFromSettings(state.roomSettings, { render: false, resetTimer: true });
  startRoomRealtime(state.roomSettings.code);
  state.joiningRoom = null;
  state.isSpectator = false;
  state.mode = "room";
  state.currentOwner = "player";
  state.currentRoomStatus = room.status === "in-progress" ? "in-progress" : "lobby";
  state.roomSessionId += 1;
  state.roomExitLeaveSent = false;
  state.roomMissingSince = 0;
  state.roomClosedNotice = "";
  state.roomParticipants = normalizeRoomParticipantsList(room.participants);
  setCurrentRoomMatchId(room.game?.matchId || "");
  state.roomGame = room.game || null;
  rememberHostedRoomSession(room.code);
  setRoomInviteUrlPath(room.code);
  const updatedRoom = await updateRoomPresence(room, {
    host: true,
    status: "host",
    compactResponse: true
  });
  const activeRoom = updatedRoom || room;
  mergeHostedRoom(activeRoom);
  applyRoomDirectoryRoom(activeRoom);
  state.roomChat = [];
  resetChatCooldown();
  if (Array.isArray(activeRoom.chat)) {
    mergeRoomChatMessages(activeRoom.chat);
  }
  addSystemChat("Host rejoined.", { sync: false });
  stopJoinDirectoryPolling();
  setJoinInviteMode(false);
  setHidden(elements.modeScreen, true);
  setHidden(elements.roomScreen, true);
  setHidden(elements.joinScreen, true);
  setHidden(elements.gameStage, true);
  if (state.currentRoomStatus === "lobby") {
    setPlayersForMode("room");
    renderRoomLobby();
    startRoomDirectoryPolling();
    setHidden(elements.roomLobbyScreen, false);
  } else {
    startGame("room");
  }
  playSound("click");
}

function getRoomModeLabel(settings = state.roomSettings) {
  const modes = getModifierLabelsFromSettings(settings);
  return modes.length ? modes.join(" + ") : "No Modifiers";
}

function setJoinRoomBusy(isBusy, code = "") {
  state.roomJoinInProgress = Boolean(isBusy);
  elements.joinCodeForm.querySelectorAll("input, button").forEach((control) => {
    control.disabled = Boolean(isBusy);
  });
  if (!isBusy) {
    if (!state.roomInvite.active && !elements.joinScreen.classList.contains("hidden")) {
      renderHostedRooms({ force: true });
    }
    return;
  }
  elements.joinRoomList.querySelectorAll("[data-join-room]").forEach((button) => {
    button.disabled = true;
    if (code && button.dataset.joinRoom === code) {
      button.dataset.previousText = button.textContent;
      button.textContent = "Joining...";
    }
  });
}

async function syncJoinedRoomPresence(room, expectedSessionId = state.roomSessionId, options = {}) {
  let serverRoom = await updateRoomPresence(room, {
    spectator: state.isSpectator,
    status: state.isSpectator ? "spectating" : "joined",
    compactResponse: true,
    ...(Object.hasOwn(options, "roomPassword") ? { roomPassword: options.roomPassword } : {})
  });
  if (expectedSessionId !== state.roomSessionId || state.roomSettings.code !== room.code) {
    return null;
  }
  if (!serverRoom) {
    if (room.settings?.private) {
      elements.joinRoomPasswordInput.focus();
      setJoinInviteStatus("That password did not work. Try again or return to the main menu.", "error");
      addSystemChat("Room password did not match.", { private: true, sync: false });
      return null;
    }
    const lookup = await fetchRoomByCode(room.code);
    if (expectedSessionId !== state.roomSessionId || state.roomSettings.code !== room.code) {
      return null;
    }
    if (lookup.status === "closed") {
      handleCurrentRoomClosed("The room was closed by the host or an admin.");
      return null;
    }
    if (lookup.status === "found" && lookup.room) {
      serverRoom = lookup.room;
    } else {
      addSystemChat("Room server is slow. Try joining again in a moment.", { private: true, sync: false });
      return null;
    }
  }
  mergeHostedRoom(serverRoom);
  applyRoomDirectoryRoom(serverRoom);
  if (state.currentRoomStatus === "lobby" && !elements.roomLobbyScreen.classList.contains("hidden")) {
    renderRoomLobby();
  }
  return serverRoom;
}

async function joinHostedRoom(code, options = {}) {
  if (state.roomJoinInProgress) {
    return;
  }
  const normalizedCode = normalizeJoinRoomCode(code);
  if (!normalizedCode) {
    elements.joinRoomCodeInput.focus();
    return;
  }
  setJoinRoomBusy(true, normalizedCode);
  let room = state.hostedRooms.find((entry) => entry.code === normalizedCode);
  try {
    if (!room) {
      const lookup = await fetchRoomByCode(normalizedCode);
      if (lookup.status === "closed") {
        addSystemChat(`Room ${normalizedCode || "code"} was closed.`, { private: true });
        return;
      }
      if (lookup.status === "found" && lookup.room) {
        room = lookup.room;
        mergeHostedRoom(room);
      }
    }
    if (!room) {
      addSystemChat(`Room ${normalizedCode || "code"} was not found.`, { private: true });
      return;
    }
    if (isCurrentProfileHostOfRoom(room)) {
      await rejoinHostedRoomAsHost(room);
      return;
    }
    const sameProfileParticipant = getRoomParticipantWithCurrentProfile(room);
    const reconnectAsPlayer = canReconnectCurrentProfileAsRoomPlayer(room);
    if (
      sameProfileParticipant
      && sameProfileParticipant.active !== false
    ) {
      addSystemChat("This profile is already active in that room. Use the existing tab, or reconnect after it disconnects.", { private: true, sync: false });
      return;
    }
    const banList = state.roomModeration.bannedByRoom[normalizedCode] || [];
    if (banList.includes("opponent") || banList.includes(state.profile.name)) {
      addSystemChat(`You cannot rejoin ${normalizedCode}.`, { private: true });
      return;
    }
    const activePlayerCount = getHostedRoomActivePlayerCount(room);
    const roomIsFull = activePlayerCount >= getRoomMaxPlayers(room.settings);
    const shouldSpectate = Boolean(options.spectate || (!reconnectAsPlayer && options.fromInvite && (room.status !== "lobby" || roomIsFull)));
    if (room.status !== "lobby" && !shouldSpectate && !reconnectAsPlayer) {
      addSystemChat("That match already started. Join as a spectator instead.", { private: true });
      return;
    }
    if (!shouldSpectate && !reconnectAsPlayer && roomIsFull) {
      addSystemChat(`${normalizedCode} is full. Join as a spectator instead.`, { private: true });
      return;
    }
    let typedPassword = "";
    if (room.settings.private) {
      typedPassword = cleanChatInput(options.password || elements.joinRoomPasswordInput.value);
      if (!typedPassword) {
        openJoinScreen({ inviteCode: normalizedCode, checked: true });
        setJoinInviteStatus(`Room ${getRoomShortCode(normalizedCode) || normalizedCode} is private. Enter the password to join.`, "");
        focusInvitePasswordField();
        return;
      }
    }

    state.roomSettings = { ...room.settings };
    syncRoomMatchStateFromSettings(state.roomSettings, { render: false, resetTimer: true });
    startRoomRealtime(state.roomSettings.code);
    state.joiningRoom = room;
    state.isSpectator = shouldSpectate || (!reconnectAsPlayer && room.status !== "lobby");
    state.roomSessionId += 1;
    state.roomExitLeaveSent = false;
    state.roomMissingSince = 0;
    state.roomClosedNotice = "";
    state.currentOwner = state.isSpectator ? "spectator" : "opponent";
    state.currentRoomStatus = room.status === "lobby" ? "lobby" : "in-progress";
    state.roomParticipants = normalizeRoomParticipantsList(room.participants);
    const joinedRoom = await syncJoinedRoomPresence(room, state.roomSessionId, { roomPassword: typedPassword });
    if (!joinedRoom) {
      clearLocalRoomState();
      startSupabaseRealtime();
      if (!elements.joinScreen.classList.contains("hidden")) {
        renderHostedRooms();
      }
      return;
    }
    room = joinedRoom;
    if (room.status !== "lobby" && !shouldSpectate && !reconnectAsPlayer) {
      await leavePublishedRoom({ reason: "join-race" });
      clearLocalRoomState();
      addSystemChat("That match just started. Join as a spectator instead.", { private: true, sync: false });
      renderHostedRooms();
      return;
    }
    state.isSpectator = shouldSpectate || (!reconnectAsPlayer && room.status !== "lobby");
    state.currentOwner = state.isSpectator ? "spectator" : "opponent";
    state.currentRoomStatus = room.status === "lobby" ? "lobby" : "in-progress";
    state.roomChat = [];
    resetChatCooldown();
    if (Array.isArray(room.chat)) {
      mergeRoomChatMessages(room.chat);
    }
    addSystemChat(reconnectAsPlayer
      ? `${state.profile.name || "Guest"} reconnected to the match.`
      : `${state.profile.name || "Guest"} joined ${state.isSpectator ? "as a spectator" : "the room"}.`);
    stopJoinDirectoryPolling();
    setJoinInviteMode(false);
    setRoomInviteUrlPath(normalizedCode);
    setHidden(elements.modeScreen, true);
    setHidden(elements.roomScreen, true);
    setHidden(elements.joinScreen, true);
    setHidden(elements.gameStage, true);
    if (room.status === "lobby") {
      state.mode = "room";
      setPlayersForMode("room");
      applyRoomDirectoryRoom(state.hostedRooms.find((entry) => entry.code === normalizedCode) || room);
      renderRoomLobby();
      startRoomDirectoryPolling();
      setHidden(elements.roomLobbyScreen, false);
      playSound("click");
      return;
    }

    setHidden(elements.roomLobbyScreen, true);
    startGame("room");
  } finally {
    setJoinRoomBusy(false);
  }
}

async function processInitialRoomInvite() {
  const inviteCode = getInitialRoomInviteCodeFromPath();
  if (!inviteCode || state.roomInvite.checked) {
    return;
  }
  openJoinScreen({ inviteCode, checked: true, playSound: false });
  setJoinInviteStatus(`Finding room ${getRoomShortCode(inviteCode) || inviteCode}...`);
  let lookup;
  try {
    await ensureSupabaseAuthReady({ realtime: true });
    lookup = await fetchRoomByCode(inviteCode);
  } catch (error) {
    console.warn("Could not open room invite:", error.message || error);
    setJoinInviteStatus("Could not open this invite. Check your connection, then try again.", "error");
    return;
  }
  if (lookup.status === "closed") {
    setJoinInviteStatus("This room was closed by the host.", "error");
    return;
  }
  if (lookup.status === "missing") {
    setJoinInviteStatus("No active room exists for this invite code. Check the code with the host.", "error");
    return;
  }
  if (lookup.status !== "found" || !lookup.room) {
    setJoinInviteStatus("Room lookup is taking too long. Check your connection, then try again.", "error");
    return;
  }
  mergeHostedRoom(lookup.room);
  elements.joinRoomCodeInput.value = getRoomShortCode(inviteCode) || inviteCode;
  if (lookup.room.settings?.private) {
    setJoinInviteStatus(`Room ${getRoomShortCode(inviteCode)} is private. Enter the password to join.`);
    focusInvitePasswordField();
    return;
  }
  setJoinInviteStatus("Room found. Joining...", "success");
  await joinHostedRoom(inviteCode, { fromInvite: true });
}

function getRoomOpenSlotCount() {
  return Math.max(0, getRoomMaxPlayers() - getActiveRoomPlayerCount());
}

function getRandomRoomBotName() {
  const existingNames = new Set(getRoomParticipantsFromPlayers("lobby").map((participant) => String(participant.name || "").toLowerCase()));
  const candidates = getRandomBotUsernames(12).filter((name) => !existingNames.has(name.toLowerCase()));
  if (candidates.length) {
    return candidates[0];
  }
  return `Room_Bot_${state.roomParticipants.filter((participant) => participant.bot).length + 1}`;
}

async function addBotToRoom() {
  if (!isCurrentHost() || state.currentRoomStatus !== "lobby") {
    addSystemChat("Only the host can add bots while the room is in the lobby.", { private: true });
    return;
  }
  if (getRoomOpenSlotCount() <= 0) {
    addSystemChat("This room is full.", { private: true });
    renderRoomLobby();
    return;
  }
  if (!state.randomUsernames.length) {
    await loadRandomUsernames();
  }
  const participants = state.roomParticipants.length
    ? normalizeRoomParticipantsList(state.roomParticipants).filter((participant) => participant.active !== false || participant.spectator)
    : getRoomParticipantsFromPlayers("lobby");
  const botCount = participants.filter((participant) => participant.bot).length + 1;
  const botName = getRandomRoomBotName();
  state.roomBotSequence += 1;
  const bot = {
    id: `room-bot-${Date.now()}-${state.roomBotSequence}-${String(state.clientId).slice(-10)}`,
    name: botName,
    avatar: "",
    equippedTitleId: "",
    cardCustomization: null,
    host: false,
    spectator: false,
    bot: true,
    active: true,
    muted: false,
    status: "bot"
  };
  state.roomParticipants = normalizeRoomParticipantsList([...participants, bot]);
  syncRoomPlayersFromParticipants();
  addSystemChat(`${botName} joined as a bot.`);
  const hostedRoom = state.hostedRooms.find((room) => room.code === state.roomSettings.code);
  if (hostedRoom) {
    hostedRoom.participants = [...state.roomParticipants];
    hostedRoom.activePlayers = state.roomParticipants.filter((participant) => participant.active && !participant.spectator).length;
    hostedRoom.spectators = state.roomParticipants.filter((participant) => participant.active && participant.spectator).length;
    hostedRoom.updatedAt = Date.now();
  }
  broadcastRealtimeRoomChange("participant-updated", state.roomSettings.code, {
    status: state.currentRoomStatus,
    revision: state.roomEventRevision,
    updatedAt: Date.now(),
    participant: bot
  });
  publishRoomParticipantDelta(bot).then((data) => {
    if (!data) {
      upsertHostedRoom("lobby");
    }
  });
  renderRoomLobby();
  playSound("click");
}

function renderRoomLobby() {
  stopTimer();
  stopNextRoundCountdown();
  clearRoomAutoResolve();
  elements.lobbyRoomCode.textContent = state.roomSettings.code;
  elements.lobbyRoomCodeLabel.textContent = state.roomSettings.code;
  syncRoomInviteButtons();
  renderModifierIconLabel(elements.lobbyRoomVariantLabel);
  elements.lobbyRoomSummary.textContent = `${state.roomSettings.private ? "Private" : "Public"} ${getRoomModeLabel()} room. ${state.roomSettings.rounds} rounds, ${state.roomSettings.timerSeconds}s timer, ${getRoomMaxPlayers()} player limit.`;
  const hostParticipant = state.roomParticipants.find((participant) => participant.host)
    || getRoomParticipantsFromPlayers("lobby").find((participant) => participant.host)
    || getCurrentParticipant({ host: true, status: "host" });
  renderPlayerNameWithTitle(elements.lobbyHostNamePreview, {
    owner: hostParticipant.id === state.clientId ? state.currentOwner : "room-host",
    label: hostParticipant.name || "Host",
    host: Boolean(hostParticipant.host),
    equippedTitleId: hostParticipant.equippedTitleId || "",
    specialBadges: hostParticipant.specialBadges || [],
    cardCustomization: hostParticipant.cardCustomization || null
  }, hostParticipant.name || "Host");
  renderAvatar(elements.lobbyHostAvatarPreview, { label: hostParticipant.name || "Host", avatar: hostParticipant.avatar || "" });
  applyProfileCustomizationSurface(elements.lobbyHostProfile, hostParticipant.cardCustomization || defaultProfileCustomization);
  setHidden(elements.beginRoomButton, !isCurrentHost());
  elements.beginRoomButton.disabled = isCurrentHost() && getActiveRoomPlayerCount() < 2;
  setButtonHint(
    elements.beginRoomButton,
    getActiveRoomPlayerCount() < 2
      ? "Waiting for one more active player before the host can start."
      : "Start the match for everyone in this lobby."
  );
  setHidden(elements.lobbyAddBotButton, !isCurrentHost());
  elements.lobbyAddBotButton.disabled = state.currentRoomStatus !== "lobby" || getRoomOpenSlotCount() <= 0;
  setButtonHint(
    elements.lobbyAddBotButton,
    getRoomOpenSlotCount() <= 0
      ? "This room is full."
      : "Add a bot to occupy an empty player slot for multiplayer testing."
  );
  setHidden(elements.lobbySettingsButton, !isCurrentHost());
  renderRoomPlayers();
  renderRoomChat();
}

function openRoomLobby() {
  state.mode = "room";
  setPlayersForMode("room");
  state.roomParticipants = normalizeRoomParticipantsList(getRoomParticipantsFromPlayers("lobby"));
  setRoomInviteUrlPath(state.roomSettings.code);
  renderRoomLobby();
  startRoomDirectoryPolling();
  setHidden(elements.modeScreen, true);
  setHidden(elements.roomScreen, true);
  setHidden(elements.joinScreen, true);
  setHidden(elements.gameStage, true);
  setHidden(elements.roomLobbyScreen, false);
}

function openLobbySettings() {
  syncRoomControls();
  setHidden(elements.roomLobbyScreen, true);
  setHidden(elements.roomScreen, false);
  playSound("click");
}

async function beginRoomMatch() {
  if (!isCurrentHost()) {
    addSystemChat("Only the host can begin the match.", { private: true });
    return;
  }

  await refreshCurrentRoomDirectory();
  if (getActiveRoomPlayerCount() < 2) {
    addSystemChat("Need at least 2 players before starting the match.", { private: true });
    renderRoomLobby();
    return;
  }
  state.currentRoomStatus = "in-progress";
  setCurrentRoomMatchId(createRoomMatchId());
  state.roomGame = null;
  state.roomRoundResult = null;
  resetRoomPowerSyncClocks();
  clearRoundSubmissionState();
  applyRandomRoomModifiersForMatch();
  addSystemChat("The host started the match.");
  upsertHostedRoom("in-progress");
  publishRoomRoundAdvancing(1);
  startGame("room");
}

async function leaveCurrentRoom() {
  const isLeavingRoom = isRoomMode() || state.currentRoomStatus === "lobby";
  const isLeavingActiveMatch = !elements.gameStage.classList.contains("hidden");
  if (!isLeavingRoom && !isLeavingActiveMatch) {
    return;
  }

  if (isLeavingRoom) {
    const leavingLabel = getOwnerLabel(state.currentOwner) || state.profile.name || "A player";
    addSystemChat(`${leavingLabel} left and was removed from the room.`, { sync: false });
  }
  clearRoomAutoResolve();
  stopRoomDirectoryPolling();
  stopNextRoundCountdown();
  resetTimerDisplay();
  stopLoadingMessages();
  state.matchEnded = true;
  discardUnusedQuestionSetups();
  state.roomSessionId += 1;
  state.roomExitLeaveSent = true;
  const leavePromise = isLeavingRoom
    ? leavePublishedRoom({ reason: "manual" })
    : Promise.resolve(null);
  if (isLeavingRoom) {
    leavePromise.catch(() => null);
  }
  clearLocalRoomState({ clearHostedSession: true });
  clearRoomInviteUrlPath();

  setHidden(elements.gameStage, true);
  setHidden(elements.roomChat, true);
  setHidden(elements.roomLobbyScreen, true);
  setHidden(elements.roomScreen, true);
  setHidden(elements.joinScreen, true);
  elements.gameStage.classList.remove("room-active");
  setHidden(elements.modeScreen, false);
  playSound("click");
}

function animateRoomPlayerListChange(target, renderList) {
  if (!target || typeof renderList !== "function") {
    return;
  }
  if (target === elements.roomPlayerList) {
    renderList();
    return;
  }
  const reduceMotion = shouldReduceMotion();
  const panelIsVisible = target.isConnected && !target.closest(".hidden");
  const previousHeight = target.getBoundingClientRect().height;
  if (reduceMotion || !panelIsVisible || previousHeight <= 0) {
    renderList();
    return;
  }

  target.classList.add("room-player-list-resizing");
  target.style.height = `${previousHeight}px`;
  renderList();
  const previousInlineTransition = target.style.transition;
  target.style.transition = "none";
  target.style.height = "auto";
  const nextHeight = target.getBoundingClientRect().height;
  target.style.height = `${previousHeight}px`;
  target.offsetHeight;
  target.style.transition = previousInlineTransition;
  if (Math.abs(nextHeight - previousHeight) < 2) {
    target.classList.remove("room-player-list-resizing");
    target.style.height = "";
    return;
  }

  const resizeToken = `${Date.now()}-${Math.random()}`;
  target.dataset.resizingRoomList = resizeToken;
  window.requestAnimationFrame(() => {
    target.style.height = `${previousHeight}px`;
    window.requestAnimationFrame(() => {
      target.style.height = `${nextHeight}px`;
    });
  });

  const cleanup = (event) => {
    if (event.propertyName && event.propertyName !== "height") {
      return;
    }
    target.removeEventListener("transitionend", cleanup);
    if (target.dataset.resizingRoomList !== resizeToken) {
      return;
    }
    delete target.dataset.resizingRoomList;
    target.classList.remove("room-player-list-resizing");
    target.style.height = "";
  };
  target.addEventListener("transitionend", cleanup);
  window.setTimeout(() => cleanup({ propertyName: "height" }), 420);
}

function syncRoomPanelHeights() {
  const roomScreenVisible = elements.roomScreen && !elements.roomScreen.classList.contains("hidden");
  const settingsPanel = elements.roomScreen?.querySelector(".room-settings-panel");
  const previewPanel = elements.roomScreen?.querySelector(".room-preview");
  const playerList = elements.roomPlayerList;
  if (!roomScreenVisible || !settingsPanel || !previewPanel || !playerList) {
    if (previewPanel) {
      previewPanel.style.height = "";
    }
    if (playerList) {
      playerList.style.maxHeight = "";
    }
    return;
  }

  previewPanel.style.height = "";
  playerList.style.maxHeight = "";
  const settingsRect = settingsPanel.getBoundingClientRect();
  const previewRect = previewPanel.getBoundingClientRect();
  const listRect = playerList.getBoundingClientRect();
  const columnsAreSideBySide = Math.abs(settingsRect.top - previewRect.top) < 12
    && previewRect.left > settingsRect.left
    && previewRect.width > 0
    && settingsRect.width > 0;
  if (!columnsAreSideBySide) {
    return;
  }

  const previewStyle = window.getComputedStyle(previewPanel);
  const previewPaddingBottom = Number.parseFloat(previewStyle.paddingBottom) || 0;
  const listMaxHeight = Math.floor(settingsRect.bottom - listRect.top - previewPaddingBottom - 2);
  if (listMaxHeight < 140) {
    return;
  }
  previewPanel.style.height = `${Math.round(settingsRect.height)}px`;
  playerList.style.maxHeight = `${listMaxHeight}px`;
}

function scheduleRoomPanelHeightSync() {
  if (state.roomPanelHeightSyncFrame) {
    window.cancelAnimationFrame(state.roomPanelHeightSyncFrame);
  }
  state.roomPanelHeightSyncFrame = window.requestAnimationFrame(() => {
    state.roomPanelHeightSyncFrame = 0;
    syncRoomPanelHeights();
  });
}

function renderRoomPlayers() {
  animateRoomPlayerListChange(elements.roomPlayerList, () => renderRoomPlayerList(elements.roomPlayerList));
  animateRoomPlayerListChange(elements.roomLobbyPlayerList, () => renderRoomPlayerList(elements.roomLobbyPlayerList));
  scheduleRoomPanelHeightSync();
}

function createRoomModerationControls(owner, context = "list") {
  const player = getPlayer(owner);
  const controls = document.createElement("div");
  controls.className = context === "chat" ? "chat-options" : "room-player-controls";
  if (!player || !player.active || player.owner === state.currentOwner || player.bot || player.type === "bot") {
    return controls;
  }

  if (isCurrentHost()) {
    const muteButton = document.createElement("button");
    muteButton.type = "button";
    muteButton.className = "mini-button";
    muteButton.dataset.action = "mute";
    muteButton.dataset.owner = player.owner;
    muteButton.textContent = player.muted ? "Unmute" : "Mute";
    const banButton = document.createElement("button");
    banButton.type = "button";
    banButton.className = "mini-button danger-button";
    banButton.dataset.action = "ban";
    banButton.dataset.owner = player.owner;
    banButton.textContent = "Ban";
    controls.append(muteButton, banButton);
    return controls;
  }

  const voteButton = document.createElement("button");
  voteButton.type = "button";
  voteButton.className = "mini-button";
  voteButton.dataset.action = "vote-ban";
  voteButton.dataset.owner = player.owner;
  voteButton.textContent = "Vote ban";
  controls.appendChild(voteButton);
  return controls;
}

function renderRoomPlayerList(target) {
  if (!target) {
    return;
  }

  const maxPlayers = getRoomMaxPlayers();
  const isCreationPanel = target === elements.roomPlayerList;
  const isLobbyPanel = target === elements.roomLobbyPlayerList;
  const isRoomSetupList = isCreationPanel || isLobbyPanel;
  const hostProfileIsShown = isCreationPanel && !state.joiningRoom;
  const featuredHostId = (state.roomParticipants.find((participant) => participant.host)?.id
    || state.joiningRoom?.host?.id
    || state.hostedRooms.find((room) => room.code === state.roomSettings.code)?.host?.id
    || (!state.joiningRoom && isCurrentHost() ? state.clientId : ""));
  const participantPlayers = state.roomParticipants
    .filter((participant) => participant.active)
    .map((participant, index) => createPlayer(
      getRoomOwnerForParticipant(participant, index),
      participant.name,
      {
        avatar: participant.avatar,
        equippedTitleId: participant.equippedTitleId || "",
        specialBadges: normalizeSpecialBadges(participant.specialBadges || []),
        cardCustomization: participant.cardCustomization || null,
        participantId: participant.id,
        profileUserId: participant.profileUserId || "",
        connectionId: participant.connectionId || "",
        host: participant.host,
        spectator: participant.spectator,
        bot: Boolean(participant.bot),
        type: participant.bot ? "bot" : participant.spectator ? "spectator" : "human",
        active: participant.active,
        muted: participant.muted,
        connectionStatus: participant.status || (participant.host ? "host" : participant.bot ? "bot" : participant.spectator ? "spectating" : "joined")
      }
    ));
  const basePlayers = participantPlayers.length
    ? participantPlayers
    : state.mode === "room" && state.players.length
    ? state.players
    : [
      createPlayer("player", state.profile.name || "You", { avatar: state.profile.avatar, host: true, equippedTitleId: state.profile.equippedTitleId, specialBadges: state.profile.specialBadges, cardCustomization: state.profile.cardCustomization, connectionStatus: "host" })
    ];
  const activePlayers = basePlayers.filter((player) => player.active && !player.spectator);
  const visiblePlayers = activePlayers.filter((player) => {
    const isFeaturedHost = player.host
      || (featuredHostId && player.participantId === featuredHostId)
      || (player.participantId === state.clientId && isCurrentHost() && !state.joiningRoom)
      || String(player.connectionStatus || "").toLowerCase() === "host";
    if (isLobbyPanel && isFeaturedHost) {
      return false;
    }
    return !(hostProfileIsShown && player.owner === "player");
  });
  const openSlotCount = Math.max(0, maxPlayers - activePlayers.length);
  const openSlots = isRoomSetupList ? [] : Array.from({ length: openSlotCount }, (_, index) => {
    const slotNumber = activePlayers.length + index + 1;
    return createPlayer(`slot-${slotNumber}`, `Player ${slotNumber}`, {
      active: false,
      connectionStatus: "waiting"
    });
  });

  target.replaceChildren();
  if (isRoomSetupList && !visiblePlayers.length) {
    const empty = document.createElement("p");
    empty.className = "room-waiting-copy";
    empty.textContent = "Waiting for more players to join.";
    target.appendChild(empty);
    return;
  }
  [...visiblePlayers, ...openSlots].forEach((player) => {
    const card = document.createElement("div");
    card.className = "room-player-card";
    card.classList.toggle("waiting-slot", !player.active);
    const avatar = document.createElement("span");
    avatar.className = "room-player-avatar";
    renderAvatar(avatar, player);
    const name = document.createElement("strong");
    renderPlayerNameWithTitle(name, player, player.label);
    const status = document.createElement("small");
    status.textContent = player.bot || player.type === "bot"
      ? "BOT"
      : player.muted ? "muted" : player.connectionStatus || "ready";
    card.dataset.owner = player.owner;
    card.dataset.participantId = player.participantId || "";
    card.dataset.bot = String(Boolean(player.bot));
    applyPlayerCustomizationSurface(card, player);
    card.classList.toggle("kickable-bot", canKickRoomBot(player.owner, player.participantId));
    if (canKickRoomBot(player.owner, player.participantId)) {
      card.dataset.tooltip = "Click to kick this bot from the room.";
    }
    card.append(avatar, name, status);

    if (state.mode === "room" && player.owner !== state.currentOwner && player.active && !player.bot && player.type !== "bot") {
      const controls = createRoomModerationControls(player.owner);
      card.appendChild(controls);
    }
    target.appendChild(card);
  });
}

function publishRoomModeration(action, participantId, options = {}) {
  if (!isCurrentHost() || !state.roomSettings.code || state.roomSettings.code === "CAI-0000" || !participantId) {
    return Promise.resolve(null);
  }
  return fetchWithTimeout(`/api/rooms/${encodeURIComponent(state.roomSettings.code)}/moderation`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      action,
      participantId,
      hostParticipantId: state.clientId,
      muted: options.muted,
      reason: options.reason || ""
    })
  }, roomPresenceFetchTimeoutMs).then(async (response) => {
    if (!response.ok) {
      return null;
    }
    const data = await response.json();
    if (data.closed) {
      broadcastRealtimeRoomChange("room-closed", state.roomSettings.code, { reason: data.reason || action });
      return data;
    }
    updateRoomEventRevision(data.revision);
    applyRoomModerationDelta({ ...data, code: state.roomSettings.code, silent: true });
    broadcastRealtimeRoomChange("participant-moderated", state.roomSettings.code, data);
    return data;
  }).catch(() => null);
}

function muteRoomPlayer(owner) {
  if (!isRoomMode() || !isCurrentHost()) {
    return;
  }

  const player = getPlayer(owner);
  if (!player || player.owner === state.currentOwner) {
    return;
  }

  player.muted = !player.muted;
  player.connectionStatus = player.muted ? "muted" : "ready";
  addSystemChat(`${player.label} was ${player.muted ? "muted" : "unmuted"} by the host.`);
  if (player.participantId) {
    publishRoomModeration(player.muted ? "mute" : "unmute", player.participantId, { muted: player.muted });
  }
  renderRoomPlayers();
}

function banRoomPlayer(owner, reason = "banned by the host") {
  if (!isRoomMode()) {
    return;
  }

  const player = getPlayer(owner);
  if (!player || player.owner === "player") {
    return;
  }

  player.active = false;
  player.connectionStatus = "banned";
  const banList = getRoomBanList();
  if (!banList.includes(owner)) {
    banList.push(owner);
  }
  if (!banList.includes(player.label)) {
    banList.push(player.label);
  }
  state.roomSubmissions[owner] = true;
  addSystemChat(`${player.label} was kicked and cannot rejoin room ${state.roomSettings.code} (${reason}).`);
  if (isCurrentHost() && state.currentRoomStatus !== "draft") {
    if (player.participantId) {
      publishRoomModeration("ban", player.participantId, { reason });
    } else {
      upsertHostedRoom(state.currentRoomStatus === "in-progress" ? "in-progress" : "lobby");
    }
  }
  renderRoomPlayers();
  renderScore();
  renderSubmissionStatus();
}

function voteBanRoomPlayer(owner) {
  if (!isRoomMode()) {
    return;
  }

  const activeOwners = getActiveOwners();
  if (activeOwners.length < 3) {
    addSystemChat("Vote ban needs at least 3 active players.");
    return;
  }

  if (!state.roomModeration.voteBans[owner]) {
    state.roomModeration.voteBans[owner] = [];
  }
  const votes = state.roomModeration.voteBans[owner];
  if (!votes.includes(state.currentOwner)) {
    votes.push(state.currentOwner);
  }
  const needed = Math.floor(activeOwners.length / 2) + 1;
  addSystemChat(`${votes.length}/${needed} voted to kick ${getOwnerLabel(owner)}.`);
  if (votes.length >= needed) {
    banRoomPlayer(owner, "vote ban passed");
  }
}

function handleRoomPlayerAction(action, owner) {
  if (action === "mute") {
    muteRoomPlayer(owner);
  }
  if (action === "ban") {
    banRoomPlayer(owner);
  }
  if (action === "vote-ban") {
    voteBanRoomPlayer(owner);
  }
}

function startRoomGame() {
  updateRoomVariants({ publish: false });
  if (state.roomSettings.private && !state.roomSettings.password) {
    elements.roomPasswordInput.focus();
    return;
  }
  if (state.currentRoomStatus === "lobby") {
    upsertHostedRoom("lobby");
    setRoomInviteUrlPath(state.roomSettings.code);
    renderRoomLobby();
    setHidden(elements.roomScreen, true);
    setHidden(elements.roomLobbyScreen, false);
    playSound("click");
    return;
  }

  state.mode = "room";
  state.currentOwner = "player";
  state.joiningRoom = null;
  state.isSpectator = false;
  state.roomGame = null;
  resetRoomPowerSyncClocks();
  state.roomSessionId += 1;
  state.roomMissingSince = 0;
  state.roomClosedNotice = "";
  state.currentRoomStatus = "lobby";
  state.roomModeration.voteBans = {};
  if (!state.roomModeration.bannedByRoom[state.roomSettings.code]) {
    state.roomModeration.bannedByRoom[state.roomSettings.code] = [];
  }
  setPlayersForMode("room");
  state.roomChat = [];
  resetChatCooldown();
  addSystemChat(`Room ${state.roomSettings.code} created with ${getRoomVariantNames().join(" + ")} rules.`);
  upsertHostedRoom("lobby");
  openRoomLobby();
}

function renderRoomChat() {
  const active = isRoomMode();
  const inGameRoom = active && !elements.gameStage.classList.contains("hidden");
  setHidden(elements.roomChat, !inGameRoom);
  elements.gameStage.classList.toggle("room-active", inGameRoom);
  elements.gameStage.classList.toggle("spectator-mode", Boolean(active && state.isSpectator));
  elements.gameStage.classList.toggle("wild-fire-active", isMatchModifierEnabled("wildFire"));
  updateWildFireBurningState();
  renderSpectatorCountIndicator();
  if (!active) {
    return;
  }

  elements.roomCodeLabel.textContent = state.roomSettings.code;
  renderModifierIconLabel(elements.roomVariantLabel);
  elements.lobbyRoomCodeLabel.textContent = state.roomSettings.code;
  renderModifierIconLabel(elements.lobbyRoomVariantLabel);
  renderChatLog(elements.chatLog);
  renderChatLog(elements.lobbyChatLog);
}

function renderChatLog(target) {
  if (!target) {
    return;
  }

  const existingNodes = new Map(
    [...target.querySelectorAll(".chat-message[data-chat-key]")]
      .map((node) => [node.dataset.chatKey, node])
  );
  const wasNearBottom = target.scrollTop + target.clientHeight >= target.scrollHeight - 12;
  const fragment = document.createDocumentFragment();
  state.roomChat.forEach((message) => {
    const chatKey = getRoomChatMessageKey(message);
    const existing = existingNodes.get(chatKey);
    const item = existing || document.createElement("div");
    const isNew = !existing;
    item.className = "chat-message";
    item.dataset.chatKey = chatKey;
    item.classList.toggle("own-message", Boolean(message.own));
    item.classList.toggle("system-message", message.sender === "System");
    item.classList.toggle("private-message", Boolean(message.private));
    item.classList.toggle("host-message", Boolean(message.host));
    item.classList.toggle("spectator-message", Boolean(message.spectator));
    if (message.owner && message.sender !== "System") {
      item.dataset.chatOwner = message.owner;
      item.classList.add("clickable-profile");
    } else {
      delete item.dataset.chatOwner;
      item.classList.remove("clickable-profile");
    }
    if (isNew) {
      item.classList.add("chat-message-new");
      const avatar = document.createElement("span");
      avatar.className = "chat-avatar";
      renderAvatar(avatar, {
        label: message.sender,
        avatar: message.avatar || ""
      });
      const sender = document.createElement("strong");
      if (message.sender === "System") {
        sender.textContent = message.sender;
      } else {
        renderPlayerNameWithTitle(sender, {
          owner: message.owner || "",
          label: message.sender,
          host: Boolean(message.host),
          spectator: Boolean(message.spectator),
          equippedTitleId: message.equippedTitleId || "",
          specialBadges: message.specialBadges || [],
          cardCustomization: message.cardCustomization || null
        }, message.sender);
      }
      const text = document.createElement("span");
      text.textContent = message.text;
      item.append(avatar, sender, text);
    }
    fragment.appendChild(item);
  });
  target.replaceChildren(fragment);
  target.querySelectorAll(".chat-message-new").forEach((item) => {
    window.setTimeout(() => item.classList.remove("chat-message-new"), 420);
  });
  if (wasNearBottom) {
    target.scrollTop = target.scrollHeight;
  }
}

function toggleChatOptions(messageNode, owner) {
  document.querySelectorAll(".chat-options").forEach((menu) => {
    if (!messageNode.contains(menu)) {
      menu.remove();
    }
  });

  if (!owner || owner === state.currentOwner || !getPlayer(owner)) {
    return;
  }

  const existing = messageNode.querySelector(".chat-options");
  if (existing) {
    existing.remove();
    return;
  }

  const controls = createRoomModerationControls(owner, "chat");
  if (controls.childElementCount) {
    messageNode.appendChild(controls);
  }
}

function sendChatMessage(text, input = elements.chatInput) {
  const cleaned = cleanChatInput(text);
  if (!cleaned) {
    return;
  }
  const sender = getPlayer(state.currentOwner);
  if (sender?.muted) {
    addSystemChat("You are muted and cannot send chat messages.", { private: true });
    input.value = "";
    return;
  }
  if (!canSendClientChatMessage()) {
    showLocalChatCooldownNotice(input);
    playSound("error");
    return;
  }

  const message = pushRoomChatMessage({
    sender: state.profile.name || "Host",
    avatar: getRoomSyncAvatar(state.profile.avatar),
    equippedTitleId: state.profile.equippedTitleId || "",
    specialBadges: getRoomSyncSpecialBadges(),
    cardCustomization: getRoomSyncCardCustomization(state.profile.cardCustomization),
    text: cleaned,
    owner: state.currentOwner,
    own: true,
    host: isCurrentHost(),
    spectator: Boolean(state.isSpectator),
    createdAt: Date.now()
  });
  const chatStat = getAchievementStat(state.currentOwner);
  if (chatStat) {
    chatStat.chatMessages += 1;
  }
  input.value = "";
  renderRoomChat();
  publishRoomChat(message);
  playSound("click");
}

function openSettings() {
  setHidden(elements.settingsModal, false);
  syncSettingsControls();
  playSound("click");
}

function closeSettings() {
  hideModalWithMotion(elements.settingsModal);
  playSound("click");
}

function isModalOpen(element) {
  return element && !element.classList.contains("hidden");
}

function closeTopModal() {
  if (isModalOpen(elements.targetModal)) {
    cancelTargetSelector();
    return true;
  }

  if (isModalOpen(elements.confirmEndModal)) {
    closeEndConfirm();
    return true;
  }

  if (isModalOpen(elements.abilitiesModal)) {
    closeAbilities();
    return true;
  }

  if (isModalOpen(elements.achievementsModal)) {
    closeAchievements();
    return true;
  }

  if (isModalOpen(elements.roundHelpModal)) {
    hideModalWithMotion(elements.roundHelpModal);
    return true;
  }

  if (isModalOpen(elements.profileCustomModal)) {
    closeProfileCustomization();
    return true;
  }

  if (isModalOpen(elements.profileShopModal)) {
    closeProfileShop();
    return true;
  }

  if (isModalOpen(elements.themeModal)) {
    closeThemeSelector();
    return true;
  }

  if (isModalOpen(elements.botAdvancedModal)) {
    closeBotAdvancedPanel();
    return true;
  }

  if (isModalOpen(elements.settingsModal)) {
    closeSettings();
    return true;
  }

  return false;
}

function closeOverlayMenus() {
  setHidden(elements.targetModal, true);
  if (isModalOpen(elements.confirmEndModal) || state.pendingConfirmResolver) {
    closeEndConfirm(false, { silent: true });
  } else {
    setHidden(elements.confirmEndModal, true);
  }
  setHidden(elements.abilitiesModal, true);
  setHidden(elements.profileCustomModal, true);
  setHidden(elements.profileShopModal, true);
  setHidden(elements.themeModal, true);
  setHidden(elements.settingsModal, true);
}

function syncSettingsControls() {
  elements.sfxVolumeSlider.value = Math.round(soundState.sfxVolume * 100);
  elements.musicVolumeSlider.value = Math.round(soundState.musicVolume * 100);
  elements.timerSecondsSlider.value = state.timerSeconds;
  elements.roundsSlider.value = state.maxRounds;
  if (elements.performanceModeSelect) {
    elements.performanceModeSelect.value = state.performanceMode;
  }
  elements.sfxVolumeValue.textContent = `${elements.sfxVolumeSlider.value}`;
  elements.musicVolumeValue.textContent = `${elements.musicVolumeSlider.value}`;
  elements.timerSecondsValue.textContent = `${state.timerSeconds}s`;
  elements.roundsValue.textContent = `${state.maxRounds}`;
  if (elements.performanceModeValue) {
    elements.performanceModeValue.textContent = performanceModes[state.performanceMode]?.shortLabel || "Full";
  }
}

function updateSfxVolume(value) {
  soundState.sfxVolume = Number(value) / 100;
  localStorage.setItem("cardsAgainstAiSfxVolume", String(value));
  cacheUserStorageSnapshotNow();
  scheduleUserStorageSnapshot();
  elements.sfxVolumeValue.textContent = `${value}`;
  playSound("click");
}

function updateMusicSetting(value) {
  soundState.musicVolume = Number(value) / 100;
  localStorage.setItem("cardsAgainstAiMusicVolume", String(value));
  cacheUserStorageSnapshotNow();
  scheduleUserStorageSnapshot();
  elements.musicVolumeValue.textContent = `${value}`;
  updateMusicVolume();
}

function updateTimerSetting(value) {
  state.timerSeconds = Number(value);
  localStorage.setItem("cardsAgainstAiTimerSeconds", String(state.timerSeconds));
  cacheUserStorageSnapshotNow();
  scheduleUserStorageSnapshot();
  elements.timerSecondsValue.textContent = `${state.timerSeconds}s`;
  if (!elements.inputPanel.classList.contains("hidden")) {
    startTimer();
  } else {
    state.timerRemaining = state.timerSeconds;
    renderTimer();
  }
}

function updateRoundsSetting(value) {
  const requestedRounds = Math.min(10, Math.max(1, Number(value) || 5));
  const activeGame = !elements.gameStage.classList.contains("hidden") && !state.matchEnded;
  state.maxRounds = activeGame ? Math.max(requestedRounds, state.round) : requestedRounds;
  localStorage.setItem("cardsAgainstAiMaxRounds", String(requestedRounds));
  cacheUserStorageSnapshotNow();
  scheduleUserStorageSnapshot();
  elements.roundsSlider.value = state.maxRounds;
  elements.roundsValue.textContent = `${state.maxRounds}`;
  updateModeUi();
  renderScore();
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function stopNextRoundCountdown() {
  if (state.nextRoundAutoTimerId) {
    clearInterval(state.nextRoundAutoTimerId);
    state.nextRoundAutoTimerId = null;
  }
}

function canAdvanceVerdict() {
  return !isRoomMode() || isCurrentHost();
}

function updateNextRoundButtonLabel() {
  const base = state.round >= state.maxRounds ? "Show Results" : "Next Round";
  const canAdvance = canAdvanceVerdict();
  elements.nextRoundButton.classList.toggle("waiting-for-host", !canAdvance);
  if (!canAdvance) {
    elements.nextRoundButton.textContent = state.nextRoundCountdown > 0
      ? `Waiting for host (${state.nextRoundCountdown}s)`
      : "Waiting for host";
    elements.nextRoundButton.disabled = false;
    elements.nextRoundButton.setAttribute("aria-disabled", "true");
    setButtonHint(elements.nextRoundButton, "Only the host can advance to the next question.");
    return;
  }
  elements.nextRoundButton.textContent = state.nextRoundCountdown > 0
    ? `${base} (${state.nextRoundCountdown}s)`
    : base;
  elements.nextRoundButton.removeAttribute("aria-disabled");
  setButtonHint(elements.nextRoundButton, "");
}

function startNextRoundCountdown() {
  stopNextRoundCountdown();
  if (isRoomMode() && state.roomSettings.autoAdvance === false) {
    state.nextRoundCountdown = 0;
    updateNextRoundButtonLabel();
    return;
  }
  const syncedDeadline = isRoomMode()
    ? Math.max(0, Number(getRoomRoundResultForCurrentRound()?.nextRoundAt) || 0)
    : 0;
  const getRemainingSeconds = () => syncedDeadline
    ? Math.max(0, Math.ceil((syncedDeadline - Date.now()) / 1000))
    : state.nextRoundCountdown - 1;
  state.nextRoundCountdown = syncedDeadline ? getRemainingSeconds() : 30;
  updateNextRoundButtonLabel();
  state.nextRoundAutoTimerId = setInterval(() => {
    state.nextRoundCountdown = getRemainingSeconds();
    updateNextRoundButtonLabel();
    if (state.nextRoundCountdown <= 0) {
      stopNextRoundCountdown();
      if (canAdvanceVerdict()) {
        advanceAfterVerdict();
      }
    }
  }, 1000);
}

function advanceAfterVerdict() {
  if (!canAdvanceVerdict()) {
    updateNextRoundButtonLabel();
    return;
  }
  stopNextRoundCountdown();
  closeOverlayMenus();
  if (state.round >= state.maxRounds) {
    endMatch();
    return;
  }

  state.round += 1;
  publishRoomRoundAdvancing(state.round);
  newRound();
}

function completeBlackCard(answer) {
  return buildBlackCardAnswerReveal(answer);
}

function scoreAnswerAgainstAcceptedAnswers(answer, acceptedAnswers) {
  const normalized = normalizeTriviaAnswer(answer);
  const accepted = acceptedAnswers.map(normalizeTriviaAnswer).filter(Boolean);
  if (!normalized || !accepted.length) {
    return 0;
  }
  if (accepted.includes(normalized)) {
    return 1;
  }
  if (accepted.some((target) => isMessyTriviaTypo(normalized, target))) {
    return 0.84;
  }
  const bestDistance = Math.min(...accepted.map((target) => levenshteinDistance(normalized, target)));
  const longest = Math.max(normalized.length, ...accepted.map((target) => target.length), 1);
  return 1 - (bestDistance / longest);
}

function getTriviaAnswerAcronym(value) {
  return normalizeTriviaAnswer(value)
    .split(" ")
    .filter(Boolean)
    .map((word) => word[0])
    .join("");
}

function compactNormalizedTriviaAnswer(value) {
  return normalizeTriviaAnswer(value).replace(/\s+/g, "");
}

function getGradingSimilarityDetails(answer, acceptedAnswers = []) {
  const normalized = normalizeTriviaAnswer(answer);
  const accepted = acceptedAnswers.map(normalizeTriviaAnswer).filter(Boolean);
  if (!normalized) {
    return { kind: "blank", score: 0 };
  }
  if (!accepted.length) {
    return { kind: "ai", score: 0 };
  }
  if (accepted.includes(normalized)) {
    return { kind: "exact", score: 1 };
  }
  const compactNormalized = compactNormalizedTriviaAnswer(answer);
  if (compactNormalized && accepted.some((target) => compactNormalized === target.replace(/\s+/g, ""))) {
    return { kind: "formatting", score: 0.98 };
  }
  if (accepted.some((target) => normalized === getTriviaAnswerAcronym(target) || getTriviaAnswerAcronym(normalized) === target)) {
    return { kind: "abbreviation", score: 0.95 };
  }
  if (accepted.some((target) => isLooseTriviaPhoneticMatch(normalized, target))) {
    return { kind: "phonetic", score: 0.84 };
  }
  if (accepted.some((target) => isMessyTriviaTypo(normalized, target))) {
    return { kind: "typo", score: 0.84 };
  }
  const contained = accepted.some((target) => target.length >= 5 && (normalized.includes(target) || target.includes(normalized)));
  if (contained) {
    return { kind: "partial", score: 0.86 };
  }
  const bestDistance = Math.min(...accepted.map((target) => levenshteinDistance(normalized, target)));
  const longest = Math.max(normalized.length, ...accepted.map((target) => target.length), 1);
  const score = 1 - (bestDistance / longest);
  return { kind: "similarity", score };
}

function getAnswerGradingReason(answer, rating = {}, roundResult = {}, index = -1) {
  if (isMultipleChoiceRound()) {
    return rating.correct ? "Nice, that was the right option." : "Not this time, that option was not the right one.";
  }
  const aiRescued = Array.isArray(roundResult.aiSecondOpinionIndexes) && roundResult.aiSecondOpinionIndexes.includes(index);
  const aiReviewed = Array.isArray(roundResult.aiReviewedIndexes) && roundResult.aiReviewedIndexes.includes(index);
  const details = getGradingSimilarityDetails(answer, [state.canonicalAnswer, ...state.acceptedAnswers].filter(Boolean));
  if (details.kind === "blank") {
    return "No answer was submitted.";
  }
  if (rating.correct) {
    if (aiRescued) {
      return "A second look counted this as what you meant.";
    }
    if (details.kind === "exact") {
      return "That matches the answer.";
    }
    if (details.kind === "abbreviation") {
      return "That short version is clear enough.";
    }
    if (details.kind === "formatting") {
      return "That matches the answer with different spacing or punctuation.";
    }
    if (details.kind === "phonetic") {
      return "That sounds close enough to the right answer.";
    }
    if (details.kind === "typo") {
      return "That looks like the right answer with a spelling slip.";
    }
    if (details.kind === "partial") {
      return "That gives enough of the answer to count.";
    }
    return "Close enough: it points to the right answer.";
  }
  if (aiReviewed) {
    return "A second look still could not tie it clearly to the answer.";
  }
  if (details.score >= 0.72) {
    return "Close, but not clear enough to count.";
  }
  return "That looks like a different answer.";
}

function getRoundGradingReasons(cards = [], ratings = [], roundResult = {}) {
  return cards.map((card, index) => getAnswerGradingReason(card, ratings[index] || {}, roundResult, index));
}

function buildBlackCardAnswerReveal(bestAnswer, options = {}) {
  const showBestAnswer = options.showBestAnswer !== false;
  const lines = [state.blackCard];
  if (showBestAnswer) {
    lines.push("", `Best Answer: ${bestAnswer || "No accepted answer"}`);
  }
  if (lines.length === 1) {
    lines.push("");
  }
  lines.push(`Correct Answer: ${state.canonicalAnswer || state.acceptedAnswers[0] || "Unknown"}`);
  return lines.join("\n");
}

function getBestAnswerIndexForReveal(cards, correctIndexes = [], preferredIndex = 0) {
  if (correctIndexes.includes(preferredIndex)) {
    return preferredIndex;
  }
  if (correctIndexes.length) {
    return correctIndexes[0];
  }
  const accepted = [state.canonicalAnswer, ...state.acceptedAnswers].filter(Boolean);
  if (!accepted.length) {
    return preferredIndex;
  }
  return cards
    .map((card, index) => ({ index, score: scoreAnswerAgainstAcceptedAnswers(card, accepted) }))
    .sort((a, b) => b.score - a.score || a.index - b.index)[0]?.index ?? preferredIndex;
}

async function animateWinnerToBlackCard(winnerIndex, answer, options = {}) {
  const cardNodes = getAnswerCardNodes();
  const winnerCard = cardNodes.find((card) => Number(card.dataset.cardIndex) === winnerIndex) || cardNodes[0];
  const blackCard = elements.blackCardText.closest(".black-card");
  const completedText = completeBlackCard(answer);
  const winnerOwner = options.owner || getOwnerFromCardIndex(winnerIndex);
  const customization = options.cardCustomization || null;

  if (!winnerCard || !blackCard || !Element.prototype.animate || shouldReduceMotion()) {
    applyBlackCardCustomizationForOwner(winnerOwner, customization);
    void blackCard.offsetWidth;
    await revealBlackCardAnswer(completedText);
    return;
  }

  const sourceRect = winnerCard.getBoundingClientRect();
  const targetRect = blackCard.getBoundingClientRect();
  const clone = winnerCard.cloneNode(true);
  clone.classList.add("flying-card");
  clone.style.left = `${sourceRect.left}px`;
  clone.style.top = `${sourceRect.top}px`;
  clone.style.width = `${sourceRect.width}px`;
  clone.style.height = `${sourceRect.height}px`;
  winnerCard.classList.add("launching");
  document.body.appendChild(clone);

  const sourceCenterX = sourceRect.left + sourceRect.width / 2;
  const sourceCenterY = sourceRect.top + sourceRect.height / 2;
  const targetCenterX = targetRect.left + targetRect.width / 2;
  const targetCenterY = targetRect.top + targetRect.height / 2;

  await clone.animate(
    [
      {
        transform: "translate(0, 0) scale(1) rotate(0deg)",
        opacity: 1
      },
      {
        transform: `translate(${targetCenterX - sourceCenterX}px, ${targetCenterY - sourceCenterY}px) scale(0.52) rotate(-4deg)`,
        opacity: 0.94
      }
    ],
    {
      duration: 780,
      easing: "cubic-bezier(0.2, 0.9, 0.2, 1)",
      fill: "forwards"
    }
  ).finished;

  clone.remove();
  winnerCard.classList.remove("launching");
  applyBlackCardCustomizationForOwner(winnerOwner, customization);
  void blackCard.offsetWidth;
  await revealBlackCardAnswer(completedText);
}

async function revealBlackCardAnswer(completedText) {
  const blackCard = elements.blackCardText.closest(".black-card");
  if (!blackCard) {
    elements.blackCardText.textContent = completedText;
    return;
  }

  const reduceMotion = shouldReduceMotion();
  const canAnimateHeight = Boolean(Element.prototype.animate) && !reduceMotion;

  if (!canAnimateHeight) {
    elements.blackCardText.textContent = completedText;
    blackCard.classList.add("completed");
    return;
  }

  const beforeHeight = blackCard.getBoundingClientRect().height;
  blackCard.style.height = `${beforeHeight}px`;
  blackCard.style.overflow = "hidden";
  elements.blackCardText.textContent = completedText;
  blackCard.classList.add("completed");
  restartAnimation(blackCard, "answer-reveal");

  const animation = animateBlackCardToNaturalHeight(blackCard, beforeHeight, { allowShrink: false, durationMs: 560 });

  try {
    await animation?.finished;
  } finally {
    resetBlackCardSizing();
  }
}

function submitRoomAnswer(rawInput, options = {}) {
  if (!isRoomMode() || state.isSpectator || state.roomSubmissions[state.currentOwner]) {
    return;
  }

  const owner = state.currentOwner;
  const lockedInput = lockRoundAnswer(owner, rawInput);
  if (isPublicNonSelfHostedRoom() && normalizeTriviaAnswer(lockedInput) === "i am a cute femboy") {
    incrementAchievementProgress(owner, "femboyAnswer");
  }
  if (!lockedInput && !options.allowBlank) {
    elements.answerInput.focus();
    return;
  }
  commitActivePowerUp(owner);
  state.answerRemainingTimes[owner] = state.timerRemaining;
  if (!options.timedOut) {
    markAchievementLateSubmission(owner, state.timerRemaining);
  }
  stopTimer();
  if (owner === "opponent") {
    state.localAnswers.playerTwo = lockedInput;
    state.localAnswers.playerOne = shouldAutoGenerateRoomAnswer("player")
      ? lockRoundAnswer("player", generateAutoAnswer("player"))
      : getLockedRoundAnswer("player");
  } else if (owner === "player") {
    state.localAnswers.playerOne = lockedInput;
    state.localAnswers.playerTwo = shouldAutoGenerateRoomAnswer("opponent")
      ? lockRoundAnswer("opponent", generateAutoAnswer("opponent"))
      : getLockedRoundAnswer("opponent");
  }

  setRoomSubmission(owner, true);
  rememberLocalRoomSubmission(owner, lockedInput, state.answerRemainingTimes[owner]);
  broadcastRoomAnswerSubmission(lockedInput);
  void publishCurrentRoomSubmission(lockedInput);
  maybeSubmitRoomBotsAfterRealPlayers();
  elements.answerInput.disabled = true;
  elements.submitButton.disabled = true;
  renderMultipleChoiceOptions();
  document.querySelector("#inputTitle").textContent = hasPendingTimeBenderSubmitter()
    ? "Waiting for Time Bender bonus time..."
    : "Waiting for the other player...";
  playSound("lock");
  clearRoomAutoResolve();
  void waitForRoomSubmissionsThenPlay(lockedInput);
}

function submitBotModeAnswer(rawInput, options = {}) {
  if (state.mode !== "bots" || state.roomSubmissions.player || state.matchEnded) {
    return;
  }

  const lockedInput = lockRoundAnswer("player", rawInput);
  if (!lockedInput && !options.allowBlank) {
    elements.answerInput.focus();
    return;
  }
  commitActivePowerUp("player");
  state.answerRemainingTimes.player = Math.max(0, Number(state.timerRemaining) || 0);
  if (!options.timedOut) {
    markAchievementLateSubmission("player", state.timerRemaining);
  }
  state.localAnswers.playerOne = lockedInput;
  setRoomSubmission("player", true);
  elements.answerInput.disabled = true;
  elements.submitButton.disabled = true;
  renderMultipleChoiceOptions();
  document.querySelector("#inputTitle").textContent = "Waiting for bots...";
  playSound("lock");
  commitScheduledRoomBotAnswers({ force: true });
  maybeResolveBotSubmissions();
}

function getRoundAnswerForOwner(owner) {
  const locked = getLockedRoundAnswer(owner);
  if (locked) {
    return locked;
  }
  if (shouldAutoGenerateRoomAnswer(owner)) {
    return lockRoundAnswer(owner, generateAutoAnswer(owner));
  }
  if (isRoomMode() && getActiveOwners().includes(owner)) {
    return "";
  }
  if (state.mode === "bots" && isBotOwner(owner)) {
    const index = getActiveBotOwners().indexOf(owner);
    return cleanInput(state.botCards[index] || "");
  }
  if (owner === "opponent") {
    return getLockedRoundAnswer("opponent", state.localAnswers.playerTwo);
  }
  return getLockedRoundAnswer("player", state.localAnswers.playerOne);
}

function applyCheatSheetPowers() {
  getPlayedPowerEntries()
    .filter((entry) => entry.power.type === "cheat_sheet")
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      const copiedAnswer = getRoundAnswerForOwner(target);
      if (target && copiedAnswer) {
        lockRoundAnswer(entry.owner, copiedAnswer);
        if (entry.owner === "player") {
          state.localAnswers.playerOne = copiedAnswer;
        }
        if (entry.owner === "opponent") {
          state.localAnswers.playerTwo = copiedAnswer;
        }
      }
    });
}

async function playRound(rawInput, options = {}) {
  const matchToken = state.matchWorkToken;
  if (!isCurrentMatchWork(matchToken)) {
    state.roomRoundResolving = false;
    return;
  }
  const syncedRoundResult = options.roundResult ? normalizeRoomRoundResultPayload(options.roundResult) : null;
  if (isRoomMode() && (!isCurrentHost() || state.joiningRoom) && !syncedRoundResult) {
    if (!state.roomRoundResolving) {
      state.roomRoundResolving = true;
    }
    showWaitingForRoomRoundResult();
    void waitForRoomRoundResultThenPlay(rawInput, matchToken);
    return;
  }
  clearRoomAutoResolve();
  applyCheatSheetPowers();
  resetTimerDisplay();
  elements.answerInput.disabled = true;
  elements.playerTwoInput.disabled = true;
  elements.submitButton.disabled = true;
  animateTableLayoutChange(() => {
    setHidden(elements.inputPanel, true);
    setHidden(elements.answerProgressPanel, true);
    setHidden(elements.powerPanel, true);
    setHidden(elements.effectPanel, true);
    setHidden(elements.errorPanel, true);
    setHidden(elements.loadingPanel, false);
  });
  startLoadingMessages("round", isMultipleChoiceRound() ? "Checking the selected options..." : `${state.judge.name} is checking the answers...`);
  playSound("submit");

  let roundResult;
  if (syncedRoundResult) {
    roundResult = syncedRoundResult;
  } else if (isMultipleChoiceRound()) {
    roundResult = createMultipleChoiceRoundResult(rawInput);
  } else if (state.roundRequestAbortController) {
    state.roundRequestAbortController.abort();
  }
  if (!roundResult) {
    const roundAbortController = new AbortController();
    state.roundRequestAbortController = roundAbortController;
    try {
      setGradingActive(true);
      try {
        roundResult = await requestAiRound(rawInput, { signal: roundAbortController.signal });
      } finally {
        setGradingActive(false);
        if (state.roundRequestAbortController === roundAbortController) {
          state.roundRequestAbortController = null;
        }
      }
      if (!isCurrentMatchWork(matchToken)) {
        state.roomRoundResolving = false;
        return;
      }
    } catch (error) {
      if (isAbortError(error) || !isCurrentMatchWork(matchToken)) {
        state.roomRoundResolving = false;
        return;
      }
      console.warn(error);
      playSound("error");
      stopLoadingMessages();
      elements.errorText.textContent = `${error.message} Start the server with npm start and make sure your model settings are valid.`;
      elements.answerInput.disabled = false;
      elements.submitButton.disabled = false;
      renderMultipleChoiceOptions();
      animateTableLayoutChange(() => {
        setHidden(elements.inputPanel, true);
        setHidden(elements.answerProgressPanel, true);
        setHidden(elements.powerPanel, true);
        setHidden(elements.effectPanel, true);
        setHidden(elements.cardsArea, true);
        setHidden(elements.roomSubmitStatus, true);
        setHidden(elements.loadingPanel, true);
        setHidden(elements.errorPanel, false);
      });
      state.roomRoundResolving = false;
      return;
    }
  }

  if (!isCurrentMatchWork(matchToken)) {
    state.roomRoundResolving = false;
    return;
  }
  const cardRatings = getCardRatings(roundResult.cards, roundResult.winner.index, roundResult.correctIndexes);
  state.currentRoundCards = roundResult.cards;
  state.currentRoundCardRatings = cardRatings;
  state.currentRoundCorrectIndexes = roundResult.correctIndexes;
  state.currentRoundGradingReasons = getRoundGradingReasons(roundResult.cards, cardRatings, roundResult);
  if (syncedRoundResult?.damagedParticipantIds?.length) {
    applyDamagedAnswerParticipantIds(syncedRoundResult.damagedParticipantIds);
  }
  clearCardBadges();
  renderAnswerCardLayout(roundResult.cards, roundResult.correctIndexes, roundResult.winner.index);
  fillVisibleAnswerCards(roundResult.cards, cardRatings);
  stopLoadingMessages();
  animateTableLayoutChange(() => {
    setHidden(elements.loadingPanel, true);
    setHidden(elements.cardsArea, false);
    setHidden(elements.effectPanel, true);
  });
  restartAnimation(elements.cardsArea, "revealed");
  playSound("reveal");

  await sleep(450);
  if (!isCurrentMatchWork(matchToken)) {
    state.roomRoundResolving = false;
    return;
  }
  animateTableLayoutChange(() => {
    setHidden(elements.loadingPanel, false);
  });
  startLoadingMessages("judge", "Preparing the answer review...");
  playSound("judge");
  await sleep(850);
  if (!isCurrentMatchWork(matchToken)) {
    state.roomRoundResolving = false;
    return;
  }

  const forcedWinnerOwner = getForcedWinnerOwner();
  const forcedLoserOwner = getForcedLoserOwner();
  const winner = forcedWinnerOwner
    ? { ...roundResult.winner, index: getCardIndexFromOwner(forcedWinnerOwner) }
    : roundResult.winner;
  const winnerOwner = getOwnerFromCardIndex(winner.index);
  const correctIndexes = roundResult.correctIndexes;
  const revealAnswerIndex = Number.isInteger(Number(roundResult.revealAnswerIndex))
    ? clampNumber(roundResult.revealAnswerIndex, 0, Math.max(roundResult.cards.length - 1, 0), winner.index)
    : getBestAnswerIndexForReveal(roundResult.cards, correctIndexes, winner.index);
  const revealAnswer = roundResult.cards[revealAnswerIndex] || roundResult.cards[winner.index] || "No answer";
  const revealOwner = syncedRoundResult?.revealParticipantId
    ? getOwnerFromRoomRoundParticipantId(syncedRoundResult.revealParticipantId, revealAnswerIndex)
    : getOwnerFromCardIndex(revealAnswerIndex);
  const revealCustomization = syncedRoundResult?.cardCustomization || null;
  let winningOwners = getUniqueOwnersFromCardIndexes(correctIndexes);
  if (forcedWinnerOwner && !winningOwners.includes(forcedWinnerOwner)) {
    winningOwners = [forcedWinnerOwner, ...winningOwners];
  }
  if (forcedLoserOwner) {
    winningOwners = winningOwners.filter((candidate) => candidate !== forcedLoserOwner);
  }
  if (syncedRoundResult?.winningParticipantIds?.length) {
    winningOwners = syncedRoundResult.winningParticipantIds
      .map((participantId) => getOwnerFromRoomRoundParticipantId(participantId))
      .filter((owner) => owner && getActiveOwners().includes(owner));
  }
  const hasCorrectAnswer = winningOwners.length > 0;
  const progressOwner = isRoomMode() ? state.currentOwner : "player";
  const shouldTrackCurrentProgress = progressOwner !== "spectator";
  const focusedAnswerCorrect = shouldTrackCurrentProgress && correctIndexes.includes(getCardIndexFromOwner(progressOwner));
  if (shouldTrackCurrentProgress) {
    setCurrentQuestionProgress(focusedAnswerCorrect);
  }
  const ratingsByOwner = getCardRatingsByOwner(cardRatings);
  const winningRating = cardRatings[winner.index] || { label: "Correct", bonus: 50 };
  let awarded;
  if (syncedRoundResult?.awarded) {
    awarded = syncedRoundResult.awarded;
    const syncedPowerState = syncedRoundResult.powerState || (syncedRoundResult.scoreState.length ? {
      updatedAt: syncedRoundResult.updatedAt,
      players: syncedRoundResult.scoreState
    } : null);
    if (syncedPowerState) {
      applyRoomPowerState({
        code: state.roomSettings.code,
        round: state.round,
        updatedAt: syncedPowerState.updatedAt || syncedRoundResult.updatedAt,
        hands: syncedPowerState.hands,
        played: syncedPowerState.played,
        players: syncedPowerState.players,
        effects: syncedPowerState.effects
      });
    }
  } else {
    awarded = hasCorrectAnswer
      ? awardPoints(winnerOwner, winningRating, winningOwners, ratingsByOwner)
      : createNoCorrectAward();
  }
  decorateAwardWithAnswerDamage(awarded);
  awardRoundCoins(winningOwners, awarded);
  recordRoundResult(winnerOwner, awarded, roundResult.cards[winner.index], winningOwners);
  renderScore();
  animateScorePop(winnerOwner, awarded);
  if (isRoomMode() && isCurrentHost() && !state.joiningRoom && !syncedRoundResult) {
    void publishRoomRoundResult(roundResult, {
      winnerIndex: winner.index,
      revealAnswerIndex,
      winningParticipantIds: winningOwners.map(getRoomParticipantIdForOwner).filter(Boolean),
      damagedParticipantIds: awarded.damagedParticipantIds || getDamagedAnswerParticipantIds(),
      awarded
    });
    void publishRoomScoreState("round-score");
  }
  if (progressOwner !== "spectator") {
    playSound(focusedAnswerCorrect ? "correctAnswer" : "wrongAnswer");
  }
  if (!awarded.noPoints) {
    triggerStreakFire();
  }

  renderCardBadges(roundResult.cards, winner.index, cardRatings);
  correctIndexes.forEach((index) => {
    const card = getAnswerCardNodes().find((node) => Number(node.dataset.cardIndex) === index);
    if (card) {
      card.classList.add("answer-priority");
    }
  });
  if (hasCorrectAnswer) {
    restartAnimation(document.querySelector(".table-surface"), "winner-moment");
  }
  elements.winnerText.textContent = "";
  renderPowerLog(awarded);
  renderRoundRecap(awarded, winnerOwner, winningRating);
  resetReactionPanel();
  elements.nextRoundButton.disabled = true;
  state.nextRoundCountdown = 0;
  updateNextRoundButtonLabel();
  animateTableLayoutChange(() => {
    setHidden(elements.loadingPanel, true);
    setHidden(elements.answerProgressPanel, true);
  });
  stopLoadingMessages();
  if (hasCorrectAnswer) {
    playSound("fly");
    await animateWinnerToBlackCard(revealAnswerIndex, revealAnswer, {
      owner: revealOwner,
      cardCustomization: revealCustomization
    });
  } else {
    await revealBlackCardAnswer(buildBlackCardAnswerReveal("", { showBestAnswer: false }));
  }
  if (!isCurrentMatchWork(matchToken)) {
    state.roomRoundResolving = false;
    return;
  }
  animateTableLayoutChange(() => {
    setHidden(elements.verdictPanel, false);
  });
  restartAnimation(elements.verdictPanel, "revealed");
  elements.nextRoundButton.disabled = false;
  startNextRoundCountdown();
  state.roomRoundResolving = false;
}

function getOwnerLabel(owner) {
  const player = getPlayer(owner);
  if (!player) {
    return owner;
  }
  return player.label;
}

function getOwnerFromCardIndex(index) {
  const roundOwners = getRoundCardOwners();
  if (roundOwners[index]) {
    return roundOwners[index];
  }
  if (isDuelMode()) {
    return index === 0 ? "player" : "opponent";
  }

  return index === 0 ? "player" : getActiveBotOwnerIds()[index - 1] || `bot${index}`;
}

function getUniqueOwnersFromCardIndexes(indexes) {
  return [...new Set(indexes.map(getOwnerFromCardIndex).filter((owner) => getActiveOwners().includes(owner)))];
}

function getCardRatingsByOwner(ratings) {
  return Object.fromEntries((ratings || []).map((rating, index) => [getOwnerFromCardIndex(index), rating]));
}

function getWinPhrase(owner, scope) {
  if (state.mode === "bots" && owner === "player") {
    return `You win the ${scope}.`;
  }

  return `${getOwnerLabel(owner)} wins the ${scope}.`;
}

function applyPreGradeSinGluttony(playedEntries, startingScores, startingStreaks, deltas, events) {
  playedEntries
    .filter((entry) => entry.power.type === "sin_gluttony")
    .forEach((entry) => {
      const streak = startingStreaks[entry.owner] || 0;
      const percent = isChaosInfusedPower(entry.power) ? entry.power.percentPerStreak || 0.04 : 0.025;
      const streakLoss = isChaosInfusedPower(entry.power) ? entry.power.streakLoss || 3 : streak;
      const amount = Math.floor((startingScores[entry.owner] || 0) * percent * streak);
      deltas[entry.owner] += amount;
      setOwnerStreak(entry.owner, Math.max(0, getOwnerStreak(entry.owner) - streakLoss), { force: true });
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} ate ${streak} streak before grading for ${amount.toLocaleString()} points.`));
    });
}

function applyMagic8Entries(playedEntries, startingScores, deltas, events) {
  playedEntries
    .filter((entry) => entry.power.type === "magic_8")
    .forEach((entry) => {
      const count = [...String(startingScores[entry.owner] || 0)].filter((character) => character === "8").length;
      if (isChaosInfusedPower(entry.power)) {
        const amount = count * 1888;
        if (amount > 0) {
          deltas[entry.owner] += amount;
        }
        events.push(createPowerEvent(entry.owner, entry.power, amount > 0
          ? `${entry.power.name} found ${count} eight${count === 1 ? "" : "s"} and paid ${amount.toLocaleString()} points.`
          : `${entry.power.name} found no eights.`));
        return;
      }
      if (count > 0) {
        deltas[entry.owner] += 888;
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} found an 8 and paid 888 points.`));
      }
    });
}

function armTimeBombEntries(playedEntries, events) {
  playedEntries
    .filter((entry) => entry.power.type === "time_bomb")
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      state.timeBombs.push({ owner: entry.owner, round: state.round + 3 });
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} will make players ahead lose 10% after 3 rounds.`));
    });
}

function logDeadWeightEntries(playedEntries, events) {
  playedEntries
    .filter((entry) => entry.power.type === "dead_weight")
    .forEach((entry) => {
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} was dumped immediately.`));
    });
}

function applySinEnvyEntries(playedEntries, startingScores, deltas, owners, events) {
  playedEntries
    .filter((entry) => entry.power.type === "sin_envy")
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      const ownerTotal = Math.max(0, startingScores[entry.owner] + (deltas[entry.owner] || 0));
      const amount = Math.floor(ownerTotal * 0.2);
      deltas[entry.owner] -= amount;
      owners
        .filter((participant) => participant !== entry.owner)
        .forEach((participant) => {
          deltas[participant] -= amount;
        });
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} cost ${getOwnerLabel(entry.owner)} ${amount.toLocaleString()} points, then made everyone else lose that amount.`));
    });
}

function applyBlessingEntries(playedEntries, startingScores, deltas, events) {
  playedEntries
    .filter((entry) => entry.power.type === "blessing")
    .forEach((entry) => {
      if (isChaosInfusedPower(entry.power)) {
        state.divineBlessingOwners[entry.owner] = true;
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} will pay every round for the rest of the game.`));
        return;
      }
      const amount = 500 + Math.floor(startingScores[entry.owner] * 0.1);
      deltas[entry.owner] += amount;
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} added ${amount.toLocaleString()} points.`));
    });
}

function applyVultureEntries(playedEntries, winnerSet, deltas, events) {
  playedEntries
    .filter((entry) => entry.power.type === "vulture")
    .forEach((entry) => {
      if (isChaosInfusedPower(entry.power)) {
        state.vultureSwarmOwners[entry.owner] = true;
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} will pay for losses every round.`));
        return;
      }
      const losses = state.matchHistory.filter((round) => !(round.winners || [round.winner]).includes(getOwnerLabel(entry.owner))).length + (winnerSet.has(entry.owner) ? 0 : 1);
      const amount = losses * 350;
      deltas[entry.owner] += amount;
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} paid ${amount.toLocaleString()} points for ${losses} losses.`));
    });
}

function armInsuranceFraudEntries(playedEntries, events) {
  playedEntries
    .filter((entry) => entry.power.type === "insurance_fraud")
    .forEach((entry) => {
      state.insuranceFrauds[entry.owner] = { startsRound: state.round, remaining: 3, losses: 0 };
      events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} quietly filed paperwork.`));
    });
}

function armBottomFeederEntries(playedEntries, events) {
  playedEntries
    .filter((entry) => entry.power.type === "bottom_feeder")
    .forEach((entry) => {
      state.bottomFeederRounds[entry.owner] = (state.bottomFeederRounds[entry.owner] || 0) + 1;
      if (isChaosInfusedPower(entry.power)) {
        state.chaosBottomFeederOwners[entry.owner] = true;
      }
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} stack ${state.bottomFeederRounds[entry.owner]} will pay after losses for the rest of the game.`));
    });
}

function applyBottomFeederPayouts(deltas, owners, winnerSet, events) {
  owners.forEach((participant) => {
    const stacks = Math.max(0, state.bottomFeederRounds[participant] || 0);
    if (stacks === 0 || winnerSet.has(participant)) {
      return;
    }
    const amount = stacks * 100;
    deltas[participant] += amount;
    events.push(`${getOwnerLabel(participant)} gained ${amount.toLocaleString()} points from ${stacks} Bottom Feeder stack${stacks === 1 ? "" : "s"}.`);
  });
  owners
    .filter((participant) => state.chaosBottomFeederOwners[participant])
    .forEach((participant) => {
      state.bottomFeederRounds[participant] = (state.bottomFeederRounds[participant] || 0) + 1;
      events.push(`Scavenger added a Bottom Feeder stack to ${getOwnerLabel(participant)}.`);
    });
}

function applyWrathLossTriggers(losingOwners, events) {
  const losers = new Set(losingOwners || []);
  Object.keys(state.wrathOwners || {})
    .filter((owner) => losers.has(owner) && getActiveOwners().includes(owner))
    .forEach((owner) => {
      const target = getRandomOtherOwner(owner);
      if (!target) {
        return;
      }
      state.wrathBombs = [...(state.wrathBombs || []), { owner, targetOwner: target, round: state.round + 1 }];
      events.push(`Explosive Temper planted a bomb on ${getOwnerLabel(target)} for next round.`);
    });
}

function armChaosLoserTaxCollectors(playedEntries, events) {
  playedEntries
    .filter((entry) => entry.power.type === "loser_tax" && isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      state.loserTaxCollectors[entry.owner] = Math.max(state.loserTaxCollectors[entry.owner] || 0, 3);
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} will collect from losers for 3 rounds.`));
    });
}

function applyLoserTaxCollectors(deltas, owners, losingOwners, events) {
  const loserSet = new Set(losingOwners || []);
  Object.keys(state.loserTaxCollectors || {})
    .filter((owner) => owners.includes(owner) && (state.loserTaxCollectors[owner] || 0) > 0)
    .forEach((collector) => {
      let collected = 0;
      owners
        .filter((participant) => participant !== collector && loserSet.has(participant))
        .forEach((participant) => {
          deltas[participant] -= 350;
          collected += 350;
        });
      if (collected > 0) {
        deltas[collector] += collected;
        events.push(`Debt Collector took ${collected.toLocaleString()} points from this round's losers for ${getOwnerLabel(collector)}.`);
      }
    });
}

function applyDeathMarkDeltas(deltas, owners, events) {
  const remainingMarks = [];
  (state.deathMarks || []).forEach((mark) => {
    if (!owners.includes(mark.targetOwner)) {
      return;
    }
    const currentLoss = Math.abs(Math.min(0, deltas[mark.targetOwner] || 0));
    if (currentLoss > 0) {
      deltas[mark.targetOwner] -= currentLoss;
      events.push(`Death Mark doubled ${getOwnerLabel(mark.targetOwner)}'s point losses by ${currentLoss.toLocaleString()}.`);
    }
    const nextRemaining = Math.max(0, (mark.remaining || 0) - 1);
    if (nextRemaining <= 0) {
      const currentTotal = Math.max(0, getScore(mark.targetOwner) + (deltas[mark.targetOwner] || 0));
      const finalLoss = Math.floor(currentTotal * 0.1);
      deltas[mark.targetOwner] -= finalLoss;
      events.push(`Death Mark expired on ${getOwnerLabel(mark.targetOwner)} for ${finalLoss.toLocaleString()} points.`);
      return;
    }
    remainingMarks.push({ ...mark, remaining: nextRemaining });
  });
  state.deathMarks = remainingMarks;
}

function applyRedHerringEntries(playedEntries, startingScores, deltas, events) {
  playedEntries
    .filter((entry) => entry.power.type === "red_herring")
    .forEach((entry) => {
      const amount = Math.floor(Math.max(0, startingScores[entry.owner] || 0) * 0.1);
      deltas[entry.owner] += amount;
      activateRedHerring(entry.owner);
      events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} quietly banked ${amount.toLocaleString()} hidden Red Herring points and masked their score.`));
    });
}

function resolveHotPotatoEntries(playedEntries, deltas, events) {
  const hotPotatoesThisRound = playedEntries.filter((entry) => entry.power.type === "hot_potato");
  if (state.round >= state.maxRounds) {
    const potatoOwners = [
      ...(state.hotPotatoOwners || []),
      ...hotPotatoesThisRound.map((entry) => isChaosInfusedPower(entry.power) ? `${entry.owner}|chaos` : entry.owner)
    ];
    const potatoHits = Math.max(state.hotPotatoCount + hotPotatoesThisRound.length, potatoOwners.length);
    for (let index = 0; index < potatoHits; index += 1) {
      const sourceEntry = potatoOwners[index] || "";
      const [sourceOwner, mode] = String(sourceEntry).split("|");
      const target = mode === "chaos" ? getRandomOtherOwner(sourceOwner) : getRandomActiveOwner();
      applyHotPotatoHit(target, deltas, events, sourceOwner, mode === "chaos" ? 0.3 : 0.2, mode === "chaos" ? "Not My Problem" : "Hot Potato");
    }
    state.hotPotatoCount = 0;
    state.hotPotatoOwners = [];
  } else if (hotPotatoesThisRound.length) {
    state.hotPotatoCount += hotPotatoesThisRound.length;
    state.hotPotatoOwners = [...(state.hotPotatoOwners || []), ...hotPotatoesThisRound.map((entry) => isChaosInfusedPower(entry.power) ? `${entry.owner}|chaos` : entry.owner)];
    hotPotatoesThisRound.forEach((entry) => {
      events.push(createPowerEvent(entry.owner, entry.power, "Hot Potato is armed for the final round."));
    });
  }
}

function applyMonopolyEntries(playedEntries, deltas, owners, events) {
  playedEntries
    .filter((entry) => entry.power.type === "monopoly")
    .forEach((entry) => {
      owners
        .filter((participant) => participant !== entry.owner && hasPlayedPowerThisRound(participant))
        .forEach((participant) => {
          deltas[participant] -= 200;
          deltas[entry.owner] += 200;
        });
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} taxed every other power user for 200 points.`));
    });
}

function applyPendingPowerBonuses(deltas, owners, pendingBonuses, events) {
  owners.forEach((participant) => {
    const pending = pendingBonuses[participant] || 0;
    if (!pending) {
      return;
    }
    deltas[participant] += pending;
    events.push(`${getOwnerLabel(participant)} received ${pending.toLocaleString()} pending bonus points.`);
    state.pendingPowerBonuses[participant] = 0;
  });
}

function progressInsuranceFrauds(deltas, winnerSet, events) {
  Object.entries({ ...state.insuranceFrauds }).forEach(([participant, fraud]) => {
    if (state.round < fraud.startsRound) {
      return;
    }
    if (winnerSet.has(participant)) {
      delete state.insuranceFrauds[participant];
      events.push(`${getOwnerLabel(participant)} broke their Insurance Fraud loss streak.`);
      return;
    }
    fraud.losses += 1;
    fraud.remaining -= 1;
    if (fraud.losses >= 3) {
      deltas[participant] += 4500;
      setOwnerStreak(participant, getOwnerStreak(participant) + 3);
      const buff = applyCocktailMix(participant, { buffsOnly: true });
      markAchievementInsuranceTrigger(participant, "fraud");
      delete state.insuranceFrauds[participant];
      events.push(`${getOwnerLabel(participant)} cashed out 4,500 secret Insurance Fraud points, 3 streak, and ${buff}.`);
    } else if (fraud.remaining <= 0) {
      delete state.insuranceFrauds[participant];
    } else {
      state.insuranceFrauds[participant] = fraud;
    }
  });
}

function applyCommunismEntries(playedEntries, deltas, owners, events) {
  playedEntries
    .filter((entry) => entry.power.type === "communism")
    .forEach((entry) => {
      const positivePool = owners.reduce((sum, participant) => sum + Math.max(0, deltas[participant]), 0);
      const share = Math.floor(positivePool / owners.length);
      owners.forEach((participant) => {
        deltas[participant] -= Math.max(0, deltas[participant]);
        deltas[participant] += share;
      });
      deltas[entry.owner] += 500;
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} split ${positivePool.toLocaleString()} gained points and gave ${getOwnerLabel(entry.owner)} 500 extra.`));
    });
}

function applyLastChanceEntries(playedEntries, deltas, events) {
  playedEntries
    .filter((entry) => entry.power.type === "last_chance")
    .forEach((entry) => {
      const gained = Math.max(0, deltas[entry.owner]);
      if (gained > 0) {
        const multiplier = isChaosInfusedPower(entry.power) ? entry.power.gainMultiplier || 3 : 2;
        deltas[entry.owner] += gained * (multiplier - 1);
        if (deltas[entry.owner] > 10000) {
          const stat = getAchievementStat(entry.owner);
          if (stat) {
            stat.lastLaughOver10000 = true;
          }
        }
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} multiplied ${getOwnerLabel(entry.owner)}'s ${gained.toLocaleString()} gained points by ${multiplier}.`));
      }
    });
}

function createNoCorrectAward() {
  const owners = getActiveOwners();
  const pointLossSoundToken = state.pointLossSoundToken;
  const startingScores = Object.fromEntries(owners.map((participant) => [participant, getScore(participant)]));
  const startingStreaks = Object.fromEntries(owners.map((participant) => [participant, getOwnerStreak(participant)]));
  const freezeSnapshot = { ...state.freezeProtection };
  const permafrostSnapshot = { ...state.permafrostProtection };
  const pendingBonuses = Object.fromEntries(owners.map((participant) => [participant, state.pendingPowerBonuses[participant] || 0]));
  let playedEntries = getPlayedPowerEntries(owners);
  const events = [];
  const deltas = Object.fromEntries(owners.map((participant) => [participant, 0]));

  playedEntries.forEach((entry) => events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} used ${entry.power.name}.`)));

  ({ playedEntries } = applyPlayedPowerDisables(playedEntries, events));

  if (playedEntries.some((entry) => entry.power.type === "no_one_wins")) {
    const tableFlip = playedEntries.find((entry) => entry.power.type === "no_one_wins");
    rememberLastPlayedPowers(owners);
    clearProlongedPowerEffects();
    const refillEvent = refillPowerHandToLimit(tableFlip.owner, "from Table Flip");
    events.push(createPowerEvent(tableFlip.owner, tableFlip.power, "Table Flip cancelled every score change this round, wiped prolonged power-up effects, and refilled its user's hand."));
    if (refillEvent) {
      events.push(refillEvent);
    }
    renderScore();
    return {
      bonus: 0,
      tagBonus: 0,
      difficultyBonus: 0,
      underdogBonus: 0,
      powerBonus: 0,
      sabotagePenalty: 0,
      doublePenalty: 0,
      powerLabel: "",
      total: 0,
      baseWinPoints: 0,
      chaosPlayed: false,
      winningOwners: [],
      payoutDetails: {},
      payoutOwner: null,
      reversePlayed: false,
      reverseTotal: 0,
      amplifiedMultiplier: 1,
      deltas,
      events,
      noPoints: true,
      noCorrect: true,
      tag: "Incorrect"
    };
  }

  playedEntries
    .filter((entry) => entry.power.type === "eternal_flame")
    .forEach((entry) => {
      state.eternalFlameProtection[entry.owner] = true;
      events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} protected their streak for the rest of the game.`));
    });

  playedEntries
    .filter((entry) => entry.power.type === "streak_bonus")
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      const stolen = getEntryMeta(entry).stolenStreak || 0;
      if (target && stolen > 0) {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} stole ${stolen} streak from ${getOwnerLabel(target)} instantly.`));
      } else {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} found no streak to steal.`));
      }
    });

  rememberLastPlayedPowers(owners);

  applyNewPersistentPowerEntries(playedEntries, events);
  applyPreGradeSinGluttony(playedEntries, startingScores, startingStreaks, deltas, events);

  const insuranceTriggeredOwners = resolveInsurancePolicies(owners, deltas, startingScores, events);
  owners.forEach((participant) => {
    if (!insuranceTriggeredOwners.has(participant) && !shouldKeepStreakAfterRoundLoss(participant)) {
      setOwnerStreak(participant, 0);
    }
  });
  owners
    .filter((participant) => startingStreaks[participant] > 0 && (insuranceTriggeredOwners.has(participant) || shouldKeepStreakAfterRoundLoss(participant)))
    .forEach((participant) => {
      const source = insuranceTriggeredOwners.has(participant)
        ? " with Insurance"
        : isMatchModifierEnabled("wildFire") && !state.eternalFlameProtection[participant]
          ? " in Wild Fire"
          : " with Eternal Flame";
      events.push(`${getOwnerLabel(participant)} kept their streak through the loss${source}.`);
    });

  if (isMatchModifierEnabled("harsh")) {
    owners.forEach((participant) => {
      deltas[participant] -= getBrutalWrongAnswerLoss(participant, startingScores);
    });
    events.push("Brutal mode made every wrong answer lose 10% of that player's points.");
  }

  playedEntries
    .filter((entry) => entry.power.type === "double_jeopardy")
    .forEach((entry) => {
      const amount = Math.floor(startingScores[entry.owner] * (entry.power.losePercent || 0.1));
      deltas[entry.owner] -= amount;
      events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} lost ${amount.toLocaleString()} points from ${entry.power.name}.`));
    });

  playedEntries
    .filter((entry) => entry.power.type === "sin_wrath" && !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      const target = getRandomOtherOwner(entry.owner);
      const amount = 350 * (startingStreaks[entry.owner] || 0);
      if (target) {
        deltas[target] -= amount;
      }
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} punished ${target ? getOwnerLabel(target) : "nobody"} for ${amount.toLocaleString()} points.`));
    });

  playedEntries
    .filter((entry) => entry.power.type === "heaven_hell")
    .forEach((entry) => {
      state.heavenHellCurses[entry.owner] = true;
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} cursed ${getOwnerLabel(entry.owner)} for the rest of the game.`));
    });

  owners
    .filter((participant) => state.heavenHellCurses[participant])
    .forEach((participant) => {
      deltas[participant] -= 250;
      events.push(`${getOwnerLabel(participant)} lost 250 points from the Heaven or Hell curse.`);
    });

  playedEntries
    .filter((entry) => entry.power.type === "loser_tax")
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      owners.forEach((participant) => {
        deltas[participant] -= 250;
      });
      events.push(createPowerEvent(entry.owner, entry.power, "Every wrong answer lost 250 points."));
    });
  armChaosLoserTaxCollectors(playedEntries, events);
  applyLoserTaxCollectors(deltas, owners, owners, events);

  const penaltyClouds = playedEntries.filter((entry) => entry.power.type === "penalty_cloud");
  if (penaltyClouds.length) {
    state.loserPenaltyRounds = Math.max(state.loserPenaltyRounds, 3);
    penaltyClouds.forEach((entry) => {
      events.push(createPowerEvent(entry.owner, entry.power, "Penalty Cloud will punish wrong answers for 3 rounds."));
    });
  }
  if (state.loserPenaltyRounds > 0) {
    owners.forEach((participant) => {
      const amount = Math.floor(Math.max(0, startingScores[participant] + (deltas[participant] || 0)) * 0.05);
      deltas[participant] -= amount;
    });
    events.push("Penalty Cloud made every wrong answer lose 5% of their current total.");
    state.loserPenaltyRounds -= 1;
  }

  playedEntries
    .filter((entry) => entry.power.type === "lightning_strike" || entry.power.type === "zap_strike")
    .filter((entry) => !isEntryImmediateResolved(entry))
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      if (!target || !owners.includes(target)) {
        return;
      }
      const targetStreak = startingStreaks[target] || 0;
      if (targetStreak <= 0) {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} targeted ${getOwnerLabel(target)}, but they had no streak to zap.`));
        return;
      }
      const amount = (entry.power.type === "lightning_strike" ? 500 : 250) * (targetStreak + 1);
      deltas[target] -= amount;
      queueStatFlash("lightning", entry.power.name, formatSignedStat(-amount, "Point"), getTargetedFlashOptions(entry.owner, target));
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} zapped ${getOwnerLabel(target)} for ${amount.toLocaleString()} points.`));
    });

  playedEntries
    .filter((entry) => entry.power.type === "loose_cannon")
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      const target = getRandomActiveOwner();
      const amount = Math.floor((startingScores[target] || 0) * 0.1);
      deltas[target] -= amount;
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} hit ${getOwnerLabel(target)} for 10% of their total (${amount.toLocaleString()} points).`));
    });

  applyMagic8Entries(playedEntries, startingScores, deltas, events);
  armTimeBombEntries(playedEntries, events);
  logDeadWeightEntries(playedEntries, events);
  applySinEnvyEntries(playedEntries, startingScores, deltas, owners, events);
  applyBlessingEntries(playedEntries, startingScores, deltas, events);
  applyVultureEntries(playedEntries, new Set(), deltas, events);

  playedEntries
    .filter((entry) => entry.power.type === "haha_you_lose")
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      if (!target || !owners.includes(target)) {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} had no valid target.`));
        return;
      }
      deltas[target] -= 500;
      deltas[entry.owner] += 500;
      markAchievementPointSteal(entry.owner, 500);
      setOwnerStreak(entry.owner, getOwnerStreak(entry.owner) + 1);
      queueStatFlash("negative", entry.power.name, formatSignedStat(-500, "Point"), getTargetedFlashOptions(entry.owner, target));
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} took 500 points from ${getOwnerLabel(target)} and gained 1 streak.`));
    });
  armSkillIssueEntries(playedEntries, events);
  applySkillIssueMarks(owners, new Set(), startingScores, deltas, events);

  armInsuranceFraudEntries(playedEntries, events);

  playedEntries
    .filter((entry) => entry.power.type === "participation")
    .forEach((entry) => {
      if (isChaosInfusedPower(entry.power)) {
        const firstPlaceTotal = Math.max(...owners.map((participant) => Math.max(0, startingScores[participant] + (deltas[participant] || 0))));
        const amount = Math.floor(firstPlaceTotal * 0.15);
        deltas[entry.owner] += amount;
        setOwnerStreak(entry.owner, getOwnerStreak(entry.owner) + 5);
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} turned the loss into ${amount.toLocaleString()} points and 5 streak.`));
        return;
      }
      deltas[entry.owner] += 100;
      setOwnerStreak(entry.owner, getOwnerStreak(entry.owner) + 1);
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} turned the loss into 100 points and 1 streak.`));
    });

  armBottomFeederEntries(playedEntries, events);
  applyBottomFeederPayouts(deltas, owners, new Set(), events);
  progressInsuranceFrauds(deltas, new Set(), events);
  applyRedHerringEntries(playedEntries, startingScores, deltas, events);
  resolveHotPotatoEntries(playedEntries, deltas, events);
  applyMonopolyEntries(playedEntries, deltas, owners, events);
  applyPendingPowerBonuses(deltas, owners, pendingBonuses, events);
  applyCommunismEntries(playedEntries, deltas, owners, events);
  applyLastChanceEntries(playedEntries, deltas, events);

  applyNewPointPowerEntries(playedEntries, deltas, owners, events, new Set());
  applyPersistentRoundDeltas(deltas, owners, events);
  applyReignChaosEndRound(playedEntries, deltas, owners, events);
  applyLawsuitEntries(playedEntries, deltas, owners, events);
  applyNailInCoffin(playedEntries, deltas, events);
  applyTableEventLoserDeltas(deltas, owners, new Set(), startingScores, events);
  applyWrathLossTriggers(owners, events);
  applyDeathBombMarks(owners, new Set(), deltas, events);
  applyDeathMarkDeltas(deltas, owners, events);
  applyPermanentDeathMarkDeltas(deltas, owners, events);
  applyDeductionProtection(deltas, playedEntries, freezeSnapshot, permafrostSnapshot, events);
  applyThornsDeltas(deltas, owners, events);
  applyDeductionProtection(deltas, playedEntries, freezeSnapshot, permafrostSnapshot, events);
  const reverseTotal = applyReverseVerdicts(playedEntries, deltas, owners, events);

  owners.forEach((participant) => {
    if (freezeSnapshot[participant] > 0) {
      state.freezeProtection[participant] = Math.max(0, freezeSnapshot[participant] - 1);
    }
  });

  playedEntries
    .filter((entry) => entry.power.type === "deep_freeze")
    .forEach((entry) => {
      state.freezeProtection[entry.owner] = Math.max(state.freezeProtection[entry.owner] || 0, 2);
      if (isChaosInfusedPower(entry.power)) {
        state.freezeReflectionRounds[entry.owner] = Math.max(state.freezeReflectionRounds[entry.owner] || 0, 2);
      }
      queueStatFlash("shield", entry.power.name, "Point Shield Armed", { owners: [entry.owner], complex: true });
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} blocked this round and will block deductions for the next 2 rounds.`));
    });

  playedEntries
    .filter((entry) => entry.power.type === "permafrost")
    .forEach((entry) => {
      state.permafrostProtection[entry.owner] = true;
      queueStatFlash("shield", entry.power.name, "Permanent Shield Armed", { owners: [entry.owner], complex: true });
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} will block deductions for the rest of the match.`));
    });

  let amplifiedMultiplier = 1;
  if (isMatchModifierEnabled("amplified")) {
    amplifiedMultiplier = applyRoundAmplifiedMultiplier(deltas, owners, events);
  }

  applyEventHorizonAfterRound(owners, new Set(), events);
  applyVoidBombCaps(playedEntries, deltas, events);
  applyFinalTableEventGainMultipliers(deltas, owners, events);
  applyOverachieverRewards(playedEntries, deltas, events);
  const hasPointChanges = Object.values(deltas).some((amount) => amount !== 0);
  playUnassignedPointLossSound(deltas, pointLossSoundToken);
  owners.forEach((participant) => addScore(participant, deltas[participant]));
  decrementRoundEffectCounters(owners);
  events.push(...replenishPowerSlotsForOwners(owners, "after getting the answer wrong"));
  renderScore();

  return {
    bonus: 0,
    tagBonus: 0,
    difficultyBonus: 0,
    underdogBonus: 0,
    powerBonus: 0,
    sabotagePenalty: 0,
    doublePenalty: 0,
    powerLabel: "",
    total: 0,
    baseWinPoints: 0,
    chaosPlayed: playedEntries.some((entry) => entry.power.type === "reign_chaos"),
    winningOwners: [],
    payoutDetails: {},
    payoutOwner: null,
    reversePlayed: reverseTotal > 0 || playedEntries.some((entry) => entry.power.type === "reverse"),
    reverseTotal,
    amplifiedMultiplier,
    deltas,
    events,
    noPoints: !hasPointChanges,
    noCorrect: true,
    tag: "Incorrect"
  };
}

function hasDeductionProtection(owner, playedEntries, freezeSnapshot, permafrostSnapshot) {
  return playedEntries.some((entry) => entry.owner === owner && (entry.power.type === "participation" || entry.power.type === "deep_freeze" || entry.power.type === "permafrost" || entry.power.type === "hoarder"))
    || Boolean(state.playedPowerMeta[owner]?.hoarderShield)
    || (state.pocketShieldCharges[owner] || 0) > 0
    || freezeSnapshot[owner] > 0
    || permafrostSnapshot[owner];
}

function hasDeductionReflection(owner, playedEntries) {
  return (state.freezeReflectionRounds[owner] || 0) > 0
    || playedEntries.some((entry) => entry.owner === owner && entry.power.type === "deep_freeze" && isChaosInfusedPower(entry.power));
}

function applyDeductionProtection(deltas, playedEntries, freezeSnapshot, permafrostSnapshot, events) {
  getActiveOwners().forEach((owner) => {
    if (deltas[owner] < 0 && hasDeductionProtection(owner, playedEntries, freezeSnapshot, permafrostSnapshot)) {
      const blocked = Math.abs(deltas[owner]);
      deltas[owner] = hasDeductionReflection(owner, playedEntries) ? blocked : 0;
      if ((state.pocketShieldCharges[owner] || 0) > 0) {
        const breakThreshold = state.pocketShieldBreakThresholds[owner] || 0;
        if (!breakThreshold || blocked > breakThreshold) {
          state.pocketShieldCharges[owner] = Math.max(0, (state.pocketShieldCharges[owner] || 0) - 1);
          if ((state.pocketShieldCharges[owner] || 0) <= 0) {
            state.pocketShieldBreakThresholds[owner] = 0;
          }
        }
      }
      markAchievementShieldSave(owner);
      queueStatFlash("shield", "Shield", `Blocked ${blocked.toLocaleString()} Points`, { owners: [owner], complex: true });
      events.push(hasDeductionReflection(owner, playedEntries)
        ? `${getOwnerLabel(owner)} reversed ${blocked.toLocaleString()} blocked points into a gain.`
        : `${getOwnerLabel(owner)} blocked ${blocked.toLocaleString()} points of deductions.`);
    }
  });
}

function applyReverseVerdicts(playedEntries, deltas, owners, events) {
  let redirectedTotal = 0;
  playedEntries
    .filter((entry) => entry.power.type === "reverse")
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      if (!target || !owners.includes(target)) {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} had no valid target.`));
        return;
      }

      const amount = Math.max(0, deltas[target] || 0);
      if (!amount) {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} targeted ${getOwnerLabel(target)}, but they obtained no points to transfer.`));
        return;
      }

      deltas[target] -= amount;
      deltas[entry.owner] += amount;
      redirectedTotal += amount;
      queueStatFlash("negative", entry.power.name, `${amount.toLocaleString()} Points Transferred`, getTargetedFlashOptions(entry.owner, target, { complex: true }));
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} transferred ${getOwnerLabel(target)}'s ${amount.toLocaleString()} obtained points to ${getOwnerLabel(entry.owner)}. ${getOwnerLabel(target)} got nothing from those gains.`));
    });
  return redirectedTotal;
}

function clearProlongedPowerEffects() {
  state.pendingPowerBonuses = createOwnerValueMap(0);
  state.freezeProtection = createOwnerValueMap(0);
  state.pocketShieldCharges = createOwnerValueMap(0);
  state.permafrostProtection = createOwnerValueMap(false);
  state.eternalFlameProtection = createOwnerValueMap(false);
  state.streakAnchorCharges = createOwnerValueMap(0);
  state.pendingStreakBonuses = createOwnerValueMap(0);
  state.heavenHellCurses = createOwnerValueMap(false);
  state.secretPointBonuses = createOwnerValueMap(0);
  state.fakePointDebts = createOwnerValueMap(0);
  state.redHerringMasks = {};
  state.bottomFeederRounds = createOwnerValueMap(0);
  state.streakFreezeRounds = createOwnerValueMap(0);
  state.streakLossProtectionRounds = createOwnerValueMap(0);
  state.cocktailPenaltyRounds = createOwnerValueMap(0);
  state.debuffShieldCharges = createOwnerValueMap(0);
  state.debuffShieldRounds = createOwnerValueMap(0);
  state.failedInvestmentDebuffs = createOwnerValueMap(false);
  state.timeDilationRounds = createOwnerValueMap(0);
  state.pendingCocktailBuffs = createOwnerValueMap(0);
  state.pendingLegendaryPowers = createOwnerValueMap(0);
  state.pocketShieldBreakThresholds = createOwnerValueMap(0);
  state.insuranceFrauds = {};
  state.insurancePolicies = {};
  state.virusFactories = {};
  state.luckRounds = createOwnerValueMap(0);
  state.typhoonOwners = {};
  state.thornOwners = {};
  state.eternalSlumberOwners = {};
  state.wrathOwners = {};
  state.divineBlessingOwners = {};
  state.superFuelOwners = {};
  state.vultureSwarmOwners = {};
  state.chaosBottomFeederOwners = {};
  state.loserTaxCollectors = {};
  state.chaosInfusionBoostRounds = createOwnerValueMap(0);
  state.freezeReflectionRounds = createOwnerValueMap(0);
  state.chaosEnvyOwners = {};
  state.eventHorizonMarks = {};
  state.chaosRefreshOwners = {};
  state.permanentDeathMarks = {};
  state.timeBombs = [];
  state.deathMarks = [];
  state.deathBombMarks = [];
  state.wrathBombs = [];
  state.debuffTimeBombs = [];
  state.skillIssueMarks = [];
  state.error404Owners = {};
  state.error404Schedule = [];
  state.pendingDeadWeights = [];
  state.deadWeightLockedRounds = {};
  state.allOutRounds = {};
  state.extraPowerUses = {};
  state.nextPreferredTheme = "";
  state.soulLinks = [];
  state.streakLinks = [];
  state.arsonists = {};
  state.bartenders = {};
  state.hotInHereOwners = {};
  state.worldBurnOwners = {};
  state.lawnMowerOwners = {};
  state.loserPenaltyRounds = 0;
  state.hotPotatoCount = 0;
  state.hotPotatoOwners = [];
}

function awardPoints(owner, rating = { label: "Correct", bonus: 50 }, winningOwners = [owner], ratingsByOwner = {}) {
  const owners = getActiveOwners();
  const pointLossSoundToken = state.pointLossSoundToken;
  const winnerSet = new Set(winningOwners.filter((participant) => owners.includes(participant)));
  if (!winnerSet.size && owners.includes(owner)) {
    winnerSet.add(owner);
  }
  const winners = [...winnerSet];
  const startingScores = Object.fromEntries(owners.map((participant) => [participant, getScore(participant)]));
  const startingStreaks = Object.fromEntries(owners.map((participant) => [participant, getOwnerStreak(participant)]));
  const pendingBonuses = Object.fromEntries(owners.map((participant) => [participant, state.pendingPowerBonuses[participant] || 0]));
  const freezeSnapshot = { ...state.freezeProtection };
  const permafrostSnapshot = { ...state.permafrostProtection };
  const winnerScore = startingScores[owner];
  const highScore = Math.max(...owners.map((participant) => startingScores[participant]));
  const underdogBonus = highScore - winnerScore >= UNDERDOG_BONUS_THRESHOLD ? UNDERDOG_BONUS_POINTS : 0;
  const winnerPower = getPlayedPowerEntries([owner]).find((entry) => !isSecretPower(entry.power))?.power || getPowerById(state.playedPowerUps[owner]);
  let playedEntries = getPlayedPowerEntries(owners);
  const events = [];
  const refillEvents = replenishLosingPowerSlots(winners);
  const deltas = Object.fromEntries(owners.map((participant) => [participant, 0]));

  playedEntries.forEach((entry) => events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} used ${entry.power.name}.`)));

  ({ playedEntries } = applyPlayedPowerDisables(playedEntries, events));

  if (playedEntries.some((entry) => entry.power.type === "no_one_wins")) {
    const tableFlip = playedEntries.find((entry) => entry.power.type === "no_one_wins");
    clearProlongedPowerEffects();
    const refillEvent = refillPowerHandToLimit(tableFlip.owner, "from Table Flip");
    events.push(createPowerEvent(tableFlip.owner, tableFlip.power, "Table Flip cancelled every score change this round, wiped prolonged power-up effects, and refilled its user's hand."));
    if (refillEvent) {
      events.push(refillEvent);
    }
    return {
      bonus: 0,
      tagBonus: 0,
      underdogBonus: 0,
      powerBonus: 0,
      powerLabel: "",
      total: 0,
      baseWinPoints: 0,
      chaosPlayed: false,
      winningOwners: winners,
      payoutDetails: {},
      deltas: Object.fromEntries(owners.map((participant) => [participant, 0])),
      events,
      noPoints: true,
      tag: rating.label
    };
  }

  playedEntries
    .filter((entry) => entry.power.type === "eternal_flame")
    .forEach((entry) => {
      state.eternalFlameProtection[entry.owner] = true;
      events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} protected their streak for the rest of the game.`));
    });

  playedEntries
    .filter((entry) => entry.power.type === "hard_reset")
    .filter((entry) => !isEntryImmediateResolved(entry))
    .forEach((entry) => {
      owners.forEach((participant) => {
        if (!state.eternalFlameProtection[participant]) {
          setOwnerStreak(participant, 0);
        }
      });
      events.push(createPowerEvent(entry.owner, entry.power, "Hard Reset wiped every unprotected win streak."));
    });

  applyNewPersistentPowerEntries(playedEntries, events);
  applyPreGradeSinGluttony(playedEntries, startingScores, startingStreaks, deltas, events);

  const losingOwners = owners.filter((participant) => !winnerSet.has(participant));
  const insuranceTriggeredOwners = resolveInsurancePolicies(losingOwners, deltas, startingScores, events);
  const retainedOwners = owners.filter((participant) => (
    !winnerSet.has(participant)
    && (insuranceTriggeredOwners.has(participant) || shouldKeepStreakAfterRoundLoss(participant))
    && getOwnerStreak(participant) > 0
  ));

  owners.forEach((participant) => {
    if (!winnerSet.has(participant) && !retainedOwners.includes(participant)) {
      setOwnerStreak(participant, 0);
    }
  });

  retainedOwners.forEach((retainedOwner) => {
    const source = insuranceTriggeredOwners.has(retainedOwner)
      ? " with Insurance"
      : isMatchModifierEnabled("wildFire") && !state.eternalFlameProtection[retainedOwner]
        ? " in Wild Fire"
        : " with Eternal Flame";
    events.push(`${getOwnerLabel(retainedOwner)} kept their streak alive${source}.`);
  });

  winners.forEach((winner) => {
    setOwnerStreak(winner, getOwnerStreak(winner) + (state.superFuelOwners[winner] ? 2 : 1));
  });

  playedEntries
    .filter((entry) => entry.power.type === "sabotage" && entry.power.blockStreak)
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      if (target && winnerSet.has(target)) {
        setOwnerStreak(target, Math.max(0, getOwnerStreak(target) - 1), { force: true });
        queueStatFlash("negative", entry.power.name, "Streak Gain Blocked", getTargetedFlashOptions(entry.owner, target, { complex: true }));
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} blocked ${getOwnerLabel(target)}'s streak gain for that win.`));
      }
    });

  playedEntries
    .filter((entry) => entry.power.type === "streak_bonus")
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      const stolen = getEntryMeta(entry).stolenStreak || 0;
      if (target && stolen > 0) {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} stole ${stolen} streak from ${getOwnerLabel(target)} instantly.`));
      } else {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} found no streak to steal.`));
      }
    });

  playedEntries
    .filter((entry) => entry.power.type === "rocket")
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      state.pendingStreakBonuses[entry.owner] = (state.pendingStreakBonuses[entry.owner] || 0) + 3;
      events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} will gain 3 streak next round.`));
    });

  playedEntries
    .filter((entry) => winnerSet.has(entry.owner) && entry.power.type === "heaven_hell")
    .forEach((entry) => {
      setOwnerStreak(entry.owner, getOwnerStreak(entry.owner) + 3);
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} added 3 streak before scoring.`));
    });

  playedEntries
    .filter((entry) => winnerSet.has(entry.owner) && entry.power.type === "sin_wrath" && !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      setOwnerStreak(entry.owner, getOwnerStreak(entry.owner) + 1);
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} added an extra win streak.`));
    });

  const streakRewardRefillEvents = replenishPowerSlotsForOwners(
    winners.filter((winner) => getOwnerStreak(winner) >= 3),
    "for winning with a 3x streak"
  );

  const payoutDetails = {};
  let sabotagePenalty = 0;
  let doublePenaltyTotal = 0;
  const executionBlockedOwners = new Map();
  const chaosPlayed = playedEntries.some((entry) => entry.power.type === "reign_chaos");
  winners.forEach((winner) => {
    const ownerRating = ratingsByOwner[winner] || (winner === owner ? rating : { label: "Correct", bonus: 50 });
    const ownerPowerEntries = playedEntries.filter((entry) => entry.owner === winner && !isSecretPower(entry.power));
    const ownerPower = ownerPowerEntries.find((entry) => entry.power.type !== "all_out")?.power || ownerPowerEntries[0]?.power || getPowerById(state.playedPowerUps[winner]);
    const ownerTimingMeta = ownerPowerEntries.find((entry) => getEntryMeta(entry).remainingTime !== undefined)?.meta || state.playedPowerMeta[winner] || {};
    const scoringStreak = getOwnerStreak(winner);
    const ownerBonus = scoringStreak > 1 ? (scoringStreak - 1) * STREAK_BONUS_POINTS : 0;
    const ownerTagBonus = ownerRating.bonus || 0;
    const ownerDifficultyBonus = getDifficultyBonus();
    const ownerUnderdogBonus = highScore - startingScores[winner] >= UNDERDOG_BONUS_THRESHOLD ? UNDERDOG_BONUS_POINTS : 0;
    const timeMoneyBase = isMatchModifierEnabled("timeMoney")
      ? Math.max(0, (state.answerRemainingTimes[winner] ?? ownerTimingMeta.remainingTime ?? 0) * TIME_MONEY_SECONDS_MULTIPLIER)
      : null;
    const baseWinPoints = timeMoneyBase ?? BASE_WIN_POINTS;
    let directPowerBonus = 0;
    let ownerSabotagePenalty = 0;
    let ownerTotal = baseWinPoints + ownerBonus + ownerTagBonus + ownerDifficultyBonus + ownerUnderdogBonus;

    if (timeMoneyBase !== null) {
      events.push(`Time Is Money set ${getOwnerLabel(winner)}'s base win to ${baseWinPoints.toLocaleString()} points.`);
    }

    ownerPowerEntries
      .filter((entry) => entry.power.type === "bounty")
      .forEach((entry) => {
        const percent = Number.isFinite(entry.power.minPercent) && Number.isFinite(entry.power.maxPercent)
          ? getRandomInt(Math.round(entry.power.minPercent * 1000), Math.round(entry.power.maxPercent * 1000)) / 1000
          : entry.power.percent || 0;
        const amount = Math.floor(startingScores[winner] * percent);
        directPowerBonus += amount;
        events.push(createPowerEvent(winner, entry.power, `${entry.power.name} added ${amount.toLocaleString()} points.`));
      });

    ownerPowerEntries
      .filter((entry) => entry.power.type === "speed_answer")
      .forEach((entry) => {
      const speedBonus = Math.max(0, (getEntryMeta(entry).remainingTime || 0) * (entry.power.timeMultiplier || 20));
      directPowerBonus += speedBonus;
      events.push(createPowerEvent(winner, entry.power, `${entry.power.name} added ${speedBonus.toLocaleString()} points.`));
      });

    if (ownerPowerEntries.some((entry) => entry.power.type === "heaven_hell")) {
      directPowerBonus += 750;
      events.push(createPowerEvent(winner, getPowerById("heaven_hell"), `Heaven or Hell added 750 win points.`));
    }

    ownerTotal += directPowerBonus;
    playedEntries
      .filter((entry) => entry.owner !== winner && entry.power.type === "sabotage" && getEntryTarget(entry) === winner)
      .forEach((entry) => {
        const amount = (entry.power.amount || 0) + Math.floor((startingScores[winner] || 0) * (entry.power.percentPenalty || 0));
        ownerSabotagePenalty += amount;
        if (entry.power.freezeTargetOnWin) {
          setOwnerStreak(winner, Math.max(0, getOwnerStreak(winner) - 3), { force: true });
          state.streakFreezeRounds[winner] = Math.max(state.streakFreezeRounds[winner] || 0, 3);
        }
        queueStatFlash("negative", entry.power.name, formatSignedStat(-amount, "Point"), getTargetedFlashOptions(entry.owner, winner));
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} cut ${amount.toLocaleString()} points from ${getOwnerLabel(winner)}'s win.`));
      });

    if (ownerSabotagePenalty) {
      ownerTotal = Math.max(0, ownerTotal - ownerSabotagePenalty);
    }

    const doubleEntry = ownerPowerEntries.find((entry) => entry.power.type === "double_jeopardy");
    if (doubleEntry) {
      const multiplier = doubleEntry.power.winMultiplier || 2;
      ownerTotal *= multiplier;
      events.push(createPowerEvent(winner, doubleEntry.power, `${doubleEntry.power.name} multiplied the winning payout by ${multiplier}.`));
    }

    payoutDetails[winner] = {
      bonus: ownerBonus,
      tagBonus: ownerTagBonus,
      difficultyBonus: ownerDifficultyBonus,
      underdogBonus: ownerUnderdogBonus,
      powerBonus: directPowerBonus,
      sabotagePenalty: ownerSabotagePenalty,
      baseWinPoints,
      tag: ownerRating.label,
      total: ownerTotal,
      powerLabel: ownerPower ? ownerPower.name : ""
    };
    sabotagePenalty += ownerSabotagePenalty;
  });

  const primaryPayout = payoutDetails[owner] || {
    bonus: 0,
    tagBonus: rating.bonus || 0,
    difficultyBonus: getDifficultyBonus(),
    underdogBonus,
    powerBonus: 0,
    sabotagePenalty: 0,
    baseWinPoints: BASE_WIN_POINTS,
    tag: rating.label,
    total: 0,
    powerLabel: winnerPower ? winnerPower.name : ""
  };
  let total = primaryPayout.total;
  const bonus = primaryPayout.bonus;
  const tagBonus = primaryPayout.tagBonus;
  const difficultyBonus = primaryPayout.difficultyBonus || 0;
  const directPowerBonus = primaryPayout.powerBonus;
  const baseWinPoints = primaryPayout.baseWinPoints;

  if (isMatchModifierEnabled("harsh")) {
    owners
      .filter((participant) => !winnerSet.has(participant))
      .forEach((participant) => {
        deltas[participant] -= getBrutalWrongAnswerLoss(participant, startingScores);
      });
    events.push("Brutal mode made every non-winner lose 10% of that player's points.");
  }

  playedEntries
    .filter((entry) => entry.power.type === "loose_cannon")
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      const target = getRandomActiveOwner();
      const amount = Math.floor((startingScores[target] || 0) * 0.1);
      deltas[target] -= amount;
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} hit ${getOwnerLabel(target)} for 10% of their total (${amount.toLocaleString()} points).`));
    });

  applyMagic8Entries(playedEntries, startingScores, deltas, events);
  armTimeBombEntries(playedEntries, events);
  logDeadWeightEntries(playedEntries, events);
  applySinEnvyEntries(playedEntries, startingScores, deltas, owners, events);

  playedEntries
    .filter((entry) => entry.power.type === "hitman")
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      const leader = owners
        .filter((participant) => participant !== entry.owner)
        .sort((a, b) => startingScores[b] - startingScores[a])[0];
      if (!leader) {
        return;
      }

      const stolenStreak = getOwnerStreak(leader);
      const amount = 1000 + (500 * stolenStreak);
      deltas[leader] -= amount;
      markAchievementPointSteal(entry.owner, amount);
      if (!state.eternalFlameProtection[leader]) {
        setOwnerStreak(leader, 0);
      }
      if (stolenStreak > 0) {
        setOwnerStreak(entry.owner, getOwnerStreak(entry.owner) + stolenStreak);
      }
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} hit ${getOwnerLabel(leader)} for ${amount.toLocaleString()} points and stole ${stolenStreak} streak.`));
    });

  applyBlessingEntries(playedEntries, startingScores, deltas, events);
  applyVultureEntries(playedEntries, winnerSet, deltas, events);

  playedEntries
    .filter((entry) => entry.power.type === "haha_you_lose")
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      if (!target || !owners.includes(target)) {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} had no valid target.`));
      } else if (!winnerSet.has(target)) {
        deltas[target] -= 500;
        deltas[entry.owner] += 500;
        markAchievementPointSteal(entry.owner, 500);
        setOwnerStreak(entry.owner, getOwnerStreak(entry.owner) + 1);
        queueStatFlash("negative", entry.power.name, formatSignedStat(-500, "Point"), getTargetedFlashOptions(entry.owner, target));
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} took 500 points from ${getOwnerLabel(target)} and gained 1 streak.`));
      } else {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} marked ${getOwnerLabel(target)}, but they answered correctly.`));
      }
    });
  armSkillIssueEntries(playedEntries, events);
  applySkillIssueMarks(owners, winnerSet, startingScores, deltas, events);

  armInsuranceFraudEntries(playedEntries, events);

  playedEntries
    .filter((entry) => entry.power.type === "participation")
    .forEach((entry) => {
      if (!winnerSet.has(entry.owner)) {
        if (isChaosInfusedPower(entry.power)) {
          const firstPlaceTotal = Math.max(...owners.map((participant) => Math.max(0, startingScores[participant] + (deltas[participant] || 0))));
          const amount = Math.floor(firstPlaceTotal * 0.15);
          deltas[entry.owner] += amount;
          setOwnerStreak(entry.owner, getOwnerStreak(entry.owner) + 5);
          events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} turned the loss into ${amount.toLocaleString()} points and 5 streak.`));
          return;
        }
        deltas[entry.owner] += 100;
        setOwnerStreak(entry.owner, getOwnerStreak(entry.owner) + 1);
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} turned the loss into 100 points and 1 streak.`));
      } else {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} protected ${getOwnerLabel(entry.owner)} from point loss this round.`));
      }
    });

  armBottomFeederEntries(playedEntries, events);
  applyBottomFeederPayouts(deltas, owners, winnerSet, events);

  playedEntries
    .filter((entry) => !winnerSet.has(entry.owner) && entry.power.type === "heaven_hell")
    .forEach((entry) => {
      state.heavenHellCurses[entry.owner] = true;
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} cursed ${getOwnerLabel(entry.owner)} for the rest of the game.`));
    });

  playedEntries
    .filter((entry) => !winnerSet.has(entry.owner) && entry.power.type === "sin_wrath" && !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      const target = getRandomOtherOwner(entry.owner);
      const amount = 350 * (startingStreaks[entry.owner] || 0);
      if (target) {
        deltas[target] -= amount;
      }
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} punished ${target ? getOwnerLabel(target) : "nobody"} for ${amount.toLocaleString()} points.`));
    });

  owners
    .filter((participant) => state.heavenHellCurses[participant])
    .forEach((participant) => {
      deltas[participant] -= 250;
      events.push(`${getOwnerLabel(participant)} lost 250 points from the Heaven or Hell curse.`);
    });

  playedEntries
    .filter((entry) => entry.power.type === "loser_tax")
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      owners
        .filter((participant) => !winnerSet.has(participant))
        .forEach((participant) => {
          deltas[participant] -= 250;
        });
      events.push(createPowerEvent(entry.owner, entry.power, "Every loser lost 250 points."));
    });
  armChaosLoserTaxCollectors(playedEntries, events);
  applyLoserTaxCollectors(deltas, owners, owners.filter((participant) => !winnerSet.has(participant)), events);

  const penaltyClouds = playedEntries.filter((entry) => entry.power.type === "penalty_cloud");
  if (penaltyClouds.length) {
    state.loserPenaltyRounds = Math.max(state.loserPenaltyRounds, 3);
    penaltyClouds.forEach((entry) => {
      events.push(createPowerEvent(entry.owner, entry.power, "Penalty Cloud will punish losers for 3 rounds."));
    });
  }
  if (state.loserPenaltyRounds > 0) {
    owners
      .filter((participant) => !winnerSet.has(participant))
      .forEach((participant) => {
        const amount = Math.floor(Math.max(0, startingScores[participant] + (deltas[participant] || 0)) * 0.05);
        deltas[participant] -= amount;
      });
    events.push("Penalty Cloud made every loser lose 5% of their current total.");
    state.loserPenaltyRounds -= 1;
  }

  applyRedHerringEntries(playedEntries, startingScores, deltas, events);

  playedEntries
    .filter((entry) => entry.power.type === "lightning_strike")
    .filter((entry) => !isEntryImmediateResolved(entry))
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      if (!target || !owners.includes(target)) {
        return;
      }
      const targetStreak = startingStreaks[target] || 0;
      if (targetStreak <= 0) {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} targeted ${getOwnerLabel(target)}, but they had no streak to zap.`));
        return;
      }
      const amount = 500 * (targetStreak + 1);
      deltas[target] -= amount;
      queueStatFlash("lightning", entry.power.name, formatSignedStat(-amount, "Point"), getTargetedFlashOptions(entry.owner, target));
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} zapped ${getOwnerLabel(target)} for ${amount.toLocaleString()} points.`));
    });

  playedEntries
    .filter((entry) => entry.power.type === "zap_strike")
    .filter((entry) => !isEntryImmediateResolved(entry))
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      if (!target || !owners.includes(target)) {
        return;
      }
      const targetStreak = startingStreaks[target] || 0;
      if (targetStreak <= 0) {
        events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} targeted ${getOwnerLabel(target)}, but they had no streak to zap.`));
        return;
      }
      const amount = 250 * (targetStreak + 1);
      deltas[target] -= amount;
      queueStatFlash("lightning", entry.power.name, formatSignedStat(-amount, "Point"), getTargetedFlashOptions(entry.owner, target));
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} clipped ${getOwnerLabel(target)} for ${amount.toLocaleString()} points.`));
    });

  resolveHotPotatoEntries(playedEntries, deltas, events);

  playedEntries
    .filter((entry) => !winnerSet.has(entry.owner) && entry.power.type === "double_jeopardy")
    .forEach((entry) => {
      const amount = Math.floor(startingScores[entry.owner] * (entry.power.losePercent || 0.1));
      doublePenaltyTotal += amount;
      deltas[entry.owner] -= amount;
      events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} lost ${amount.toLocaleString()} points from ${entry.power.name}.`));
    });

  let payoutOwner = owner;
  const largestWinnerPayout = Math.max(0, ...Object.values(payoutDetails).map((detail) => detail.total || 0));
  winners.forEach((winner) => {
    deltas[winner] += payoutDetails[winner]?.total || 0;
  });

  playedEntries
    .filter((entry) => entry.power.type === "bribe")
    .forEach((entry) => {
      const amount = Math.floor(largestWinnerPayout * (entry.power.payoutShare || 0.33));
      deltas[entry.owner] += amount;
      events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} skimmed ${amount.toLocaleString()} points from the biggest winner payout with ${entry.power.name}.`));
    });

  playedEntries
    .filter((entry) => entry.power.type === "robin_hood")
    .forEach((entry) => {
      const leader = owners
        .filter((participant) => participant !== entry.owner)
        .sort((a, b) => startingScores[b] - startingScores[a])[0];
      if (!leader) {
        return;
      }
      const otherCount = Math.max(1, owners.length - 1);
      const stealTotal = Math.floor((startingScores[leader] || 0) * (entry.power.percentPerOther || 0.025) * otherCount);
      const share = Math.floor(stealTotal / otherCount);
      deltas[leader] -= stealTotal;
      if (entry.power.keepAll) {
        deltas[entry.owner] += stealTotal;
      } else {
        owners.filter((participant) => participant !== leader).forEach((participant) => {
          deltas[participant] += share;
        });
      }
      markAchievementPointSteal(entry.owner, stealTotal);
      if (!entry.power.keepAll) {
        markAchievementPointGift(entry.owner, share * owners.filter((participant) => participant !== leader && participant !== entry.owner).length);
      }
      events.push(createPowerEvent(entry.owner, entry.power, entry.power.keepAll
        ? `${entry.power.name} stole ${stealTotal.toLocaleString()} points from ${getOwnerLabel(leader)} and kept it.`
        : `${entry.power.name} stole ${stealTotal.toLocaleString()} points from ${getOwnerLabel(leader)} (${(2.5 * otherCount).toLocaleString()}%) and shared it around.`));
    });

  playedEntries
    .filter((entry) => entry.power.type === "tax_collector")
    .forEach((entry) => {
      const leader = owners
        .filter((participant) => participant !== entry.owner)
        .sort((a, b) => startingScores[b] - startingScores[a])[0];
      if (!leader) {
        return;
      }
      const amount = Math.floor(startingScores[leader] * 0.15);
      deltas[leader] -= amount;
      deltas[entry.owner] += amount;
      markAchievementPointSteal(entry.owner, amount);
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} collected ${amount.toLocaleString()} points from ${getOwnerLabel(leader)}.`));
    });

  applyPendingPowerBonuses(deltas, owners, pendingBonuses, events);

  playedEntries
    .filter((entry) => entry.power.type === "execution" && winnerSet.has(entry.owner))
    .filter((entry) => !isChaosInfusedPower(entry.power))
    .forEach((entry) => {
      const target = getEntryTarget(entry);
      if (!target || !owners.includes(target)) {
        return;
      }
      const amount = Math.floor(startingScores[target] * 0.2);
      deltas[target] -= amount;
      incrementAchievementProgress(entry.owner, "executionTriggers");
      state.powerHands[target] = [];
      executionBlockedOwners.set(target, entry);
      queueStatFlash("bomb", entry.power.name, [formatSignedStat(-amount, "Point"), "Power-ups Removed"], getTargetedFlashOptions(entry.owner, target, { complex: true }));
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} stripped ${getOwnerLabel(target)} of ${amount.toLocaleString()} points and all power-ups.`));
    });

  applyMonopolyEntries(playedEntries, deltas, owners, events);

  progressInsuranceFrauds(deltas, winnerSet, events);
  applyCommunismEntries(playedEntries, deltas, owners, events);
  applyLastChanceEntries(playedEntries, deltas, events);

  executionBlockedOwners.forEach((entry, target) => {
    if ((deltas[target] || 0) > 0) {
      const blocked = deltas[target];
      deltas[target] = 0;
      queueStatFlash("negative", entry.power.name, `${blocked.toLocaleString()} Points Blocked`, getTargetedFlashOptions(entry.owner, target, { complex: true }));
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} prevented ${getOwnerLabel(target)} from gaining ${blocked.toLocaleString()} points this round.`));
    }
  });

  applyNewPointPowerEntries(playedEntries, deltas, owners, events, winnerSet);
  applyPersistentRoundDeltas(deltas, owners, events);
  applyReignChaosEndRound(playedEntries, deltas, owners, events);
  applyLawsuitEntries(playedEntries, deltas, owners, events);
  applyNailInCoffin(playedEntries, deltas, events);
  applyTableEventWinnerDeltas(deltas, owners, winnerSet, startingScores, events);
  applyTableEventLoserDeltas(deltas, owners, winnerSet, startingScores, events);
  applyWrathLossTriggers(owners.filter((participant) => !winnerSet.has(participant)), events);
  applyDeathBombMarks(owners, winnerSet, deltas, events);
  applyDeathMarkDeltas(deltas, owners, events);
  applyPermanentDeathMarkDeltas(deltas, owners, events);
  applyDeductionProtection(deltas, playedEntries, freezeSnapshot, permafrostSnapshot, events);
  applyThornsDeltas(deltas, owners, events);
  applyDeductionProtection(deltas, playedEntries, freezeSnapshot, permafrostSnapshot, events);

  playedEntries
    .filter((entry) => entry.power.type === "bribe_judge")
    .forEach((entry) => {
      deltas[entry.owner] -= 1000;
      events.push(createPowerEvent(entry.owner, entry.power, `${getOwnerLabel(entry.owner)} paid 1,000 points to force the verdict.`));
    });

  owners.forEach((participant) => {
    if (freezeSnapshot[participant] > 0) {
      state.freezeProtection[participant] = Math.max(0, freezeSnapshot[participant] - 1);
    }
  });

  playedEntries
    .filter((entry) => entry.power.type === "deep_freeze")
    .forEach((entry) => {
      state.freezeProtection[entry.owner] = Math.max(state.freezeProtection[entry.owner] || 0, 2);
      if (isChaosInfusedPower(entry.power)) {
        state.freezeReflectionRounds[entry.owner] = Math.max(state.freezeReflectionRounds[entry.owner] || 0, 2);
      }
      queueStatFlash("shield", entry.power.name, "Point Shield Armed", { owners: [entry.owner], complex: true });
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} blocked this round and will block deductions for the next 2 rounds.`));
    });

  playedEntries
    .filter((entry) => entry.power.type === "permafrost")
    .forEach((entry) => {
      state.permafrostProtection[entry.owner] = true;
      queueStatFlash("shield", entry.power.name, "Permanent Shield Armed", { owners: [entry.owner], complex: true });
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} will block deductions for the rest of the match.`));
    });

  const reverseTotal = applyReverseVerdicts(playedEntries, deltas, owners, events);

  rememberLastPlayedPowers(owners);

  let amplifiedMultiplier = 1;
  if (isMatchModifierEnabled("amplified")) {
    amplifiedMultiplier = applyRoundAmplifiedMultiplier(deltas, owners, events);
    total = Math.max(0, deltas[payoutOwner] || 0);
  }

  applyEventHorizonAfterRound(owners, winnerSet, events);
  executionBlockedOwners.forEach((entry, target) => {
    if ((deltas[target] || 0) > 0) {
      const blocked = deltas[target];
      deltas[target] = 0;
      queueStatFlash("negative", entry.power.name, `${blocked.toLocaleString()} Points Blocked`, getTargetedFlashOptions(entry.owner, target, { complex: true }));
      events.push(createPowerEvent(entry.owner, entry.power, `${entry.power.name} prevented ${getOwnerLabel(target)} from gaining ${blocked.toLocaleString()} late-round points.`));
    }
  });

  applyFailedInvestmentDebuffs(deltas, winnerSet, events);
  applyVoidBombCaps(playedEntries, deltas, events);
  applyFinalTableEventGainMultipliers(deltas, owners, events);
  applyOverachieverRewards(playedEntries, deltas, events, ratingsByOwner);
  total = Math.max(0, deltas[payoutOwner] || 0);
  playUnassignedPointLossSound(deltas, pointLossSoundToken);
  owners.forEach((participant) => addScore(participant, deltas[participant]));
  decrementRoundEffectCounters(owners);
  events.push(...refillEvents);
  events.push(...streakRewardRefillEvents);

  return {
    bonus,
    tagBonus,
    difficultyBonus,
    underdogBonus,
    powerBonus: directPowerBonus,
    sabotagePenalty,
    doublePenalty: doublePenaltyTotal,
    powerLabel: winnerPower ? winnerPower.name : "",
    baseWinPoints,
    chaosPlayed,
    winningOwners: winners,
    payoutDetails,
    payoutOwner,
    reversePlayed: reverseTotal > 0 || playedEntries.some((entry) => entry.power.type === "reverse"),
    reverseTotal,
    amplifiedMultiplier,
    deltas,
    events,
    tag: rating.label,
    total
  };
}

function recordRoundResult(owner, awarded, winningCard, winningOwners = [owner]) {
  state.biggestStreak = Math.max(state.biggestStreak, ...getActiveOwners().map((participant) => getOwnerStreak(participant)));
  if (!awarded.noCorrect && awarded.total >= state.bestWinningScore) {
    state.bestWinningScore = awarded.total;
    state.bestWinningCard = winningCard;
  }
  const winnerLabels = winningOwners.map(getOwnerLabel);
  state.matchHistory.push({
    round: state.round,
    winner: awarded.noCorrect ? "No correct answers" : getOwnerLabel(owner),
    winners: winnerLabels,
    points: awarded.total,
    tag: awarded.tag,
    tagBonus: awarded.tagBonus,
    difficulty: state.questionDifficulty,
    difficultyBonus: awarded.difficultyBonus,
    power: awarded.powerLabel,
    powerBonus: awarded.powerBonus,
    underdogBonus: awarded.underdogBonus,
    coinsEarned: awarded.coinsEarned || 0,
    powerEvents: awarded.events,
    card: winningCard
  });
  const correctOwnerSet = new Set((winningOwners || []).filter((participant) => getActiveOwners().includes(participant)));
  if (!awarded.noCorrect && correctOwnerSet.size === 1 && isPublicNonSelfHostedRoom() && getActiveRoomPlayerCount() >= 5) {
    const [onlyCorrectOwner] = correctOwnerSet;
    const stat = getAchievementStat(onlyCorrectOwner);
    if (stat) {
      stat.onlyCorrectRoundWin = true;
    }
  }
  const roundDeltas = awarded.deltas || {};
  const highestRoundGain = Math.max(0, ...getActiveOwners().map((participant) => roundDeltas[participant] || 0));
  getActiveOwners().forEach((participant) => {
    const stat = getAchievementStat(participant);
    if (!stat) {
      return;
    }
    updateAchievementActiveEffectPeak(participant);
    const participantGain = Math.max(0, roundDeltas[participant] || 0);
    stat.maxSingleRoundGain = Math.max(stat.maxSingleRoundGain || 0, participantGain);
    if (highestRoundGain > 0 && participantGain === highestRoundGain) {
      stat.mostPointRounds += 1;
    }
    stat.roundsAnswered += 1;
    if (correctOwnerSet.has(participant)) {
      stat.correctAnswers += 1;
      incrementAchievementProgress(participant, "correctAnswers");
      const ownerTag = awarded.payoutDetails?.[participant]?.tag || (participant === owner ? awarded.tag : "");
      if (ownerTag === "Exact Answer") {
        stat.exactAnswers += 1;
      }
      if (stat.usedCopyAnswerRounds?.[state.round]) {
        stat.usedCopyAnswerCorrect = true;
        incrementAchievementProgress(participant, "cheatSheetCorrect");
      }
    }
  });
  recordAchievementRankSnapshot();
}

function animateScorePop(owner, awarded) {
  const deltas = awarded.deltas || { [awarded.payoutOwner || owner]: awarded.total || 0 };
  const entries = Object.entries(deltas).filter(([, amount]) => amount !== 0);
  if (!entries.length) {
    return;
  }

  queueDeltaStatFlash("Score Change", Object.fromEntries(entries));

  entries.forEach(([targetOwner, amount]) => {
    const target = elements.leaderboard.querySelector(`[data-owner="${targetOwner}"] .leaderboard-score`);
    if (!target) {
      return;
    }

    const pop = document.createElement("span");
    pop.className = `score-pop ${amount < 0 ? "negative" : ""}`;
    pop.textContent = `${amount > 0 ? "+" : ""}${amount.toLocaleString()}`;
    target.appendChild(pop);
    pop.addEventListener("animationend", () => pop.remove(), { once: true });
    window.setTimeout(() => pop.remove(), 1250);
  });
}

function triggerStreakFire() {
  const streakingChips = elements.leaderboard.querySelectorAll(".leaderboard-player.streaking");
  if (!streakingChips.length) {
    return;
  }

  if ([...streakingChips].some((chip) => getOwnerStreak(chip.dataset.owner) > 1)) {
    playSound("streak");
  }
}

function renderMatchStats(wasExited = false) {
  const progressTotal = Math.max(state.maxRounds || 0, state.roundProgress.length || 0, 1);
  const playerScore = (state.roundProgress || []).filter((status) => status === "correct").length;
  const stats = [
    ["Rounds played", `${state.matchHistory.length}/${state.maxRounds}${wasExited ? " (ended early)" : ""}`],
    ["Your score", `${playerScore}/${progressTotal}`],
    ["Coins earned", formatCoins(state.matchCoinsEarned)],
    state.finalEffectSummary ? ["Final effects", state.finalEffectSummary] : null
  ].filter(Boolean);

  elements.matchStats.replaceChildren(
    ...stats.flatMap(([label, value]) => {
      const term = document.createElement("dt");
      term.textContent = label;
      const detail = document.createElement("dd");
      detail.textContent = value;
      return [term, detail];
    })
  );
}

function getTimelineEventText(event) {
  if (typeof event === "string") {
    return event;
  }
  if (!event || event.secret) {
    return "";
  }
  return event.text || "";
}

function renderMatchTimeline() {
  if (!elements.matchTimeline) {
    return;
  }
  elements.matchTimeline.replaceChildren();
  if (!state.matchHistory.length) {
    const empty = document.createElement("p");
    empty.className = "match-timeline-empty";
    empty.textContent = "No completed rounds to show yet.";
    elements.matchTimeline.appendChild(empty);
    return;
  }
  state.matchHistory.forEach((round) => {
    const item = document.createElement("article");
    item.className = "match-timeline-item";
    const heading = document.createElement("div");
    heading.className = "match-timeline-heading";
    const title = document.createElement("strong");
    title.textContent = `Round ${round.round}`;
    const points = document.createElement("span");
    points.textContent = `${Math.max(0, Number(round.points) || 0).toLocaleString()} pts`;
    heading.append(title, points);

    const summary = document.createElement("p");
    const winners = (round.winners || [round.winner]).filter(Boolean).join(", ");
    summary.textContent = `${winners || "No winner"} · ${round.difficulty || "medium"} · ${round.tag || "Result"}`;

    const question = document.createElement("small");
    question.textContent = round.card ? `Winning answer: ${round.card}` : "No winning answer.";

    const events = (round.powerEvents || []).map(getTimelineEventText).filter(Boolean);
    item.append(heading, summary, question);
    if (events.length) {
      const eventList = document.createElement("div");
      eventList.className = "match-timeline-events";
      events.slice(0, 10).forEach((text) => {
        const chip = document.createElement("span");
        chip.textContent = text;
        eventList.appendChild(chip);
      });
      if (events.length > 10) {
        const more = document.createElement("em");
        more.textContent = `+${events.length - 10} more`;
        eventList.appendChild(more);
      }
      item.appendChild(eventList);
    }
    elements.matchTimeline.appendChild(item);
  });
}

function toggleMatchTimeline() {
  const isHidden = elements.matchTimeline.classList.contains("hidden");
  setHidden(elements.matchTimeline, !isHidden);
  elements.matchTimelineButton.textContent = isHidden ? "Hide Timeline" : "View Timeline";
  elements.matchTimelineButton.setAttribute("aria-expanded", String(isHidden));
  if (isHidden) {
    renderMatchTimeline();
  }
  playSound("click");
}

function renderFinalLeaderboard() {
  const rows = getActiveOwners()
    .map((owner) => ({
      owner,
      label: getOwnerLabel(owner),
      score: getScore(owner),
      streak: getOwnerStreak(owner)
    }))
    .sort((a, b) => b.score - a.score || getActiveOwners().indexOf(a.owner) - getActiveOwners().indexOf(b.owner));

  elements.finalLeaderboard.replaceChildren();
  rows.forEach((row, index) => {
    const item = document.createElement("div");
    item.className = "final-leaderboard-row";
    item.classList.toggle("winner", index === 0);
    applyOwnerCustomizationSurface(item, row.owner);
    const rank = document.createElement("span");
    rank.textContent = `#${index + 1}`;
    const avatar = document.createElement("span");
    avatar.className = "final-leaderboard-avatar";
    renderAvatar(avatar, getPlayer(row.owner) || { label: row.label });
    const identity = document.createElement("div");
    identity.className = "final-player-identity";
    const name = document.createElement("strong");
    renderPlayerNameWithTitle(name, row.owner, row.label);
    const titles = state.finalTitlesByOwner?.[row.owner] || [];
    const titleRow = document.createElement("div");
    titleRow.className = "player-title-row";
    titles.forEach((title) => {
      const badge = document.createElement("span");
      badge.className = "player-title-badge";
      badge.dataset.rarity = title.rarity;
      badge.dataset.description = title.description;
      badge.tabIndex = 0;
      badge.textContent = title.name;
      attachFloatingDescriptionTooltip(badge);
      titleRow.appendChild(badge);
    });
    identity.append(name);
    if (titles.length) {
      identity.appendChild(titleRow);
    }
    const score = document.createElement("em");
    score.textContent = `${row.score.toLocaleString()} points`;
    const streak = document.createElement("small");
    streak.textContent = `${row.streak}x streak`;
    item.append(rank, avatar, identity, score, streak);
    elements.finalLeaderboard.appendChild(item);
  });
}

function applyFinalMatchEffects() {
  const owners = getActiveOwners();
  if (!owners.length) {
    return null;
  }

  const pointLossSoundToken = state.pointLossSoundToken;
  const deltas = Object.fromEntries(owners.map((owner) => [owner, 0]));
  const events = [];
  if (state.hotPotatoCount > 0) {
    const potatoOwners = state.hotPotatoOwners || [];
    for (let index = 0; index < state.hotPotatoCount; index += 1) {
      const target = getRandomActiveOwner();
      applyHotPotatoHit(target, deltas, events, potatoOwners[index] || "");
    }
    state.hotPotatoCount = 0;
    state.hotPotatoOwners = [];
  }

  owners.forEach((owner) => {
    if (state.redHerringMasks[owner] !== undefined) {
      delete state.redHerringMasks[owner];
    }
  });

  protectNegativeDeltasNow(deltas, owners, "Final Effects", events);
  const changed = Object.values(deltas).some((amount) => amount !== 0);
  if (!changed) {
    return null;
  }

  playUnassignedPointLossSound(deltas, pointLossSoundToken);
  owners.forEach((owner) => addScore(owner, deltas[owner]));
  state.finalEffectSummary = events.join(" ");
  return { deltas, events };
}

function endMatch(wasExited = false, options = {}) {
  state.matchEnded = true;
  if (wasExited) {
    discardUnusedQuestionSetups();
  }
  cancelActiveMatchWork({ stopRoomSync: isRoomMode() });
  if (!wasExited) {
    stashUnusedQuestionSetups();
  }
  state.nextSetup = null;
  state.nextSetupPromise = null;
  state.nextSetupStatus = "idle";
  state.setupStack = [];
  clearRoundSubmissionState();
  const redHerringOwnersAtEnd = new Set(Object.keys(state.redHerringMasks || {}));
  const finalEffects = applyFinalMatchEffects();
  const titlesByOwner = wasExited ? {} : evaluateMatchTitles(redHerringOwnersAtEnd);
  if (wasExited) {
    state.finalTitlesByOwner = {};
  }
  finalizeLongTermAchievements(wasExited, titlesByOwner);
  const owners = getActiveOwners();
  const highScore = Math.max(...owners.map((owner) => getScore(owner)));
  const winners = owners.filter((owner) => getScore(owner) === highScore);
  const winner = winners.length === 1 ? winners[0] : "tie";

  elements.matchWinnerText.textContent = wasExited
    ? "Game ended early."
    : winner === "tie"
      ? "The match ends in a tie."
      : getWinPhrase(winner, "match");
  renderFinalLeaderboard();
  renderMatchStats(wasExited);
  renderMatchTimeline();
  elements.matchTimelineButton.textContent = "View Timeline";
  elements.matchTimelineButton.setAttribute("aria-expanded", "false");
  setHidden(elements.matchTimeline, true);
  const hostCanControlRoomEnd = isRoomMode() && isCurrentHost() && !state.joiningRoom;
  setHidden(elements.continueAsPlayerButton, true);
  setHidden(elements.spectateAgainButton, true);
  setHidden(elements.rematchButton, isRoomMode() && !hostCanControlRoomEnd);
  setHidden(elements.changeModeButton, isRoomMode() && !hostCanControlRoomEnd);
  elements.changeModeButton.textContent = isRoomMode() ? "Back to Room" : "Change Mode";
  let roomEndPublish = null;
  if (isRoomMode() && isCurrentHost() && !state.joiningRoom) {
    state.currentRoomStatus = "complete";
    upsertHostedRoom("complete");
    if (options.syncRoom !== false) {
      roomEndPublish = publishRoomGameEnded();
    }
  }
  if (finalEffects) {
    renderPowerLog({ events: finalEffects.events });
  }
  setHidden(elements.inputPanel, true);
  setHidden(elements.answerProgressPanel, true);
  setHidden(elements.powerPanel, true);
  setHidden(elements.cardsArea, true);
  setHidden(elements.verdictPanel, true);
  setHidden(elements.powerLog, true);
  setHidden(elements.loadingPanel, true);
  setHidden(elements.errorPanel, true);
  setHidden(elements.endPanel, false);
  if (!isRoomMode()) {
    ensureQuestionReserve({ enabledThemes: getEnabledTriviaThemes() });
  }
  if (isRoomMode()) {
    const keepRoomSyncAfterEnd = () => {
      if (state.matchEnded && state.roomSettings.code && state.roomSettings.code !== "CAI-0000") {
        startRoomRealtime(state.roomSettings.code);
        startRoomDirectoryPolling();
      }
    };
    if (roomEndPublish && typeof roomEndPublish.finally === "function") {
      roomEndPublish.finally(keepRoomSyncAfterEnd);
    } else {
      keepRoomSyncAfterEnd();
    }
  }
  playSound("matchEnd");
}

function submitCurrentAnswer(rawInput) {
  rawInput = cleanInput(rawInput);
  if (!rawInput) {
    focusAnswerControl();
    return;
  }

  if (isRoomMode()) {
    submitRoomAnswer(rawInput);
    return;
  }

  if (state.mode === "bots") {
    submitBotModeAnswer(rawInput);
    return;
  }

  if (isDuelMode() && state.localEntryStep === 1) {
    commitActivePowerUp("player");
    state.answerRemainingTimes.player = state.timerRemaining;
    if (isRoomMode()) {
      setRoomSubmission("player", true);
    }
    state.localAnswers.playerOne = lockRoundAnswer("player", rawInput);
    state.localEntryStep = 2;
    elements.answerInput.value = "";
    updateModeUi();
    startTimer();
    focusAnswerControl();
    playSound("lock");
    return;
  }

  if (isDuelMode()) {
    commitActivePowerUp("opponent");
    state.answerRemainingTimes.opponent = state.timerRemaining;
    if (isRoomMode()) {
      setRoomSubmission("opponent", true);
    }
    state.localAnswers.playerTwo = lockRoundAnswer("opponent", rawInput);
    playRound(getLockedRoundAnswer("player", state.localAnswers.playerOne));
    return;
  }

  commitActivePowerUp("player");
  state.answerRemainingTimes.player = state.timerRemaining;
  playRound(lockRoundAnswer("player", rawInput));
}

